import { test, expect } from '@playwright/test';

test.describe('User Account Page', () => {
    test.beforeEach(async ({ page }) => {
        // Login before each test
        await page.goto('/login');
        await page.locator('input[placeholder="email@example.com"]').fill('user@example.com');
        await page.locator('input[placeholder="••••••••"]').fill('Password123!');
        await page.getByRole('button', { name: 'Đăng nhập' }).click();
        await expect(page).toHaveURL('/');
    });

    test('should load account profile', async ({ page }) => {
        await page.goto('/account');
        await expect(page).toHaveURL('/account');
        await expect(page.locator('text=Thông tin tài khoản')).toBeVisible();
        await expect(page.locator('input[name="fullName"]')).toBeVisible();
    });

    test('should navigate to orders', async ({ page }) => {
        await page.goto('/account/orders');
        await expect(page.locator('h2:has-text("Lịch sử đơn hàng")')).toBeVisible();
    });

    test('should navigate to addresses', async ({ page }) => {
        await page.goto('/account/addresses');
        await expect(page.locator('h2:has-text("Sổ địa chỉ")')).toBeVisible();
    });

    test('should navigate to settings/notifications', async ({ page }) => {
        await page.goto('/account/settings');
        await expect(page.locator('text=Cài đặt tài khoản')).toBeVisible();

        await page.goto('/account/notifications');
        await expect(page.locator('text=Thông báo của tôi')).toBeVisible();
    });
    test('should navigate to wishlist', async ({ page }) => {
        await page.goto('/account/wishlist');
        await expect(page.locator('text=Sản phẩm yêu thích')).toBeVisible();
    });

    test('should redirect /wishlist to /account/wishlist', async ({ page }) => {
        await page.goto('/wishlist');
        await expect(page).toHaveURL(/\/account\/wishlist/);
    });
});

import { test, expect } from '@playwright/test';

test.describe('Admin Functionality', () => {



    test.beforeEach(async ({ page }) => {
        // 1. Navigate first to ensure valid context for Storage access
        await page.goto('/login');

        // 2. Clear state fully
        await page.context().clearCookies();
        await page.evaluate(() => localStorage.clear());
        await page.evaluate(() => sessionStorage.clear());
        // Wait for inputs to be ready
        const emailInput = page.getByPlaceholder('email@example.com');
        await expect(emailInput).toBeVisible();
        await emailInput.fill('admin@vnvtstore.com');

        await page.getByPlaceholder('••••••••').fill('Password123!');

        // 3. Submit
        const submitBtn = page.getByRole('button', { name: /Đăng nhập|Login/i });
        await expect(submitBtn).toBeVisible();
        await submitBtn.click();

        // 4. Wait for redirection to Admin Dashboard
        // Admin usually redirects to /admin
        // Increase timeout for potentially slow backend/seed
        await expect(page).toHaveURL(/.*\/admin/, { timeout: 40000 });

        // 5. Verify Admin Sidebar presence which confirms successful load
        await expect(page.locator('aside')).toBeVisible({ timeout: 30000 });
    });

    test('should display Dashboard statistics', async ({ page }) => {
        // Wait for stats to load
        await expect(page.getByText(/Doanh thu|Revenue/i)).toBeVisible({ timeout: 20000 });
        await expect(page.getByText(/Đơn hàng|Orders/i)).toBeVisible();
        await expect(page.getByText(/Sản phẩm|Products/i)).toBeVisible();
    });

    test('should manage products module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/products"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/products/);
        await expect(page.locator('table')).toBeVisible({ timeout: 15000 });
    });

    test('should manage categories module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/categories"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/categories/);
        await expect(page.locator('table')).toBeVisible({ timeout: 10000 });
    });

    test('should manage suppliers module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/suppliers"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/suppliers/);
        await expect(page.locator('table')).toBeVisible({ timeout: 10000 });
    });

    test('should manage customers module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/customers"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/customers/);
        await expect(page.locator('table')).toBeVisible({ timeout: 10000 });
    });

    test('should manage orders module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/orders"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/orders/);
        await expect(page.locator('table')).toBeVisible({ timeout: 10000 }); // some fail if empty
    });

    test('should manage promotions module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/promotions"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/promotions/);
        await expect(page.locator('table')).toBeVisible({ timeout: 10000 });
    });

    test('should manage banners module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/banners"]');
        await expect(link).toBeVisible();
        await link.click();

        await expect(page).toHaveURL(/.*\/admin\/banners/);
        await expect(page.locator('table')).toBeVisible({ timeout: 10000 });
    });

    test('should manage quote requests module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/quotes"]');
        await expect(link).toBeVisible();
        await link.click();
        await expect(page).toHaveURL(/.*\/admin\/quotes/);
    });

    test('should view settings module', async ({ page }) => {
        const link = page.locator('aside a[href="/admin/settings"]');
        await expect(link).toBeVisible();
        await link.click();
        await expect(page).toHaveURL(/.*\/admin\/settings/);
    });

    test('should logout correctly', async ({ page }) => {
        // User profile menu in header (it's a button with user email)
        await page.locator('header').getByRole('button').last().click();

        // The Sign out button is in the portal dropdown
        const logoutBtn = page.getByText(/Sign out|Đăng xuất/i).last();
        await expect(logoutBtn).toBeVisible();
        await logoutBtn.click();

        // Confirm Dialog
        const confirmBtn = page.getByRole('button', { name: /Đăng xuất|Logout/i }).filter({ hasText: /Đăng xuất|Logout/i });
        await expect(confirmBtn).toBeVisible();
        await confirmBtn.click();

        await expect(page).toHaveURL(/.*login/);
    });

});

import { test, expect } from '@playwright/test';

test.describe('Authentication Flow', () => {
    test('homepage loads successfully', async ({ page }) => {
        await page.goto('/');
        await expect(page).toHaveTitle(/VNVT Store/);
    });

    test('should navigate to login page', async ({ page }) => {
        await page.goto('/');

        // On desktop, login is inside the user menu dropdown caused by Header.tsx structure
        // Find the button with User icon. 
        // We look for a button in the header that contains the lucide-user svg class or similar logic.
        const userMenuBtn = page.locator('header button').filter({ has: page.locator('svg.lucide-user') });

        if (await userMenuBtn.isVisible()) {
            await userMenuBtn.click();
            // Wait for dropdown
            const loginLink = page.getByRole('link', { name: /login|đăng nhập/i });
            await expect(loginLink).toBeVisible();
            await loginLink.click();
            await expect(page).toHaveURL(/.*login/);
        } else {
            console.log('User menu button not found, checking direct login link (mobile view?)');
            // Fallback for mobile or if different layout
            const loginLink = page.getByRole('button', { name: /login|đăng nhập/i });
            if (await loginLink.isVisible()) {
                await loginLink.click();
                await expect(page).toHaveURL(/.*login/);
            } else {
                console.log('No login entry point found');
            }
        }
    });
});

import { test, expect } from '@playwright/test';

test.describe('Contact Page', () => {
    test.beforeEach(async ({ page }) => {
        await page.goto('/contact');
    });

    test('should display validation errors when fields are empty', async ({ page }) => {
        // Click submit without filling anything
        await page.click('button[type="submit"]');

        // Check for validation messages
        // Since we localized it, we expect strings from vi.json for validation.required
        await expect(page.locator('p.text-red-500').first()).toBeVisible();

        // Check for specific labels using localized text
        const fullNameLabel = page.getByText('Họ và tên');
        await expect(fullNameLabel).toBeVisible();
    });

    test('should show error for invalid email', async ({ page }) => {
        await page.fill('input[name="fullName"]', 'Test User');
        await page.fill('input[name="email"]', 'invalid-email');
        await page.fill('input[name="subject"]', 'Support');
        await page.fill('textarea[name="message"]', 'Hello world');

        await page.click('button[type="submit"]');

        // Check for invalid email message (vi.json: validation.invalidEmail)
        await expect(page.getByText('Email không hợp lệ')).toBeVisible();
    });

    test('should submit successfully with valid data', async ({ page }) => {
        await page.fill('input[name="fullName"]', 'Nguyễn Văn A');
        await page.fill('input[name="email"]', 'vna@example.com');
        await page.fill('input[name="phone"]', '0901234567');
        await page.fill('input[name="subject"]', 'Hợp tác');
        await page.fill('textarea[name="message"]', 'Tôi muốn hợp tác kinh doanh.');

        await page.click('button[type="submit"]');

        // Check for success toast (vi.json: contactPage.success)
        await expect(page.getByText('Cảm ơn bạn! Chúng tôi sẽ liên hệ lại trong thời gian sớm nhất.')).toBeVisible();
    });
});

import { test, expect } from '@playwright/test';

test('diagnostic login test', async ({ page }) => {
    // Listen for console logs
    page.on('console', msg => console.log('BROWSER LOG:', msg.text()));
    page.on('pageerror', err => console.log('BROWSER ERROR:', err.message));

    await page.goto('/login');

    // Fill login
    await page.getByPlaceholder('email@example.com').fill('admin@vnvt.com');
    await page.getByPlaceholder('••••••••').fill('Admin@123');

    console.log('Clicking login button...');
    await page.getByRole('button', { name: /Đăng nhập|Login/i }).click();

    console.log('Waiting for URL change...');
    try {
        await expect(page).toHaveURL(/.*\/admin/, { timeout: 10000 });
        console.log('SUCCESS: URL changed to admin');
    } catch (e) {
        console.log('FAILURE: Current URL is', page.url());
        // Check for error message on page
        const errorMsg = await page.locator('.bg-red-50').textContent().catch(() => 'No visible error div');
        console.log('Error message on page:', errorMsg);
    }
});

import { test, expect } from '@playwright/test';

// Configuration
const BASE_URL = 'http://localhost:5173';

test.describe('Admin Safe Delete Complex Flows', () => {

    test.beforeEach(async ({ page }) => {
        // Login
        await page.goto('/auth/login');
        await page.fill('input[name="username"]', 'admin');
        await page.fill('input[name="password"]', 'admin123');
        await page.click('button[type="submit"]');
        await page.waitForURL('**/admin/dashboard');
    });

    // Helpers
    const createCategory = async (page: any, name: string) => {
        await page.goto('/admin/categories');
        const addBtn = page.locator('button').filter({ hasText: /New|Add|Thêm|Tạo/i }).first();
        if (await addBtn.isVisible()) {
            await addBtn.click();
        } else {
            await page.getByRole('button').filter({ hasText: 'Add' }).first().click();
        }

        await page.fill('input[name="name"]', name);
        // Submit is usually inside the modal form
        // Wait for modal
        await page.waitForSelector('form');
        await page.locator('form button[type="submit"]').click();

        // Wait for table to reload/contain name
        await page.waitForSelector(`text=${name}`);
    };

    test('Complex Flow: Verify Safe Delete on Category', async ({ page }) => {
        // 1. Identification
        // We rely on existing data that has products to verify the BLOCK mechanism.
        // "Electronics" or similar usually exists.

        await page.goto('/admin/categories');
        await page.waitForSelector('table');

        // Find a row that likely has products. 
        // Safe Delete logic triggers a TOAST error.

        const deleteButtons = page.locator('button[aria-label="Delete"]');
        const count = await deleteButtons.count();

        if (count > 0) {
            await deleteButtons.first().click();

            // Check for Toast with "Cannot delete"
            try {
                // Try specific toast selector if known, or generic text
                const toast = page.locator('li[role="status"]').filter({ hasText: /Cannot delete|Không thể xóa/i }).first();

                // Wait for toast if it appears
                await expect(toast).toBeVisible({ timeout: 5000 });
                console.log("Verified Safe Delete Toast");
            } catch (e) {
                // If not blocked, it probably showed Confirm Delete modal
                const confirmModal = page.getByText(/Are you sure|Bạn có chắc chắn/i);
                if (await confirmModal.isVisible()) {
                    console.log("Warning: Category was safe to delete (no products). Block logic not exercised.");
                    await page.getByText(/Cancel|Hủy/i).click();
                } else {
                    console.log("No toast and no modal? Logic might be broken.");
                }
            }
        }
    });

    test('Complex Flow: Delete Empty Category (Success)', async ({ page }) => {
        const timestamp = Date.now();
        const catName = `SafeDel_${timestamp}`;

        // 1. Create Empty Category
        await page.goto('/admin/categories');

        await page.waitForSelector('table');
        const addBtn = page.locator('button').filter({ hasText: /New|Add|Thêm|Tạo/i }).first();
        await addBtn.click();

        await page.waitForSelector('input[name="name"]');
        await page.fill('input[name="name"]', catName);
        await page.locator('button').filter({ hasText: /Save|Lưu|Create/i }).click();

        await page.waitForSelector(`text=${catName}`);

        // 2. Delete it
        // Find row with this name
        const row = page.locator('tr', { hasText: catName });

        // Click delete on the row
        const deleteBtn = row.locator('button').filter({ hasText: /Delete|Xóa/i });
        if (await deleteBtn.count() > 0) {
            await deleteBtn.click();
        } else {
            await row.locator('button[aria-label="Delete"]').click();
        }

        // Expect "Are you sure" dialog (Custom Modal) not native dialog
        const confirmModal = page.getByText(/Are you sure|Bạn có chắc chắn/i);
        await expect(confirmModal).toBeVisible();
        await page.locator('button').filter({ hasText: /Delete|Xóa|Đồng ý/i }).click();

        await page.waitForTimeout(1000); // Wait for delete
        await expect(page.locator(`text=${catName}`)).not.toBeVisible();
    });
});

import { test, expect } from '@playwright/test';

test.describe('i18n Language Switching', () => {

    test('should switch from Vietnamese to English and back', async ({ page }) => {
        await page.goto('/');

        // 1. Initial should be Vietnamese (default)
        // Check for common Vietnamese text like "Giỏ hàng" or "Sản phẩm"
        await expect(page.getByText('Sản phẩm')).toBeVisible();

        // 2. Click Language Toggle (Assuming there's a button or dropdown in Header)
        // We'll look for a button that likely holds the language label or icon
        const langToggle = page.locator('button').filter({ hasText: /VN|EN/i });
        await langToggle.click();

        // Select English
        const enOption = page.getByRole('button', { name: /English/i });
        if (await enOption.isVisible()) {
            await enOption.click();
        } else {
            // Backup: click the toggle again if it's a direct toggle button
        }

        // 3. Verify English text
        await expect(page.getByText('Products')).toBeVisible();
        await expect(page.getByText('Sản phẩm')).not.toBeVisible();

        // 4. Switch back to Vietnamese
        await langToggle.click();
        await page.getByRole('button', { name: /Tiếng Việt/i }).click();

        // 5. Verify Vietnamese text again
        await expect(page.getByText('Sản phẩm')).toBeVisible();
    });
});

import { test, expect } from '@playwright/test';

test.describe('Business Logic Verification', () => {
    test.beforeEach(async ({ page }) => {
        await page.context().clearCookies();
    });

    test('should calculate cart totals and shipping fee correctly', async ({ page }) => {
        // 1. Add item to cart
        await page.goto('/products');

        // We need a product with known price or just dynamic check.
        // Let's grab the first product price from the card
        const firstProductCard = page.locator('.group').first();
        // Assuming grid layout default
        const priceText = await firstProductCard.locator('.text-error').first().innerText();
        const cleanPrice = parseInt(priceText.replace(/[^\d]/g, ''));

        await firstProductCard.getByRole('button', { name: /add to cart|thêm vào giỏ/i }).click();
        await page.waitForTimeout(500);

        // 2. Go to Cart
        await page.goto('/cart');

        // 3. Verify Subtotal
        // Cart page has subtotal in summary
        const subtotalEl = page.locator('.bg-primary').getByText('Tạm tính').locator('..').locator('span').last();
        // Or closer selector: .bg-primary -> contains text 'Tạm tính' -> sibling span
        // In CartPage.tsx: <div className="flex justify-between text-secondary"><span>{t('cart.subtotal')}</span><span>{formatCurrency(total)}</span></div>

        // Let's try text matching
        const subtotalText = await subtotalEl.innerText();
        const cartSubtotal = parseInt(subtotalText.replace(/[^\d]/g, ''));

        expect(cartSubtotal).toBe(cleanPrice);

        // 4. Verify Shipping Fee Logic
        // Fee is 30k if < 500k, 0 if >= 500k
        const shippingEl = page.locator('.bg-primary').getByText('Phí vận chuyển').locator('..').locator('span').last();
        let shippingText = await shippingEl.innerText();

        let expectedShipping = cartSubtotal >= 500000 ? 0 : 30000;

        if (expectedShipping === 0) {
            // Might say "Miễn phí"
            expect(shippingText).toMatch(/miễn phí|0/i);
        } else {
            const shippingFee = parseInt(shippingText.replace(/[^\d]/g, ''));
            expect(shippingFee).toBe(30000);
        }

        // 5. Update Quantity to trigger Free Shipping (if not already)
        // If current total < 500k, increase quantity until > 500k
        if (cartSubtotal < 500000) {
            const requiredQty = Math.ceil(500000 / cleanPrice);
            // Find quantity input or plus button
            // In CartPage.tsx: plus button has <Plus size={16} /> inside a button
            // <button onClick={() => updateQuantity...}><Plus../></button>
            const plusBtn = page.locator('button:has(svg.lucide-plus)');

            // Click (requiredQty - 1) times
            for (let i = 0; i < requiredQty - 1; i++) {
                await plusBtn.click();
                await page.waitForTimeout(200); // Wait for state update
            }

            // Re-check shipping
            shippingText = await shippingEl.innerText();
            expect(shippingText).toMatch(/miễn phí|0/i);
        }
    });
});

import { test, expect } from '@playwright/test';

test.describe('Shop Order Flow', () => {

    test.beforeEach(async ({ page }) => {
        // Shared start point: clear state fully
        await page.context().clearCookies();
        await page.evaluate(() => localStorage.clear());
        await page.evaluate(() => sessionStorage.clear());
    });

    test('should complete a GUEST purchase flow', async ({ page }) => {
        // 1. Add product to cart
        await page.goto('/products');
        const addToCartBtn = page.getByRole('button', { name: /add to cart|thêm vào giỏ/i }).first();
        await expect(addToCartBtn).toBeVisible();
        await addToCartBtn.click();

        await page.waitForTimeout(500);

        // 2. Go to Cart & Verify
        await page.goto('/cart');
        await expect(page.locator('h1')).toContainText(/Giỏ hàng|Cart/i);
        await expect(page.locator('.grid').first()).toBeVisible();

        // 3. Proceed to Checkout
        await page.getByRole('button', { name: /thanh toán|checkout/i }).click();

        // 4. Handle Guest Option in Modal
        const guestBtn = page.getByRole('button', { name: /mua hàng không cần đăng nhập/i });
        if (await guestBtn.isVisible({ timeout: 5000 })) {
            await guestBtn.click();
        }

        // 5. STEP 1: Shipping Info
        await expect(page.getByRole('heading', { name: /thông tin giao hàng/i })).toBeVisible();
        await page.getByPlaceholder('Nguyễn Văn A').fill('Guest User');
        await page.getByPlaceholder('0901234567').fill('0908887777');
        await page.getByPlaceholder('email@example.com').fill('guest@example.com');

        // Native select or custom components? Assuming standard interaction
        await page.locator('select').first().selectOption({ index: 1 });
        await page.locator('select').nth(1).selectOption({ index: 1 });
        await page.getByPlaceholder('Số nhà, tên đường...').fill('456 Guest Road');

        await page.getByRole('button', { name: /tiếp tục|continue/i }).click();

        // 6. STEP 2: Payment Method
        await expect(page.getByRole('heading', { name: /phương thức thanh toán/i })).toBeVisible();
        await page.getByRole('button', { name: /tiếp tục|continue/i }).click();

        // 7. STEP 3: Confirm Order
        await expect(page.getByRole('heading', { name: /xác nhận đơn hàng/i })).toBeVisible();
        const placeOrderBtn = page.getByRole('button', { name: /đặt hàng|place order/i });
        await expect(placeOrderBtn).toBeVisible();
        await placeOrderBtn.click();

        // 8. Final Success
        await expect(page).toHaveURL(/.*order-success/, { timeout: 15000 });
        await expect(page.getByText(/đặt hàng thành công/i)).toBeVisible();
    });

    test('should complete an AUTHENTICATED purchase flow', async ({ page }) => {
        // 1. First Login
        await page.goto('/login');
        await page.getByPlaceholder('email@example.com').fill('admin@vnvtstore.com');
        await page.getByPlaceholder('••••••••').fill('Password123!');
        await page.getByText('Ghi nhớ đăng nhập').click();
        await page.getByRole('button', { name: /^Đăng nhập$/i }).click();

        // Wait for login redirection
        await expect(page).toHaveURL(/\/admin|^\/$/); // Might redirect to admin or home depending on role/last page

        // 2. Add product to cart (go to shop)
        await page.goto('/products');
        const addToCartBtn = page.getByRole('button', { name: /add to cart|thêm vào giỏ/i }).first();
        await expect(addToCartBtn).toBeVisible();
        await addToCartBtn.click();

        // 3. Checkout
        await page.goto('/checkout');

        // 4. STEP 1: Shipping Info (Should be pre-filled or need filling)
        // If pre-filled, we check values, if not, we fill.
        const nameInput = page.getByPlaceholder('Nguyễn Văn A');
        if (!(await nameInput.inputValue())) {
            await nameInput.fill('Admin User');
            await page.getByPlaceholder('0901234567').fill('0901234567');
            await page.locator('select').first().selectOption({ index: 1 });
            await page.locator('select').nth(1).selectOption({ index: 1 });
            await page.getByPlaceholder('Số nhà, tên đường...').fill('123 Admin St');
        }

        await page.getByRole('button', { name: /tiếp tục|continue/i }).click();

        // 5. STEP 2: Payment
        await expect(page.getByRole('heading', { name: /phương thức thanh toán/i })).toBeVisible();
        await page.getByRole('button', { name: /tiếp tục|continue/i }).click();

        // 6. STEP 3: Confirm
        await expect(page.getByRole('heading', { name: /xác nhận đơn hàng/i })).toBeVisible();
        await page.getByRole('button', { name: /đặt hàng|place order/i }).click();

        // 7. Success
        await expect(page).toHaveURL(/.*order-success/);
        await expect(page.getByText(/đặt hàng thành công/i)).toBeVisible();
    });
});

import { test, expect } from '@playwright/test';

test.describe('Dynamic Product Management', () => {

    test.beforeEach(async ({ page }) => {
