  onViewDetails?: () => void; // Converted from onMore
  onEdit?: () => void;
  onDelete?: () => void;
  // Removed onCheck

  onSearchClick?: () => void;
  onRefresh?: () => void;
  onReset?: () => void;


  onImport?: () => void;
  onExport?: () => void;
  // Removed onPrint

  // Removed onHelp

  // States
  isSearchActive?: boolean;
  isExporting?: boolean;
  selectedCount?: number;
  className?: string;
  searchRef?: React.Ref<HTMLButtonElement>;
  children?: React.ReactNode;
}

// Specific styled versions based on screenshot (Blue icons)
const BlueItem = React.forwardRef<HTMLButtonElement, AdminToolbarAction & { "data-testid"?: string }>(({ icon, onClick, title, disabled, className: itemClassName, "data-testid": testId }, ref) => (
  <button
    type="button"
    ref={ref}
    onClick={onClick ? onClick : undefined}
    disabled={disabled || !onClick}
    title={title}
    data-testid={testId}
    className={cn(
      "p-2 hover:bg-blue-50 dark:hover:bg-slate-700 rounded transition-colors disabled:opacity-30 disabled:cursor-not-allowed",
      itemClassName
    )}
  >
    <div className="w-5 h-5 flex items-center justify-center text-[#2d7ad6]">
      {icon}
    </div>
  </button>
));
BlueItem.displayName = "BlueItem";

export const AdminToolbar = ({
  onAdd,
  onViewDetails,
  onEdit,
  onDelete,
  // onCheck removed
  onSearchClick,
  onRefresh,
  onReset,
  onImport,
  onExport,
  // onPrint removed
  // onHelp removed
  isSearchActive,
  isExporting = false,
  selectedCount = 0,
  className,
  searchRef,
  searchInput, // New prop
  children,
}: AdminToolbarProps & { searchInput?: React.ReactNode }) => {
  const { t } = useTranslation();

  return (
    <div className={cn("flex flex-wrap items-center bg-transparent gap-1 relative z-20", className)}>

      {/* Group 1: CRUD */}
      <div className="flex items-center gap-1">
        <BlueItem icon={<Plus size={20} className="stroke-[2.5]" />} onClick={onAdd} title={t('admin.createNew')} data-testid="toolbar-add" />
        <BlueItem icon={<MoreHorizontal size={20} className="stroke-[2.5]" />} onClick={onViewDetails} disabled={selectedCount !== 1} title={t('admin.viewDetails')} data-testid="toolbar-view" />
        <BlueItem icon={<Edit size={18} className="stroke-[2.5]" />} onClick={onEdit} disabled={selectedCount !== 1} title={t('common.actions.edit')} data-testid="toolbar-edit" />
        <BlueItem icon={<Trash2 size={20} className="stroke-[2.5]" />} onClick={onDelete} disabled={selectedCount === 0} title={t('common.actions.delete')} data-testid="toolbar-delete" />
      </div>

      <div className="h-6 w-px bg-gray-200 dark:bg-slate-600 mx-2" />

      {/* Group 2: Search & Refresh */}
      <div className="flex items-center gap-1">
        {searchInput}
        <BlueItem
          ref={searchRef}
          icon={<Search size={20} className="stroke-[2.5]" />}
          onClick={onSearchClick}
          title={t('common.search')}
          className={isSearchActive ? "bg-blue-100 dark:bg-blue-900/30" : ""}
          data-testid="toolbar-search"
        />
        <BlueItem icon={<RefreshCw size={18} className="stroke-[2.5]" />} onClick={onRefresh} title={t('admin.refreshData')} data-testid="toolbar-refresh" />
      </div>

      <div className="h-6 w-px bg-gray-200 dark:bg-slate-600 mx-2" />

      {/* Group 3: File Ops */}
      <div className="flex items-center gap-1">
        <BlueItem icon={<Upload size={20} className="stroke-[2.5]" />} onClick={onImport} title={t('admin.import')} />
        <BlueItem 
          icon={isExporting ? <Loader2 size={20} className="stroke-[2.5] animate-spin" /> : <Download size={20} className="stroke-[2.5]" />} 
          onClick={!isExporting ? onExport : undefined} 
          disabled={isExporting}
          title={isExporting ? t('admin.exporting') : t('admin.export')} 
        />
      </div>

      {children && (
        <>
          <div className="flex-1" /> {/* Spacer to push children to right */}
          <div className="h-6 w-px bg-gray-200 dark:bg-slate-600 mx-2" />
          {children}
        </>
      )}

    </div>
  );
};

import React from 'react';
import { LucideIcon } from 'lucide-react';
import { cn } from '@/utils/cn';

export interface StatItem {
  label: string;
  value: number | string;
  icon: React.ReactNode;
  color?: 'blue' | 'rose' | 'emerald' | 'amber' | 'purple' | 'cyan' | 'indigo';
  loading?: boolean;
}

interface StatsCardsProps {
  stats: StatItem[];
  className?: string;
}

const colorMap = {
  blue: { bg: 'bg-blue-50', text: 'text-blue-600' },
  rose: { bg: 'bg-rose-50', text: 'text-rose-600' },
  emerald: { bg: 'bg-emerald-50', text: 'text-emerald-600' },
  amber: { bg: 'bg-amber-50', text: 'text-amber-600' },
  purple: { bg: 'bg-purple-50', text: 'text-purple-600' },
  cyan: { bg: 'bg-cyan-50', text: 'text-cyan-600' },
  indigo: { bg: 'bg-indigo-50', text: 'text-indigo-600' },
};

export const StatsCards = ({ stats, className }: StatsCardsProps) => {
  return (
    <div className={cn("grid grid-cols-1 md:grid-cols-3 gap-4", className)}>
      {stats.map((stat, index) => {
        const theme = stat.color && colorMap[stat.color] ? colorMap[stat.color] : colorMap.blue;
        
        return (
          <div key={index} className="bg-white dark:bg-slate-800 p-4 rounded-xl shadow-sm border border-slate-100 dark:border-slate-700 flex items-center gap-4 transition-all hover:shadow-md">
            <div className={cn("w-12 h-12 rounded-lg flex items-center justify-center transition-colors", theme.bg, theme.text)}>
              {stat.icon}
            </div>
            <div>
              <p className="text-sm text-slate-500 dark:text-slate-400">{stat.label}</p>
              {stat.loading ? (
                <div className="h-7 w-16 bg-slate-100 dark:bg-slate-700 animate-pulse rounded mt-1" />
              ) : (
                <p className="text-xl font-bold text-slate-800 dark:text-slate-100">{stat.value}</p>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
};

import { Search, Download, Trash2 } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui';

interface TableToolbarProps {
  // Search
  searchQuery: string;
  onSearchChange: (value: string) => void;
  searchField: string;
  onSearchFieldChange: (value: string) => void;
  searchOptions: { label: string; value: string }[];

  // Selection
  selectedCount: number;
  onBulkDelete?: () => void;

  // Actions
  onExport: () => void;
  onImport?: (file: File) => void; // Made optional - backend doesn't support import yet
}

export const TableToolbar = ({
  searchQuery,
  onSearchChange,
  searchField,
  onSearchFieldChange,
  searchOptions,
  selectedCount,
  onBulkDelete,
  onExport,
  onImport,
}: TableToolbarProps) => {
  const { t } = useTranslation();

  return (
    <div className="bg-primary p-4 rounded-xl space-y-4 border shadow-sm">
      <div className="flex flex-col md:flex-row gap-4">
        {/* Search Section + Export Button */}
        <div className="flex flex-1 gap-2">
          <select
            value={searchField}
            onChange={(e) => onSearchFieldChange(e.target.value)}
            className="px-3 py-2 border rounded-lg bg-secondary focus:outline-none focus:border-accent w-auto min-w-[120px]"
          >
            <option value="all">{t('common.all')}</option>
            {searchOptions.map((opt) => (
              <option key={opt.value} value={opt.value}>{opt.label}</option>
            ))}
          </select>

          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" size={18} />
            <input
              type="text"
              placeholder={t('common.search') + '...'}
              value={searchQuery}
              onChange={(e) => onSearchChange(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border rounded-lg bg-transparent focus:outline-none focus:border-accent"
            />
          </div>


        </div>
      </div>

      {/* Bulk Actions Indicator */}
      {selectedCount > 0 && (
        <div className="flex items-center justify-between bg-accent/10 text-accent p-2 rounded-lg border border-accent/20 animate-in fade-in slide-in-from-top-2">
          <div className="flex items-center gap-2">
            <span className="font-semibold">{selectedCount} {t('common.selected')}</span>
            <span className="text-sm opacity-80">|</span>
            <button className="text-sm hover:underline" onClick={onBulkDelete}>
              {t('common.deleteAll')}
            </button>
          </div>

          {onBulkDelete && (
            <Button
              variant="primary"
              size="sm"
              className="bg-error hover:bg-error/90 border-error text-white h-8"
              leftIcon={<Trash2 size={14} />}
              onClick={onBulkDelete}
            >
              {t('common.delete')} {selectedCount} {t('common.items')}
            </Button>
          )}
        </div>
      )}
    </div>
  );
};

