Header.displayName = 'Header';

export default Header;

import { useState, useMemo } from 'react';
import { useWatch, UseFormReturn } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { Star, X } from 'lucide-react';
import { Button, Textarea } from '@/components/ui';
import { reviewService as reviewApi, type CreateReviewRequest } from '@/services/reviewService';
import { useToast } from '@/store/toastStore';
import { cn } from '@/utils/cn';
import { BaseForm, FieldDefinition } from '@/components/common/BaseForm';
import { z } from 'zod';

interface ReviewFormProps {
  orderItemCode?: string;
  productCode?: string;
  productName: string;
  productImage?: string;
  userCode: string;
  onSuccess: () => void;
  onCancel: () => void;
  embedded?: boolean;
}

const MAX_COMMENT_LENGTH = 1000;

// Schema Definition
const reviewSchema = z.object({
  rating: z.number().min(1, "Rating is required").max(5),
  comment: z.string()
    .min(10, "Review must be at least 10 characters")
    .max(MAX_COMMENT_LENGTH, "Review is too long")
});

type ReviewFormValues = z.infer<typeof reviewSchema>;

const ReviewForm = ({ 
  orderItemCode, 
  productCode, 
  productName, 
  productImage, 
  userCode, 
  onSuccess, 
  onCancel,
  embedded = false 
}: ReviewFormProps) => {
  const { t } = useTranslation();
  const toast = useToast();

  const handleSubmit = async (data: ReviewFormValues) => {
    if (!userCode || (!orderItemCode && !productCode)) {
      toast.error("Missing required information to submit review.");
      return;
    }

    try {
      const payload: CreateReviewRequest = {
        orderItemCode: orderItemCode,
        productCode: productCode,
        rating: data.rating,
        comment: data.comment,
        userCode: userCode
      };

      const res = await reviewApi.create(payload);
      if (res.success) {
        toast.success(t('review.submit_success') || 'Review submitted successfully!');
        onSuccess();
      } else {
        toast.error(res.message || t('review.submit_error') || 'Failed to submit review');
      }
    } catch (error) {
      console.error(error);
      toast.error(t('review.submit_error') || 'An error occurred');
    }
  };

  // Defensive checks
  if ((!orderItemCode && !productCode) || !productName) {
    return (
      <div className="bg-red-50 p-4 rounded-lg text-red-600 border border-red-200">
        Error: Missing review context.
      </div>
    );
  }

  // Fields Definition
  const fields: FieldDefinition[] = [
    {
      name: 'rating',
      type: 'custom',
      label: t('review.rating') || 'How would you rate it?',
      render: (form: UseFormReturn<ReviewFormValues>) => <RatingField form={form} />
    },
    {
      name: 'comment',
      type: 'custom',
      label: t('review.comment') || 'Public Review',
      render: (form: UseFormReturn<ReviewFormValues>) => <CommentField form={form} />
    }
  ];

  const ProductInfo = () => (
    <div className="flex items-center gap-4 mb-6 p-4 bg-gray-50/50 rounded-xl border border-gray-100/50">
      <div className="w-16 h-16 flex-shrink-0 bg-white rounded-lg overflow-hidden border border-gray-100 shadow-sm">
        {productImage ? (
          <img 
            src={productImage} 
            alt={productName} 
            className="w-full h-full object-cover transform transition-transform hover:scale-110" 
          />
        ) : (
          <div className="w-full h-full bg-gray-100 flex items-center justify-center text-gray-400">
            <Star size={24} />
          </div>
        )}
      </div>
      <div className="flex-1 min-w-0">
        <p className="font-bold text-[10px] text-primary uppercase tracking-widest mb-1 opacity-70">
          {t('product.name')}
        </p>
        <p className="font-semibold text-gray-800 truncate">{productName}</p>
      </div>
    </div>
  );

  const formContent = (
    <BaseForm
      schema={reviewSchema}
      defaultValues={{ rating: 5, comment: '' }}
      fields={fields}
      onSubmit={handleSubmit}
      onCancel={onCancel}
      renderBefore={ProductInfo}
      submitLabel={t('review.post_review') || 'Post Review'}
      cancelLabel={t('common.cancel')}
      className="space-y-6"
    />
  );

  if (embedded) {
    return <div className="w-full">{formContent}</div>;
  }

  return (
    <div className="bg-white/80 backdrop-blur-xl border border-white/20 shadow-2xl p-6 rounded-2xl w-full max-w-lg mx-auto relative overflow-hidden transition-all animate-in fade-in zoom-in duration-300">
      {/* Decorative gradient background */}
      <div className="absolute -top-24 -left-24 w-48 h-48 bg-primary/10 rounded-full blur-3xl pointer-events-none" />
      <div className="absolute -bottom-24 -right-24 w-48 h-48 bg-blue-500/10 rounded-full blur-3xl pointer-events-none" />

      <button 
        onClick={onCancel}
        className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 transition-colors p-2 hover:bg-gray-100 rounded-full"
      >
        <X size={20} />
      </button>

      {/* Header for non-embedded mode */}
      <h3 className="text-2xl font-bold mb-6 bg-gradient-to-r from-gray-900 to-gray-600 bg-clip-text text-transparent">
        {t('review.write_review') || 'Share Your Experience'}
      </h3>

      {formContent}
    </div>
  );
};

// Sub-components for custom fields
const RatingField = ({ form }: { form: UseFormReturn<ReviewFormValues> }) => {
  const { t } = useTranslation();
  const [hoverRating, setHoverRating] = useState(0);
  const { setValue, watch } = form;
  const rating = watch('rating');

  return (
    <div className="space-y-3">
      <div className="flex justify-between items-end">
        <label className="text-sm font-semibold text-gray-700">{t('review.rating') || 'How would you rate it?'}</label>
        <span className={cn(
           "text-sm font-medium transition-colors duration-300",
           rating >= 4 ? "text-green-600" : rating >= 3 ? "text-yellow-600" : "text-red-500"
        )}>
          {rating === 5 ? (t('review.excellent') || 'Excellent!') : 
           rating === 4 ? (t('review.good') || 'Great') : 
           rating === 3 ? (t('review.average') || 'Average') : 
           rating === 2 ? (t('review.poor') || 'Poor') : (t('review.terrible') || 'Terrible')}
        </span>
      </div>
      <div className="flex gap-2 p-2 bg-gray-50/30 rounded-lg justify-center border border-gray-100/50" onMouseLeave={() => setHoverRating(0)}>
        {[1, 2, 3, 4, 5].map((star) => (
          <button
            key={star}
            type="button"
            className="group relative focus:outline-none transition-transform hover:scale-125 active:scale-95 duration-200"
            onClick={() => setValue('rating', star)}
            onMouseEnter={() => setHoverRating(star)}
          >
            <Star
              size={36}
              className={cn(
                "transition-all duration-300",
                star <= (hoverRating || rating)
                  ? 'fill-yellow-400 text-yellow-400 filter drop-shadow-[0_0_8px_rgba(250,204,21,0.5)]'
                  : 'text-gray-200'
              )}
            />
          </button>
        ))}
      </div>
    </div>
  );
};

const CommentField = ({ form }: { form: UseFormReturn<ReviewFormValues> }) => {
  const { t } = useTranslation();
  const { register, watch, formState: { errors } } = form;
  const commentValue = watch('comment');
  const characterCount = commentValue?.length || 0;

  return (
    <div className="space-y-2">
      <div className="flex justify-between">
        <label className="text-sm font-semibold text-gray-700">{t('review.comment') || 'Public Review'}</label>
        <span className={cn(
            "text-xs font-mono transition-colors",
            characterCount > MAX_COMMENT_LENGTH ? "text-red-500" : "text-gray-400"
        )}>
          {characterCount}/{MAX_COMMENT_LENGTH}
        </span>
      </div>
      <div className="relative group">
        <Textarea
          {...register('comment')}
          placeholder={t('review.comment_placeholder') || "What did you like or dislike? How was the quality?"}
          className="min-h-[140px] bg-white/50 backdrop-blur-sm focus:bg-white transition-all border-gray-200 focus:ring-2 focus:ring-primary/20 rounded-xl resize-none"
          error={errors.comment?.message}
        />
      </div>
    </div>
  );
};

