              {/* Footer hint */}
              <div className="px-4 py-3 bg-secondary border-t border-border text-xs text-tertiary flex items-center justify-between">
                <span>{t('admin.search.pressEnter')}</span>
                <span className="flex items-center gap-1">
                  <Command size={10} /> + K {t('admin.search.ctrlKHint')}
                </span>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
};

export default AdminLayout;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Eye, Edit2, Trash2, ExternalLink } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog, TableActions } from '@/components/ui';
import { DataTable, type DataTableColumn } from '@/components/common/DataTable';
import { useBanners, useCreateBanner, useUpdateBanner, useDeleteBanner } from '@/hooks/useBanners';
import { BannerForm, BannerFormData } from './forms/BannerForm';
import { useToast } from '@/store';
import { BannerDto } from '@/services/bannerService';
import { formatDate } from '@/utils/format';
import { AdminPageHeader } from '@/components/admin';
import { PaginationDefaults } from '@/constants';

const BannersPage = () => {
  const { t } = useTranslation();
  const toast = useToast();

  // State
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const pageSize = PaginationDefaults.PAGE_SIZE;
  const [searchQuery, setSearchQuery] = useState('');

  // Fetch Data
  const { data: bannersResponse, isLoading, refetch } = useBanners({
    pageIndex: currentPage,
    pageSize,
    search: searchQuery || undefined,
  });

  const banners: BannerDto[] = bannersResponse?.data?.items || [];
  const totalItems = bannersResponse?.data?.totalItems || 0;
  const totalPages = Math.ceil(totalItems / pageSize);

  // Mutations
  const createMutation = useCreateBanner();
  const updateMutation = useUpdateBanner();
  const deleteMutation = useDeleteBanner();

  // Modal State
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingBanner, setEditingBanner] = useState<BannerDto | null>(null);
  const [viewingBanner, setViewingBanner] = useState<BannerDto | null>(null);

  // Selection State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const selectedToDelete = banners.filter(item => selectedIds.has(item.code));
  const [showBulkConfirm, setShowBulkConfirm] = useState(false);
  const [bannerToDelete, setBannerToDelete] = useState<BannerDto | null>(null);

  const columns: DataTableColumn<BannerDto>[] = [
    {
      id: 'title',
      header: t('common.fields.title'),
      accessor: (banner) => (
        <div>
          <p className="font-medium text-slate-800 dark:text-slate-100">{banner.title}</p>
          <p className="text-xs text-slate-500 truncate max-w-[200px]">{banner.content}</p>
        </div>
      ),
      sortable: true
    },
    {
      id: 'link',
      header: t('common.fields.linkUrl'),
      accessor: (banner) => banner.linkUrl ? (
        <a
          href={banner.linkUrl}
          target="_blank"
          rel="noopener noreferrer"
          className="text-blue-600 hover:underline flex items-center gap-1 text-sm"
        >
          {banner.linkText || t('common.fields.linkUrl')} <ExternalLink size={12} />
        </a>
      ) : <span className="text-slate-400">-</span>,
    },
    {
      id: 'priority',
      header: t('common.fields.priority'),
      accessor: 'priority',
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (banner) => (
        <Badge
          color={banner.isActive ? 'success' : 'secondary'}
          variant="outline"
        >
          {banner.isActive ? t('common.status.active') : t('common.status.inactive')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'createdAt',
      header: t('common.fields.date'),
      accessor: (banner) => <span className="text-slate-500">{formatDate(banner.createdAt)}</span>,
      sortable: true
    },

  ];

  const handleCreate = (data: BannerFormData) => {
    createMutation.mutate(data, {
      onSuccess: () => {
        setIsFormOpen(false);
        toast.success(t('common.messages.createSuccess'));
      },
      onError: () => toast.error(t('common.messages.createError')),
    });
  };

  const handleUpdate = (data: BannerFormData) => {
    if (!editingBanner) return;
    updateMutation.mutate({ code: editingBanner.code, data }, {
      onSuccess: () => {
        setIsFormOpen(false);
        setEditingBanner(null);
        toast.success(t('common.messages.updateSuccess'));
      },
      onError: () => toast.error(t('common.messages.updateError')),
    });
  };

  const handleDelete = () => {
    if (bannerToDelete) {
      deleteMutation.mutate(bannerToDelete.code, {
        onSuccess: () => {
          setBannerToDelete(null);
          toast.success(t('common.deleteSuccess'));
        },
        onError: () => toast.error(t('common.messages.deleteError')),
      });
    } else if (selectedToDelete.length > 0) {
      // Bulk delete simulation - wait for backend bulk delete or loop
      // Assuming loop for now or bulk if supported.
      // Hook only provides single delete.
      Promise.all(selectedToDelete.map(b => deleteMutation.mutateAsync(b.code)))
        .then(() => {
          setSelectedIds(new Set());
          setShowBulkConfirm(false);
          toast.success(t('common.deleteSuccess'));
        })
        .catch(() => toast.error(t('common.messages.deleteSomeError')));
    }
  };

  const openEdit = (banner: BannerDto) => {
    setEditingBanner(banner);
    setIsFormOpen(true);
  };

  const handleReset = () => {
    setSearchQuery('');
    setCurrentPage(PaginationDefaults.PAGE_INDEX);

  };

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.banners"
        subtitle="admin.subtitles.banners"
      />

      <DataTable
        columns={columns}
        data={banners}
        keyField="code"
        isLoading={isLoading}

        // Search
        onAdvancedSearch={(filters) => {
          // Mapping advanced filters to simple search for now if backend doesn't support complex
          if (filters.search) setSearchQuery(filters.search);
        }}
        onReset={handleReset}
        advancedFilterDefs={[
          {
            id: 'title',
            label: t('common.fields.title'),
            type: 'text',
            placeholder: t('common.placeholders.enterTitle')
          },
          {
            id: 'status',
            label: t('common.fields.status'),
            type: 'select',
            options: [
              { value: 'active', label: t('common.status.active') },
              { value: 'inactive', label: t('common.status.inactive') }
            ]
          }
        ]}


        // Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        totalItems={totalItems}
        pageSize={pageSize}
        onPageChange={setCurrentPage}

        // Actions
        onAdd={() => { setEditingBanner(null); setIsFormOpen(true); }}
        onRefresh={() => refetch()}
        onView={(item) => setViewingBanner(item)}
        onEdit={openEdit}
        onDelete={(item) => setBannerToDelete(item)}
        onBulkDelete={() => setShowBulkConfirm(true)}

        // Selection
        selectedIds={selectedIds}
        onSelectionChange={setSelectedIds}

        enableColumnVisibility={true}
        exportFilename="banners_export"
      />

      {/* Form Modal */}
      <Modal
        isOpen={isFormOpen}
        onClose={() => setIsFormOpen(false)}
        title={editingBanner ? (t('admin.actions.edit') + ' ' + t('admin.banners')) : (t('admin.actions.create') + ' ' + t('admin.banners'))}
        size="lg"
      >
        <BannerForm
          initialData={editingBanner ? {
            title: editingBanner.title,
            content: editingBanner.content || '',
            linkUrl: editingBanner.linkUrl || '',
            linkText: editingBanner.linkText || '',
            priority: editingBanner.priority,
            isActive: editingBanner.isActive
          } : undefined}
          onSubmit={editingBanner ? handleUpdate : handleCreate}
          onCancel={() => setIsFormOpen(false)}
          isLoading={createMutation.isPending || updateMutation.isPending}
        />
      </Modal>

      {/* View Modal */}
      <Modal
        isOpen={!!viewingBanner}
        onClose={() => setViewingBanner(null)}
        title={t('admin.actions.view') + ' ' + t('admin.banners')}
        size="md"
      >
        {viewingBanner && (
          <div className="space-y-4">
            <div>
              <h3 className="text-lg font-bold text-slate-800 dark:text-white">{viewingBanner.title}</h3>
              <Badge color={viewingBanner.isActive ? 'success' : 'secondary'} className="mt-1">
                {viewingBanner.isActive ? t('common.status.active') : t('common.status.inactive')}
              </Badge>
            </div>

            {viewingBanner.content && (
              <div className="p-3 bg-slate-50 dark:bg-slate-900 rounded-lg">
                <p className="text-sm text-slate-600 dark:text-slate-300">{viewingBanner.content}</p>
              </div>
            )}

            <div className="grid grid-cols-2 gap-4 text-sm">
              <div>
                <span className="text-slate-500 block">{t('common.fields.priority')}</span>
                <span className="font-medium">{viewingBanner.priority}</span>
              </div>
              <div>
                <span className="text-slate-500 block">{t('common.fields.createdAt')}</span>
                <span className="font-medium">{formatDate(viewingBanner.createdAt)}</span>
              </div>
              {viewingBanner.linkUrl && (
                <div className="col-span-2">
                  <span className="text-slate-500 block">{t('common.fields.linkUrl')}</span>
                  <a href={viewingBanner.linkUrl} target="_blank" className="text-blue-600 hover:underline break-all">
                    {viewingBanner.linkUrl}
                  </a>
                </div>
              )}
            </div>

            <div className="flex justify-end pt-4">
              <Button onClick={() => setViewingBanner(null)}>
                {t('common.close')}
              </Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!bannerToDelete || showBulkConfirm}
        onClose={() => { setBannerToDelete(null); setShowBulkConfirm(false); setSelectedIds(new Set()); }}
        onConfirm={handleDelete}
        title={t('admin.actions.delete')}
        message={t('common.confirmDelete', { count: bannerToDelete ? 1 : selectedToDelete.length })}
        isLoading={deleteMutation.isPending}
        variant="danger"
      />
    </div>
  );
};

export default BannersPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Plus, Tag, RefreshCw } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog, TableActions } from '@/components/ui';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { brandService, productService, type BrandDto, type CreateBrandRequest, type UpdateBrandRequest } from '@/services';
import { DataTable, type DataTableColumn } from '@/components/common';
import { AdminPageHeader } from '@/components/admin';
import { useEntityManager, useBrands } from '@/hooks';
import { BrandForm, type BrandFormData } from './forms';
import { StatsCards, StatItem } from '@/components/admin/StatsCards';
import { useQuery } from '@tanstack/react-query';
import { getImageUrl } from '@/utils/format';
import { SearchCondition } from '@/services/baseService';
import { useMemo } from 'react';

export default function BrandsPage() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [filters, setFilters] = useState<Record<string, string>>({});

  // Data Fetching
  const searchParams = useMemo(() => {
       const filterParams = [];
       if (filters.Name) filterParams.push({ field: 'Name', value: filters.Name, operator: SearchCondition.Contains });
       if (filters.IsActive) filterParams.push({ field: 'IsActive', value: filters.IsActive === 'true', operator: SearchCondition.Equal });
       
       return {
          pageIndex: page,
          pageSize,
          filters: filterParams
       };
    }, [page, pageSize, filters]);

  const { 
    data: result, 
    isLoading, 
    refetch 
  } = useBrands(searchParams);

  const brands = result?.data?.items || [];
  const totalItems = result?.data?.totalItems || 0;
  const totalPages = Math.ceil(totalItems / pageSize);

  // Entity Manager
  const {
      isFormOpen,
      editingItem: editingBrand,
      itemToDelete: brandToDelete,
      isDeleting,
      openCreate,
      openEdit,
      closeForm,
      confirmDelete: baseConfirmDelete,
      cancelDelete,
      createMutation,
      updateMutation,
      deleteMutation
  } = useEntityManager<BrandDto, CreateBrandRequest, UpdateBrandRequest>({
      service: brandService,
      queryKey: ['brands']
  });

  const confirmDelete = async (item: BrandDto) => {
    try {
        const result = await productService.search({ filters: [{ field: 'BrandCode', value: item.code }], pageSize: 1 });
        if (result.success && result.data && result.data.totalItems > 0) {
             alert(t('admin.brands.cannotDelete', { count: result.data.totalItems, defaultValue: `Cannot delete: Brand contains ${result.data.totalItems} products.` }));
             return;
        }
        baseConfirmDelete(item);
    } catch (error) {
        console.error("Check dependency failed", error);
        baseConfirmDelete(item);
    }
  };

  const { mutate: createBrand, isPending: isCreating } = createMutation;
  const { mutate: updateBrand, isPending: isUpdating } = updateMutation;
  const { mutate: deleteBrand } = deleteMutation;

  // View State
  const [viewingBrand, setViewingBrand] = useState<BrandDto | null>(null);

  // Selection
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Bulk Delete State
  const [itemsToDelete, setItemsToDelete] = useState<BrandDto[] | null>(null);

  const bulkDeleteMutation = useMutation({
    mutationFn: (codes: string[]) => brandService.deleteMultiple(codes),
    onSuccess: () => {
      setItemsToDelete(null);
      queryClient.invalidateQueries({ queryKey: ['brands'] });
    }
  });

  const handleBulkDelete = (items: BrandDto[]) => {
    setItemsToDelete(items);
  };

  const confirmBulkDelete = () => {
    if (itemsToDelete) {
      bulkDeleteMutation.mutate(itemsToDelete.map(i => i.code));
    }
  };

  const handleFormSubmit = async (formData: BrandFormData) => {
    if (editingBrand) {
      await updateBrand({
          id: editingBrand.code, 
          data: formData as UpdateBrandRequest
      }, {
          onSuccess: () => closeForm()
      });
    } else {
      await createBrand(formData as unknown as CreateBrandRequest, {
          onSuccess: () => closeForm()
      });
    }
  };

  const handleDelete = () => {
    if (brandToDelete) {
      deleteBrand(brandToDelete.code);
    }
  };

  const isSubmitting = isCreating || isUpdating;

  // Initial Data
  const prepareInitialData = (): Partial<BrandFormData> | undefined => {
      if (!editingBrand) return undefined;
      return {
          name: editingBrand.name,
          description: editingBrand.description || undefined,
          logoUrl: editingBrand.logoUrl || undefined,
          isActive: editingBrand.isActive
      };
  };

  // Columns
  const columns: DataTableColumn<BrandDto>[] = [
    {
      id: 'logo',
      header: t('common.fields.image'),
      accessor: (brand) => brand.logoUrl ? (
          <img src={getImageUrl(brand.logoUrl)} alt={brand.name} className="w-10 h-10 object-contain rounded-md border border-gray-100" />
      ) : (
          <div className="w-10 h-10 rounded-md bg-gray-50 flex items-center justify-center text-gray-400">
              <Tag size={20} />
          </div>
      ),
      className: 'w-[120px]'
    },
    {
      id: 'name',
      header: t('common.fields.name'),
      accessor: 'name',
      sortable: true,
    },
    {
      id: 'description',
      header: t('common.fields.description'),
      accessor: 'description',
      className: 'hidden md:table-cell max-w-[300px] truncate'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (brand) => (
        <Badge color={brand.isActive !== false ? 'success' : 'secondary'}>
          {brand.isActive !== false ? t('admin.status.active') : t('admin.status.inactive')}
        </Badge>
      ),
      className: 'text-center w-[120px]',
    },
    {
        id: 'actions',
        header: '',
        className: 'w-[100px]',
        accessor: (brand) => (
          <TableActions
            onView={() => setViewingBrand(brand)}
            onEdit={() => openEdit(brand)}
            onDelete={() => confirmDelete(brand)}
          />
        )
      }
  ];

  // Stats
  // Using simplified stats based on loaded data or separate query if API supported
  const stats: StatItem[] = [
      {
          label: t('common.fields.brand'),
          value: totalItems, 
          icon: <Tag size={24} />,
          color: 'blue',
      },
      // Not accurate if paginated, but shows loaded count? Or keep fetching specific stats endpoint if exists
      // If server provides stats endpoint, use it. BaseService doesn't seem to have getStats by default.
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.brands" 
        subtitle="admin.subtitles.brands" 
      />

      <StatsCards stats={stats} />

      <DataTable
        data={brands}
        columns={columns}
        isLoading={isLoading}
        searchPlaceholder={t('common.placeholders.search')}
        
        // Server-side props
        currentPage={page}
        pageSize={pageSize}
        totalItems={totalItems}
        totalPages={totalPages}
        onPageChange={setPage}
        onPageSizeChange={setPageSize}
        onRefresh={() => refetch()}

        // Advanced Filters
        advancedFilterDefs={[
             { id: 'Name', label: t('common.fields.name'), type: 'text', placeholder: t('common.placeholders.search') },
             { id: 'IsActive', label: t('common.fields.status'), type: 'select', options: [{ value: 'true', label: t('admin.status.active') }, { value: 'false', label: t('admin.status.inactive') }] }
        ]}
        onAdvancedSearch={setFilters}

        // Export
        onExportAllData={async () => {
           const res = await brandService.getAll(10000);
           return res.data?.items || [];
        }}
        exportFilename="brands"

        keyField="code"
        enableSelection
        selectedIds={selectedIds}
        onSelectionChange={setSelectedIds}
        onBulkDelete={handleBulkDelete}
        onAdd={() => openCreate()}
        onEdit={(item) => openEdit(item)}
        onDelete={(item) => confirmDelete(item)}
        onView={(item) => setViewingBrand(item)}
      />

       {/* Form Modal */}
       {isFormOpen && (
        <BrandForm
            initialData={prepareInitialData()}
            onSubmit={handleFormSubmit}
            onCancel={closeForm}
            isLoading={isSubmitting}
            modalOpen={isFormOpen}
            modalTitle={editingBrand ? t('admin.actions.edit') : t('admin.actions.create')}
            imageBaseUrl="https://example.com" 
        />
       )}

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!brandToDelete}
        onClose={cancelDelete}
        onConfirm={handleDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDelete', { name: brandToDelete?.name })}
        confirmText={t('admin.actions.delete')}
        cancelText={t('common.cancel')}
        variant="danger"
        isLoading={isDeleting}
      />

      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!itemsToDelete}
        onClose={() => setItemsToDelete(null)}
        onConfirm={confirmBulkDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDeleteCount', { count: itemsToDelete?.length || 0 })}
        confirmText={t('admin.actions.delete')}
        cancelText={t('common.cancel')}
        variant="danger"
        isLoading={bulkDeleteMutation.isPending}
      />

      {/* View Details Modal */}
      {viewingBrand && (
        <Modal
          isOpen={!!viewingBrand}
          onClose={() => setViewingBrand(null)}
          title={t('admin.actions.viewDetails')}
          size="md"
        >
          <div className="space-y-6">
             <div className="flex items-center gap-4 border-b border-gray-100 pb-4">
                {viewingBrand.logoUrl ? (
                    <img src={getImageUrl(viewingBrand.logoUrl)} className="w-16 h-16 object-contain rounded-lg border border-gray-100" />
                ) : (
                    <div className="w-16 h-16 bg-gray-50 rounded-lg flex items-center justify-center">
                        <Tag className="text-gray-400" />
                    </div>
                )}
                <div>
                    <h2 className="text-xl font-bold">{viewingBrand.name}</h2>
                    <Badge color={viewingBrand.isActive !== false ? 'success' : 'secondary'} className="mt-1">
                        {viewingBrand.isActive !== false ? t('admin.status.active') : t('admin.status.inactive')}
                    </Badge>
                </div>
             </div>
             
             <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.description')}</label>
                <p className="text-sm mt-1">{viewingBrand.description || t('common.none')}</p>
             </div>
             
             <div className="flex justify-end pt-4">
               <Button onClick={() => setViewingBrand(null)}>
                 {t('common.close')}
               </Button>
             </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Plus, Folder, RefreshCw } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog, TableActions } from '@/components/ui';
import { useCategories, useCategoriesList, useEntityManager } from '@/hooks';
import { categoryService, productService, type CategoryDto, type CreateCategoryRequest, type UpdateCategoryRequest } from '@/services';
import { DataTable, type DataTableColumn } from '@/components/common';
import { AdminPageHeader } from '@/components/admin';
import { CategoryForm, type CategoryFormData } from './forms';
import { PaginationDefaults, API_ENDPOINTS } from '@/constants';
import { CATEGORY_LIST_FIELDS } from '@/constants/fieldConstants';
import { getImageUrl } from '@/utils/format';
import { StatsCards, StatItem } from '@/components/admin/StatsCards';
import { useQuery } from '@tanstack/react-query';
import { useToast } from '@/store';

export default function CategoriesPage() {
  const { t } = useTranslation();
  const toast = useToast();
  
  // Pagination State
  const [pagination, setPagination] = useState({
    pageIndex: PaginationDefaults.PAGE_INDEX,
    pageSize: PaginationDefaults.PAGE_SIZE
  });

  // Get API Base URL for image previews
  const apiBaseUrl = import.meta.env.VITE_API_URL || 'http://localhost:5176/api/v1';

  // Data Fetching with Pagination
  const { 
    data, 
    isLoading, 
    refetch 
  } = useCategoriesList({
    pageIndex: pagination.pageIndex,
    pageSize: pagination.pageSize,
    fields: CATEGORY_LIST_FIELDS, 
  });

  const categories = data?.categories || [];
  const totalItems = data?.totalItems || 0;
  const totalPages = data?.totalPages || 0;

  // Entity Manager (for CRUD state)
  const {
    isFormOpen,
    editingItem: editingCategory,
    itemToDelete: categoryToDelete,
    isDeleting,
    openCreate,
    openEdit,
    closeForm,
    confirmDelete: baseConfirmDelete,
    cancelDelete,
    createMutation,
    updateMutation,
    deleteMutation
  } = useEntityManager<CategoryDto, CreateCategoryRequest, UpdateCategoryRequest>({
    service: categoryService,
    queryKey: ['categories'] 
  });

  const confirmDelete = async (item: CategoryDto) => {
    try {
        const result = await productService.search({ filters: [{ field: 'CategoryCode', value: item.code }], pageSize: 1 });
        if (result.success && result.data && result.data.totalItems > 0) {
             toast.error(t('admin.categories.cannotDelete', { 
                 count: result.data.totalItems, 
                 defaultValue: `Cannot delete: Category contains ${result.data.totalItems} products.` 
             }));
             return;
        }
        baseConfirmDelete(item);
    } catch (error) {
        console.error("Check dependency failed", error);
        baseConfirmDelete(item);
    }
  };

  const { mutate: createCategory, isPending: isCreating } = createMutation;
  const { mutate: updateCategory, isPending: isUpdating } = updateMutation;
  const { mutate: deleteCategory } = deleteMutation;

  // View State
  const [viewingCategory, setViewingCategory] = useState<CategoryDto | null>(null);

  // Selection State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  const handlePageChange = (page: number) => {
    setPagination(prev => ({ ...prev, pageIndex: page }));
  };

  const handlePageSizeChange = (size: number) => {
    setPagination(prev => ({ ...prev, pageSize: size, pageIndex: 1 }));
  };

  const handleFormSubmit = async (formData: CategoryFormData) => {
    if (editingCategory) {
      await updateCategory({
        id: editingCategory.code,
        data: {
          name: formData.name,
          description: formData.description,
          parentCode: formData.parentCode || null,
          imageURL: formData.imageURL,
          isActive: formData.isActive
        }
      });
    } else {
      await createCategory({
        name: formData.name,
        description: formData.description,
        parentCode: formData.parentCode || null,
        imageURL: formData.imageURL,
        isActive: formData.isActive
      });
    }
  };


  const handleImport = async (file: File) => {
      try {
          await categoryService.import(file);
          refetch();
      } catch (error) {
          console.error("Import error", error);
      }
  };

  const handleDelete = () => {
    if (categoryToDelete) {
      deleteCategory(categoryToDelete.code, {
        onSuccess: () => refetch()
      });
    }
  };

  const isSubmitting = isCreating || isUpdating;

  // Column definitions for DataTable
  const columns: DataTableColumn<CategoryDto>[] = [
    {
      id: 'imageURL',
      header: t('common.fields.image'),
      width: '120px',
      className: 'text-center',
      accessor: (category) => {

        return (
        <div className="flex flex-col items-center">
            <div className="w-10 h-10 rounded-lg overflow-hidden bg-gray-100 dark:bg-slate-700 border border-gray-200 dark:border-slate-600">
               {category.imageURL ? (
                 <img 
                   src={getImageUrl(category.imageURL)} 
                   alt={category.name} 
                   className="w-full h-full object-cover"
                   onError={(e) => console.error("Img Error:", e.currentTarget.src)}
                 />
               ) : (
                 <div className="w-full h-full flex items-center justify-center text-gray-400">
                   <Folder size={18} />
                 </div>
               )}
            </div>

        </div>
      );
    }
  },
    {
      id: 'name',
      header: t('common.fields.name'),
      accessor: 'name',
    },
    { 
      id: 'description',
      header: t('common.fields.description'),
      accessor: 'description',
      className: 'hidden md:table-cell text-gray-500' 
    },
    {
      id: 'parentCode',
      header: t('common.fields.parentCategory'),
      accessor: (category) => {
        if (!category.parentCode) return <span className="text-gray-400 italic">{t('common.none')}</span>;
        return (
          <Badge variant="outline" className="gap-1">
            <Folder size={10} className="mr-1" />
            {category.parentCode} 
          </Badge>
        );
      }
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (category) => (
        <Badge color={category.isActive !== false ? 'success' : 'secondary'}>
          {category.isActive !== false ? t('admin.status.active') : t('admin.status.inactive')}
        </Badge>
      )
    },
    {
      id: 'actions',
      header: t('common.fields.action'),
      width: '100px',
      className: 'w-[100px]',
      accessor: (category) => (
        <TableActions
          onView={() => setViewingCategory(category)}
          onEdit={() => openEdit(category)}
          onDelete={() => confirmDelete(category)}
        />
      )
    }
  ];

  const prepareInitialData = (): Partial<CategoryFormData> | undefined => {
      if (!editingCategory) return undefined;
      return {
          name: editingCategory.name,
          description: editingCategory.description || undefined,
          parentCode: editingCategory.parentCode || undefined,
          imageURL: editingCategory.imageURL || undefined,
          isActive: editingCategory.isActive
      };
  };

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['category-stats'],
      queryFn: () => categoryService.getStats(),
      staleTime: 60000,
  });

  const stats: StatItem[] = [
      {
          label: t('admin.stats.totalCategories'),
          value: statsData?.total || 0,
          icon: <Folder size={24} />,
          color: 'indigo',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.mainCategories'),
          value: statsData?.main || 0,
          icon: <Folder size={24} />, 
          color: 'emerald',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.active'),
          value: statsData?.active || 0, 
          icon: <RefreshCw size={24} />,
          color: 'amber',
          loading: isStatsLoading
      }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.categories"
        subtitle="admin.subtitles.categories"
      />

      <StatsCards stats={stats} />

      <DataTable
        data={categories}
        columns={columns}
        isLoading={isLoading}
        searchPlaceholder={t('common.placeholders.search')}
        advancedFilterDefs={[
          {
            id: 'name',
            label: t('common.fields.name'),
            type: 'text',
            placeholder: t('common.placeholders.search')
          },
          {
            id: 'status',
            label: t('common.fields.status'),
            type: 'select',
            options: [
              { value: 'active', label: t('admin.status.active') },
              { value: 'inactive', label: t('admin.status.inactive') }
            ]
          }
        ]}
        onAdvancedSearch={(filters) => {
             // Basic search simulation
             refetch(); // In real app, pass filters to hook
        }}
        onImport={handleImport}
        importTemplateUrl="/categories/template"
        importTitle={t('common.importData')}
        onExportAllData={() => categoryService.exportData()}
        keyField="code"
        enableSelection
        onAdd={() => openCreate()}
        onRefresh={() => refetch()}
        
        // Selection & Actions
        selectedIds={selectedIds}
        onSelectionChange={setSelectedIds}
        onEdit={(item) => openEdit(item)}
        onDelete={(item) => confirmDelete(item)}
        onBulkDelete={() => { /* categories doesn't seem to support bulk delete in hook yet? */ }}
        onView={(item) => setViewingCategory(item)}

        // Server-Side Pagination
        currentPage={pagination.pageIndex}
        totalItems={totalItems}
        totalPages={totalPages}
        pageSize={pagination.pageSize}
        onPageChange={handlePageChange}
        onPageSizeChange={handlePageSizeChange}
      />

       {/* Form Modal */}
       {isFormOpen && (
        <CategoryForm
            initialData={prepareInitialData()}
            onSubmit={handleFormSubmit}
            onCancel={closeForm}
            isLoading={isSubmitting}
            modalOpen={isFormOpen}
            modalTitle={editingCategory ? t('admin.actions.edit') : t('admin.actions.create')}
            excludeCode={editingCategory?.code}
            imageBaseUrl={apiBaseUrl.replace(/\/api\/v1\/?$/, '')}
        />
       )}

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!categoryToDelete}
        onClose={cancelDelete}
        onConfirm={handleDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDelete', { name: categoryToDelete?.name })}
        confirmText={t('admin.actions.delete')}
        cancelText={t('common.cancel')}
        variant="danger"
        isLoading={isDeleting}
      />

      {/* View Details Modal */}
      {viewingCategory && (
        <Modal
          isOpen={!!viewingCategory}
          onClose={() => setViewingCategory(null)}
          title={t('admin.actions.viewDetails')}
          size="md"
        >
          <div className="space-y-4">
            {viewingCategory.imageURL && (
              <div className="relative w-full h-48 rounded-lg overflow-hidden border border-gray-100 dark:border-gray-700">
                <img 
                  src={getImageUrl(viewingCategory.imageURL)} 
                  alt={viewingCategory.name} 
                  className="w-full h-full object-cover"
                />
              </div>
            )}
            
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.code')}</label>
                <p className="font-medium">{viewingCategory.code}</p>
              </div>
              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.name')}</label>
                <p className="font-medium">{viewingCategory.name}</p>
              </div>
              
              {viewingCategory.parentCode && (
                <div className="col-span-2">
                   <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.parentCategory')}</label>
                   <div className="mt-1">
                     <Badge variant="outline">
                       <Folder size={12} className="mr-1" />
                       {categories.find(c => c.code === viewingCategory.parentCode)?.name || viewingCategory.parentCode}
                     </Badge>
                   </div>
                </div>
              )}
              
              <div className="col-span-2">
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.description')}</label>
                <p className="text-gray-600 dark:text-gray-300">
                  {viewingCategory.description || t('common.none')}
                </p>
              </div>

               <div className="col-span-2">
                  <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.status')}</label>
                  <div className="mt-1">
                      <Badge color={viewingCategory.isActive !== false ? 'success' : 'secondary'}>
                          {viewingCategory.isActive !== false ? t('admin.status.active') : t('admin.status.inactive')}
                      </Badge>
                  </div>
              </div>
            </div>
            
            <div className="flex justify-end pt-4">
              <Button onClick={() => setViewingCategory(null)}>
                {t('common.close')}
              </Button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Ticket, Plus, Search, Trash2, Edit, RefreshCw } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { AdminPageHeader } from '@/components/admin';
import { DataTable } from '@/components/common';
import { formatDate } from '@/utils/format';
import { couponService, type CouponDto } from '@/services/couponService';
import { promotionService } from '@/services/promotionService';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { PaginationDefaults } from '@/constants';
import { useToast } from '@/store';

export const CouponsPage = () => {
  const { t } = useTranslation();
  const { success, error: toastError } = useToast();
  const queryClient = useQueryClient();

  // State
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCoupon, setEditingCoupon] = useState<CouponDto | null>(null);
  const [couponToDelete, setCouponToDelete] = useState<CouponDto | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    code: '',
    promotionCode: '',
    isActive: true
  });

  // Queries
  const { data: couponsData, isLoading, isFetching } = useQuery({
    queryKey: ['admin-coupons', currentPage, pageSize, searchQuery],
    queryFn: () => couponService.search({
      pageIndex: currentPage,
      pageSize: pageSize,
      search: searchQuery
    }),
  });

  const { data: promotionsData } = useQuery({
    queryKey: ['admin-promotions-all'],
    queryFn: () => promotionService.getAll({ pageSize: 100 }),
  });

  const coupons = couponsData?.data?.items || [];
  const totalPages = couponsData?.data?.totalPages || 1;
  const promotions = promotionsData?.data?.items || [];

  // Mutations
  const createMutation = useMutation({
    mutationFn: (data: any) => couponService.create(data),
    onSuccess: () => {
      success(t('messages.createSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-coupons'] });
      setIsModalOpen(false);
      resetForm();
    },
    onError: (err: any) => toastError(err.message || t('messages.createError'))
  });

  const updateMutation = useMutation({
    mutationFn: ({ code, data }: { code: string, data: any }) => couponService.update(code, data),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-coupons'] });
      setIsModalOpen(false);
      resetForm();
    },
    onError: (err: any) => toastError(err.message || t('messages.updateError'))
  });

  const deleteMutation = useMutation({
    mutationFn: (code: string) => couponService.delete(code),
    onSuccess: () => {
      success(t('messages.deleteSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-coupons'] });
      setCouponToDelete(null);
    },
    onError: () => toastError(t('messages.deleteError'))
  });

  // Handlers
  const resetForm = () => {
    setFormData({ code: '', promotionCode: '', isActive: true });
    setEditingCoupon(null);
  };

  const handleEdit = (coupon: CouponDto) => {
    setEditingCoupon(coupon);
    setFormData({
      code: coupon.code,
      promotionCode: coupon.promotionCode || '',
      isActive: coupon.isActive
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingCoupon) {
      updateMutation.mutate({ code: editingCoupon.code, data: { promotionCode: formData.promotionCode, isActive: formData.isActive } });
    } else {
      createMutation.mutate(formData);
    }
  };

  const generateRandomCode = () => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
    let result = '';
    for (let i = 0; i < 8; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setFormData({ ...formData, code: result });
  };

  // Columns
  const columns = [
    {
      id: 'code',
      header: t('common.fields.code'),
      accessor: (row: CouponDto) => <span className="font-mono font-bold text-primary">{row.code}</span>,
    },
    {
      id: 'promotion',
      header: t('admin.promotion.name'),
      accessor: (row: CouponDto) => (
        <div>
          <p className="font-medium">{row.promotionName || row.promotionCode || t('common.none')}</p>
          <p className="text-xs text-tertiary">{row.promotionCode}</p>
        </div>
      )
    },
    {
      id: 'usage',
      header: t('admin.coupon.usage'),
      accessor: (row: CouponDto) => (
        <div className="flex flex-col items-center">
          <span className="text-sm font-medium">{row.usageCount || 0}</span>
          <p className="text-[10px] text-tertiary uppercase tracking-wider">{t('admin.coupon.timesUsed')}</p>
        </div>
      ),
      className: 'text-center'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (row: CouponDto) => (
        <Badge color={row.isActive ? 'success' : 'error'} size="sm">
          {row.isActive ? t('admin.status.active') : t('admin.status.inactive')}
        </Badge>
      ),
      className: 'text-center'
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (row: CouponDto) => <span className="text-secondary text-sm">{formatDate(row.createdAt)}</span>
    }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.coupons"
        subtitle="admin.subtitles.coupons"
        rightSection={
          <Button leftIcon={<Plus size={18} />} onClick={() => { resetForm(); setIsModalOpen(true); }}>
            {t('admin.coupon.add')}
          </Button>
        }
      />

      {/* Toolbar */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between bg-primary p-4 rounded-xl border border-tertiary">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" size={18} />
          <input
            type="text"
            placeholder={t('common.placeholders.search')}
            className="w-full pl-10 pr-4 py-2 bg-secondary border border-tertiary rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
        <div className="flex gap-2">
           <Button variant="outline" onClick={() => queryClient.invalidateQueries({ queryKey: ['admin-coupons'] })}>
              <RefreshCw size={18} className={isFetching ? 'animate-spin' : ''} />
           </Button>
        </div>
      </div>

      <DataTable
        columns={columns}
        data={coupons}
        isLoading={isLoading || isFetching}
        keyField="code"
        
        currentPage={currentPage}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setCurrentPage}
        onPageSizeChange={setPageSize}

        renderRowActions={(row) => (
          <div className="flex items-center gap-1">
            <button
              className="p-1.5 hover:bg-primary/10 rounded text-primary"
              title={t('common.actions.edit')}
              onClick={() => handleEdit(row)}
            >
              <Edit size={18} />
            </button>
            <button
              className="p-1.5 hover:bg-error/10 rounded text-error"
              title={t('common.actions.delete')}
              onClick={() => setCouponToDelete(row)}
            >
              <Trash2 size={18} />
            </button>
          </div>
        )}
      />

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={editingCoupon ? t('admin.coupon.edit') : t('admin.coupon.add')}
        footer={
          <div className="flex justify-end gap-2">
             <Button variant="outline" onClick={() => setIsModalOpen(false)}>{t('common.cancel')}</Button>
             <Button onClick={handleSubmit} isLoading={createMutation.isPending || updateMutation.isPending}>{t('common.save')}</Button>
          </div>
        }
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1">{t('common.fields.code')} <span className="text-error">*</span></label>
            <div className="flex gap-2">
              <input
                type="text"
                className="flex-1 p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 disabled:opacity-50 font-mono"
                value={formData.code}
                onChange={(e) => setFormData({ ...formData, code: e.target.value.toUpperCase() })}
                disabled={!!editingCoupon}
                required
              />
              {!editingCoupon && (
                <Button type="button" variant="outline" size="sm" onClick={generateRandomCode}>
                  {t('common.generate')}
                </Button>
              )}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium mb-1">{t('admin.promotion.name')} <span className="text-error">*</span></label>
            <select
              className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
              value={formData.promotionCode}
              onChange={(e) => setFormData({ ...formData, promotionCode: e.target.value })}
              required
            >
              <option value="">{t('common.placeholders.select')}</option>
              {promotions.map(p => (
                <option key={p.code} value={p.code}>{p.name} ({p.discountType === 'PERCENTAGE' ? `${p.discountValue}%` : t('common.currency', { value: p.discountValue })})</option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-2 pt-2">
            <input
              type="checkbox"
              id="isActive"
              className="w-4 h-4 rounded border-tertiary"
              checked={formData.isActive}
              onChange={(e) => setFormData({ ...formData, isActive: e.target.checked })}
            />
            <label htmlFor="isActive" className="text-sm font-medium cursor-pointer">{t('admin.status.active')}</label>
          </div>
        </form>
      </Modal>

      <ConfirmDialog
        isOpen={!!couponToDelete}
        onClose={() => setCouponToDelete(null)}
        onConfirm={() => couponToDelete && deleteMutation.mutate(couponToDelete.code)}
        title={t('common.actions.delete')}
        message={t('messages.confirmDelete')}
        variant="danger"
        isLoading={deleteMutation.isPending}
      />
    </div>
  );
};

export default CouponsPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Mail, Phone, Users, AlertTriangle, Key } from 'lucide-react';
import { Button, Modal, Badge, ConfirmDialog, TableActions, Input, Select, Switch } from '@/components/ui';
import { useToast } from '@/store';
import { formatCurrency, formatDate } from '@/utils/format';
import { DataTable, type DataTableColumn } from '@/components/common/DataTable';
import { AdminPageHeader } from '@/components/admin';
import { useEntityManager } from '@/hooks';
import { customerService, type CustomerDto, type CreateCustomerRequest, type UpdateCustomerRequest } from '@/services';
import { useQuery, useMutation } from '@tanstack/react-query';
import { PaginationDefaults, SortDirection } from '@/constants';
import { StatsCards, StatItem } from '@/components/admin/StatsCards';

export const CustomersPage = () => {
  const { t } = useTranslation();
  const [selectedCustomer, setSelectedCustomer] = useState<CustomerDto | null>(null);
  const [resettingCustomer, setResettingCustomer] = useState<CustomerDto | null>(null);
  const [newPassword, setNewPassword] = useState('');

  // State for Fetching
  const [pageIndex, setPageIndex] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [sortField, setSortField] = useState('createdAt');
  const [sortDir, setSortDir] = useState<SortDirection>(SortDirection.DESC);
  const [filters, setFilters] = useState<Record<string, string>>({ role: 'customer' });

  // Fetch Data
  const { data: customerResponse, isLoading, refetch } = useQuery({
    queryKey: ['customers', pageIndex, pageSize, sortField, sortDir, filters],
    queryFn: () => customerService.search({
      pageIndex,
      pageSize,
      sortBy: sortField,
      sortDesc: sortDir === SortDirection.DESC,
      filters: Object.entries(filters).map(([field, value]) => ({ field, value })),
      search: filters.search,
      searchField: filters.search ? 'fullName' : undefined
    })
  });

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['customer-stats'],
      queryFn: () => customerService.getStats(),
      staleTime: 60000, 
  });

  const stats: StatItem[] = [
      {
          label: t('admin.stats.totalCustomers'),
          value: statsData?.total || 0,
          icon: <Users size={24} />,
          color: 'blue',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.notActivated'),
          value: statsData?.unverified || 0,
          icon: <AlertTriangle size={24} />,
          color: 'rose',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.activeCustomers'),
          value: statsData?.active || 0,
          icon: <Users size={24} />,
          color: 'emerald',
          loading: isStatsLoading
      }
  ];

  const items = customerResponse?.data?.items || [];
  const totalCount = customerResponse?.data?.totalItems || PaginationDefaults.TOTAL_ITEMS;
  const totalPages = Math.ceil(totalCount / pageSize) || PaginationDefaults.TOTAL_PAGES;

  // Entity Manager
  const {
      isFormOpen,
      editingItem: editingCustomer,
      itemToDelete: customerToDelete,
      isLoading: isSubmitting,
      isDeleting,
      openCreate,
      openEdit,
      closeForm,
      confirmDelete,
      cancelDelete,
      create: createCustomer,
      update: updateCustomer,
      delete: deleteCustomer
  } = useEntityManager<CustomerDto, CreateCustomerRequest, UpdateCustomerRequest>({
    service: customerService,
    queryKey: ['customers', pageIndex, pageSize, sortField, sortDir, filters],
  });

  const toast = useToast();
  // Bulk Delete State
  const [itemsToDelete, setItemsToDelete] = useState<CustomerDto[] | null>(null);

  const bulkDeleteMutation = useMutation({
    mutationFn: (codes: string[]) => customerService.deleteMultiple(codes),
    onSuccess: () => {
      toast.success(t('common.deleteSuccess'));
      setItemsToDelete(null);
      refetch();
    },
    onError: (err: any) => {
      toast.error(err.message || t('common.deleteError'));
    }
  });

  const handleBulkDelete = (items: CustomerDto[]) => {
    setItemsToDelete(items);
  };

  const confirmBulkDelete = () => {
    if (itemsToDelete) {
      bulkDeleteMutation.mutate(itemsToDelete.map(i => i.code));
    }
  };

  // Form State
  const [formData, setFormData] = useState({
      username: '',
      email: '',
      password: '',
      fullName: '',
      phone: '',
      role: 'customer',
      isActive: true,
      debtLimit: 0,
  });

  const resetForm = () => setFormData({
      username: '',
      email: '',
      password: '',
      fullName: '',
      phone: '',
      role: 'customer',
      isActive: true,
      debtLimit: 0,
  });

  const handleOpenCreate = () => {
      resetForm();
      openCreate();
  };

  const handleOpenEdit = (customer: CustomerDto) => {
      setFormData({
          username: customer.username || '',
          email: customer.email,
          password: '',
          fullName: customer.fullName || '',
          phone: customer.phone || '',
          role: customer.role || 'customer',
          role: customer.role || 'customer',
          isActive: customer.isActive,
          debtLimit: customer.debtLimit || 0
      });
      openEdit(customer);
  };

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      
      if (editingCustomer) {
          updateCustomer(editingCustomer.code, {
              fullName: formData.fullName,
              email: formData.email,
              phone: formData.phone,
              role: formData.role,
              isActive: formData.isActive,
              password: formData.password || undefined,
              debtLimit: formData.debtLimit
          });
      } else {
          createCustomer({
              username: formData.username,
              email: formData.email,
              password: formData.password,
              fullName: formData.fullName,
              phone: formData.phone,
              role: formData.role,
              isActive: formData.isActive
          });
      }
  };

  const handleResetPasswordPrompt = (customer: CustomerDto) => {
      setResettingCustomer(customer);
      setNewPassword('');
  };

  const confirmResetPassword = async () => {
      if (!resettingCustomer || !newPassword) return;
      try {
          await customerService.update(resettingCustomer.code, { password: newPassword });
          toast.success(t('messages.saveSuccess'));
          setResettingCustomer(null);
      } catch (err) {
          toast.error(t('messages.error'));
      }
  };


  const columns: DataTableColumn<CustomerDto>[] = [
    {
      id: 'fullName',
      header: t('common.fields.customer'),
      accessor: (customer) => (
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold shadow-sm">
            {customer.fullName?.charAt(0) || customer.username?.charAt(0)}
          </div>
          <div>
            <p className="font-medium text-slate-800 dark:text-slate-100">{customer.fullName || customer.username}</p>
            <p className="text-xs text-slate-500">{customer.username}</p>
          </div>
        </div>
      ),
      sortable: true
    },
    {
      id: 'contact',
      header: t('common.fields.contact'),
      accessor: (customer) => (
        <div className="space-y-1">
          <p className="text-sm flex items-center gap-2 text-slate-600 dark:text-slate-400">
            <Mail size={14} className="text-blue-400" />
            {customer.email}
          </p>
          {customer.phone && (
            <p className="text-sm flex items-center gap-2 text-slate-500 dark:text-slate-500">
              <Phone size={14} className="text-slate-400" />
              {customer.phone}
            </p>
          )}
        </div>
      )
    },
    {
      id: 'role',
      header: t('common.fields.role'),
      accessor: (customer) => (
        <Badge color={customer.role === 'admin' ? 'error' : 'info'}>
          {t(`admin.types.${customer.role.toLowerCase()}`, customer.role)}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'isActive',
      header: t('common.fields.status'),
      accessor: (customer) => (
        <Badge color={customer.isActive ? 'success' : 'secondary'}>
          {customer.isActive ? t('admin.status.active') : t('admin.status.inactive')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'isEmailVerified',
      header: t('common.fields.emailVerified', 'Email Verified'),
      accessor: (customer) => (
        <Badge color={customer.isEmailVerified ? 'success' : 'error'} variant="outline">
          {customer.isEmailVerified ? t('admin.status.verified') : t('admin.status.unactivated')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
        id: 'debt',
        header: t('admin.debt'),
        accessor: (customer) => {
            const debt = customer.currentDebt || 0;
            const limit = customer.debtLimit || 0;
            const isOverLimit = limit > 0 && debt > limit;
            return (
                <div className="flex flex-col items-end">
                    <span className={`font-medium ${isOverLimit ? 'text-red-500' : debt > 0 ? 'text-amber-600' : 'text-slate-600'}`}>
                        {formatCurrency(debt)}
                    </span>
                    {limit > 0 && (
                        <span className="text-xs text-slate-400">
                            / {formatCurrency(limit)}
                        </span>
                    )}
                </div>
            );
        },
        className: 'text-right',
        headerClassName: 'text-right'
    },
    {
      id: 'lastLogin',
      header: t('common.fields.lastLogin', 'Last Login'),
      accessor: (customer) => <span className="text-slate-500">{customer.lastLogin ? formatDate(customer.lastLogin) : t('common.never', 'Never')}</span>,
      sortable: true
    },
    {
      id: 'joinDate',
      header: t('common.fields.joinDate'),
      accessor: (customer) => <span className="text-slate-500">{formatDate(customer.createdAt)}</span>,
      sortable: true
    },

  ];

  const handleSort = (field: string, dir: 'asc' | 'desc') => {
    setSortField(field);
    setSortDir(dir as SortDirection);
  };

  const handleAdvancedSearch = (newFilters: Record<string, string>) => {
    setFilters(newFilters);
    setPageIndex(PaginationDefaults.PAGE_INDEX);
  };

  const handleReset = () => {
    // Reset to starting state: just customers sorted by createdAt desc
    setFilters({ role: 'customer' }); 
    setPageIndex(PaginationDefaults.PAGE_INDEX);
    setSortField('createdAt');
    setSortDir(SortDirection.DESC);
    refetch();
  };

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.customers"
        subtitle="admin.subtitles.customers"
      />

      <StatsCards stats={stats} />

      <DataTable
        columns={columns}
        data={items}
        keyField="code"
        isLoading={isLoading}
        onBulkDelete={handleBulkDelete}
        onView={(customer) => setSelectedCustomer(customer)}
        onEdit={handleOpenEdit}
        onDelete={confirmDelete}
        onAdd={handleOpenCreate}
        initialFilters={{ role: 'customer' }}
        renderRowActions={(customer) => (
            <button
              className="p-1.5 text-slate-500 hover:text-amber-600 hover:bg-amber-50 rounded transition-colors"
              title={t('admin.actions.resetPassword')}
              onClick={() => handleResetPasswordPrompt(customer)}
            >
              <Key size={18} />
            </button>
        )}

        // Sorting
        externalSortField={sortField}
        externalSortDir={sortDir}
        onExternalSort={handleSort}

        // Search & Filter
        onAdvancedSearch={handleAdvancedSearch}
        onReset={handleReset}
        advancedFilterDefs={[
          {
            id: 'fullName',
            label: t('common.fields.customer'),
            type: 'text',
            placeholder: t('common.placeholders.search')
          },
          {
            id: 'email',
            label: 'Email',
            type: 'text',
          },
          {
            id: 'phone',
            label: t('common.fields.phone'),
            type: 'text',
          },
          {
            id: 'role',
            label: t('common.fields.role'),
            type: 'select',
            options: [
              { value: 'customer', label: t('admin.types.customer') },
              { value: 'admin', label: t('admin.types.admin') },
              { value: 'staff', label: t('admin.types.staff') }
            ]
          }
        ]}

        // Pagination
        currentPage={pageIndex}
        totalItems={totalCount}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setPageIndex}
        onPageSizeChange={(size) => {
          setPageSize(size);
          setPageIndex(PaginationDefaults.PAGE_INDEX);
        }}

        // Visibility
        enableColumnVisibility={true}
        exportFilename="customers_export"
        onExportAllData={async () => {
          const response = await customerService.search({ pageIndex: 1, pageSize: 10000 });
          return (response.data?.items || []) as unknown as CustomerDto[];
        }}
        emptyMessage={t('common.noResults')}
      />

      {/* Customer Detail Modal */}
      <Modal
        isOpen={!!selectedCustomer}
        onClose={() => setSelectedCustomer(null)}
        title={t('admin.actions.view') + ' ' + t('common.fields.customer')}
        size="md"
      >
        {selectedCustomer && (
          <div className="space-y-6">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold text-2xl shadow-md">
                {selectedCustomer.fullName?.charAt(0) || selectedCustomer.username?.charAt(0)}
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">{selectedCustomer.fullName}</h2>
                <p className="text-slate-500">{selectedCustomer.email}</p>
                <div className="flex items-center gap-2 mt-1">
                    <Badge color={selectedCustomer.isActive ? 'success' : 'secondary'}>
                    {selectedCustomer.isActive ? t('admin.status.active') : t('admin.status.inactive')}
                    </Badge>
                     <Badge color={selectedCustomer.role === 'admin' ? 'error' : 'info'}>{selectedCustomer.role}</Badge>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="font-semibold text-slate-800 dark:text-white">{t('common.fields.contact')}</h3>
              <div className="space-y-2 text-slate-600 dark:text-slate-400">
                <p className="flex items-center gap-2">
                  <Mail size={16} className="text-blue-500" />
                  {selectedCustomer.email}
                </p>
                {selectedCustomer.phone && (
                  <p className="flex items-center gap-2">
                    <Phone size={16} className="text-slate-400" />
                    {selectedCustomer.phone}
                  </p>
                )}
                <p className="flex items-center gap-2">
                  <span className="font-semibold w-24">{t('common.fields.username')}:</span>
                  {selectedCustomer.username}
                </p>
                <p className="flex items-center gap-2">
                  <span className="font-semibold w-24">{t('common.fields.address')}:</span>
                  {selectedCustomer.address ? `${selectedCustomer.address}, ${selectedCustomer.ward}, ${selectedCustomer.district}, ${selectedCustomer.city}` : t('common.actions.none')}
                </p>
              </div>
            </div>

            <div className="space-y-3">
                 <h3 className="font-semibold text-slate-800 dark:text-white">{t('admin.financial')}</h3>
                 <div className="grid grid-cols-2 gap-4">
                     <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-lg">
                         <p className="text-xs text-slate-500">{t('admin.currentDebt')}</p>
                         <p className={`text-lg font-bold ${(selectedCustomer.currentDebt || 0) > (selectedCustomer.debtLimit || 0) ? 'text-red-500' : 'text-slate-800 dark:text-white'}`}>
                             {formatCurrency(selectedCustomer.currentDebt || 0)}
                         </p>
                     </div>
                      <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-lg">
                         <p className="text-xs text-slate-500">{t('admin.debtLimit')}</p>
                         <p className="text-lg font-bold text-slate-800 dark:text-white">
                             {formatCurrency(selectedCustomer.debtLimit || 0)}
                         </p>
                     </div>
                 </div>
            </div>

            <div className="flex gap-3">
              <Button fullWidth>
                {t('common.fields.email')}
              </Button>
            </div>
             <div className="flex justify-end pt-4">
              <Button onClick={() => setSelectedCustomer(null)} variant="outline">
                {t('common.close')}
              </Button>
            </div>
          </div>
        )}
      </Modal>


      {/* Customer Create/Edit Modal */}
      <Modal
        isOpen={isFormOpen}
        onClose={closeForm}
        title={editingCustomer ? t('admin.actions.edit') + ' ' + t('common.fields.customer') : t('admin.actions.create') + ' ' + t('common.fields.customer')}
        size="lg"
      >
        <form onSubmit={handleSubmit} className="space-y-4">
            {!editingCustomer && (
                <Input
                    label={t('common.fields.username')}
                    value={formData.username}
                    onChange={e => setFormData({...formData, username: e.target.value})}
                    isRequired
                    placeholder={t('common.placeholders.enterName')}
                />
            )}
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <Input
                    label={t('common.fields.customer')}
                    value={formData.fullName}
                    onChange={e => setFormData({...formData, fullName: e.target.value})}
                    placeholder={t('common.placeholders.enterName')}
                />
                 <Input
                    label={t('common.fields.email')}
                    type="email"
                    value={formData.email}
                    onChange={e => setFormData({...formData, email: e.target.value})}
                    isRequired
                    placeholder="example@email.com"
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <Input
                    label={t('common.fields.phone')}
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                    placeholder={t('common.placeholders.enterPhone')}
                />
                 <Select
                    label={t('common.fields.role')}
                    value={formData.role}
                    onChange={e => setFormData({...formData, role: e.target.value})}
                    options={[
                        { value: 'customer', label: t('admin.types.customer') },
                        { value: 'admin', label: t('admin.types.admin') },
                        { value: 'staff', label: t('admin.types.staff') }
                    ]}
                />
            </div>

             <Input
                label={editingCustomer ? t('common.fields.newPassword') : t('common.fields.password')}
                type="password"
                value={formData.password}
                onChange={e => setFormData({...formData, password: e.target.value})}
                isRequired={!editingCustomer}
                placeholder={editingCustomer ? t('common.hints.leaveBlankKeepCurrent') : t('common.placeholders.enterPassword')}
            />

                <div className="p-4 bg-gray-50 dark:bg-slate-800/50 rounded-lg">
                     <Switch
                        label={t('common.fields.status')}
                        description={t('admin.statusHint', 'Bật để tài khoản hoạt động')}
                        checked={formData.isActive}
                        onChange={(checked) => setFormData({...formData, isActive: checked})}
                     />
                </div>

            <div className="flex justify-end gap-3 pt-4">
                <Button type="button" variant="outline" onClick={closeForm}>
                    {t('common.cancel')}
                </Button>
                <Button type="submit" isLoading={isSubmitting}>
                    {editingCustomer ? t('common.save') : t('common.create')}
                </Button>
            </div>
        </form>
      </Modal>

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!customerToDelete}
        onClose={cancelDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDelete')}
        confirmText={t('common.delete')}
        onConfirm={() => customerToDelete && deleteCustomer(customerToDelete.code)}
        isLoading={isDeleting}
      />
      
      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!itemsToDelete}
        onClose={() => setItemsToDelete(null)}
        onConfirm={confirmBulkDelete}
        title={t('admin.actions.delete')}
        message={t('common.confirmDelete', { count: itemsToDelete?.length || 0 })}
        confirmText={t('common.delete')}
        isLoading={bulkDeleteMutation.isPending}
      />

      <Modal
        isOpen={!!resettingCustomer}
        onClose={() => setResettingCustomer(null)}
        title={t('admin.actions.resetPasswordTitle', { name: resettingCustomer?.fullName || resettingCustomer?.username })}
        size="sm"
      >
        <div className="space-y-4">
            <Input
                label={t('common.fields.newPassword')}
                type="password"
                value={newPassword}
                onChange={e => setNewPassword(e.target.value)}
                placeholder={t('common.placeholders.enterPassword')}
                isRequired
            />
            <div className="flex justify-end gap-3">
                <Button variant="outline" onClick={() => setResettingCustomer(null)}>{t('common.cancel')}</Button>
                <Button onClick={confirmResetPassword} disabled={!newPassword}>{t('common.update')}</Button>
            </div>
        </div>
      </Modal>
    </div>
  );
};

export default CustomersPage;

import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import {
  DollarSign,
  ShoppingBag,
  Users,
  Package,
  TrendingUp,
  TrendingDown,
  ArrowUpRight,
  FileText,
  Loader2,
} from 'lucide-react';
import { RevenueChart, AdminPageHeader } from '@/components/admin';
import { formatCurrency, getStatusColor, getStatusText } from '@/utils/format';
import { dashboardService } from '@/services';
import { useQuery } from '@tanstack/react-query';
import { useAdminOrders, useProducts } from '@/hooks';
import { PageSize, PaginationDefaults } from '@/constants';

// ============ Stat Card Component ============
interface StatCardProps {
  title: string;
  value: string | number;
  change?: number;
  icon: React.ElementType;
  color: string;
}

const StatCard = ({ title, value, change, icon: Icon, color }: StatCardProps) => {
  const { t } = useTranslation();
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-primary rounded-xl p-6"
    >
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm text-secondary mb-1">{title}</p>
          <p className="text-2xl font-bold">{value}</p>
          {typeof change === 'number' && (
            <p className={`flex items-center gap-1 text-sm mt-2 ${change >= 0 ? 'text-success' : 'text-error'}`}>
              {change >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
              {change >= 0 ? '+' : ''}{change}% {t('admin.stats.vsLastMonth')}
            </p>
          )}
        </div>
        <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${color}`}>
          <Icon size={24} className="text-white" />
        </div>
      </div>
    </motion.div>
  );
};

import { Link } from 'react-router-dom';

// ============ Low Stock Widget ============
const LowStockWidget = () => {
    const { t } = useTranslation();
    const { data, isLoading } = useProducts({ 
        pageIndex: 1, 
        pageSize: 5, 
        maxStock: 10, // Threshold
        sortField: 'stockQuantity', 
        sortDir: 'asc' 
    });
    
    const lowStockProducts = data?.products || [];

    return (
        <div className="bg-primary rounded-xl p-6 border border-amber-100 dark:border-amber-900/30">
            <div className="flex items-center justify-between mb-4">
                <h2 className="font-bold text-amber-600 dark:text-amber-500 flex items-center gap-2">
                    <TrendingDown size={20} />
                    {t('admin.lowStock', 'Sắp hết hàng')}
                </h2>
                <Link to="/admin/products?sortField=stockQuantity&sortDir=asc" className="text-sm text-primary hover:underline">
                    {t('common.viewAll')}
                </Link>
            </div>
            
            <div className="space-y-3">
                {isLoading ? (
                    <div className="py-4 text-center"><Loader2 className="animate-spin mx-auto text-amber-500" /></div>
                ) : lowStockProducts.length === 0 ? (
                    <p className="text-secondary text-sm text-center py-4">{t('admin.noLowStock', 'Tồn kho ổn định')}</p>
                ) : (
                    lowStockProducts.map((product) => (
                        <div key={product.code} className="flex items-center justify-between p-2 hover:bg-secondary rounded-lg transition-colors group">
                            <div className="flex items-center gap-3 overflow-hidden">
                                {product.imageURL && (
                                    <img src={product.imageURL} alt={product.name} className="w-8 h-8 rounded-md object-cover bg-white" />
                                )}
                                <div className="min-w-0">
                                    <p className="font-medium text-sm truncate group-hover:text-primary transition-colors">{product.name}</p>
                                    <p className="text-xs text-secondary">{product.code}</p>
                                </div>
                            </div>
                            <div className="flex flex-col items-end pl-2">
                                <span className={`text-sm font-bold ${product.stockQuantity === 0 ? 'text-red-500' : 'text-amber-500'}`}>
                                    {product.stockQuantity}
                                </span>
                                <span className="text-[10px] text-tertiary uppercase">{product.baseUnit || 'Cái'}</span>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

// ============ Dashboard Page ============
export const DashboardPage = () => {
  const { t, i18n } = useTranslation();



  // Fetch recent orders
  const { data: ordersData, isLoading: ordersLoading } = useAdminOrders({ pageIndex: PaginationDefaults.PAGE_INDEX, pageSize: PageSize.SMALL });
  const recentOrders = ordersData?.orders || [];

  const { data: statsResponse, isLoading: statsLoading, isError: statsError, refetch } = useQuery({
    queryKey: ['dashboard-stats'],
    queryFn: () => dashboardService.getStats(),
    staleTime: 30000,
  });

  const stats = statsResponse?.success && statsResponse?.data ? statsResponse.data : {
    totalRevenue: 0,
    revenueChange: 0,
    totalOrders: 0,
    ordersChange: 0,
    totalCustomers: 0,
    customersChange: 0,
    totalProducts: 0,
    pendingQuotes: 0
  };

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.dashboard"
        subtitle="admin.subtitles.dashboard"
        rightSection={
          <div className="flex items-center gap-3">
            <p className="text-secondary font-medium hidden sm:block">
              {new Date().toLocaleDateString(i18n.language, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
            <button
              onClick={() => refetch()}
              disabled={statsLoading}
              className="p-2 hover:bg-secondary rounded-lg transition-colors text-primary"
              title={t('common.refresh')}
            >
              <Loader2 size={20} className={statsLoading ? 'animate-spin' : ''} />
            </button>
          </div>
        }
      />

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {statsLoading ? (
           Array(4).fill(0).map((_, i) => (
             <div key={i} className="bg-primary rounded-xl p-6 h-32 animate-pulse" />
           ))
        ) : statsError ? (
           <div className="col-span-4 p-4 bg-red-50 text-red-500 rounded-xl">
             Failed to load dashboard statistics. Please try again.
           </div>
        ) : (
          <>
            <StatCard
              title={t('admin.stats.revenue')}
              value={formatCurrency(stats.totalRevenue)}
              change={stats.revenueChange}
              icon={DollarSign}
              color="bg-gradient-to-r from-green-500 to-emerald-500"
            />
            <StatCard
              title={t('admin.stats.orders')}
              value={stats.totalOrders.toLocaleString()}
              change={stats.ordersChange}
              icon={ShoppingBag}
              color="bg-gradient-to-r from-blue-500 to-cyan-500"
            />
            <StatCard
              title={t('admin.stats.customers')}
              value={stats.totalCustomers.toLocaleString()}
              change={stats.customersChange}
              icon={Users}
              color="bg-gradient-to-r from-purple-500 to-pink-500"
            />
            <StatCard
              title={t('admin.stats.products')}
              value={stats.totalProducts}
              icon={Package}
              color="bg-gradient-to-r from-orange-500 to-amber-500"
            />
          </>
        )}
      </div>

      {/* Charts & Tables Row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Revenue Chart */}
        <div className="lg:col-span-2 bg-primary rounded-xl p-6 shadow-sm border">
          <h2 className="font-bold mb-4">{t('admin.revenueChart')}</h2>
          <div className="h-64">
            <RevenueChart data={stats.revenueChart} />
          </div>
        </div>

        {/* Top Products & Low Stock Tabs or Stack */}
        <div className="space-y-6">
             {/* Top Products */}
            <div className="bg-primary rounded-xl p-6">
              <h2 className="font-bold mb-4">{t('admin.topProducts')}</h2>
              <div className="space-y-4">
                {(stats.topProducts || []).length === 0 ? (
                    <p className="text-secondary text-sm">{t('common.noData')}</p>
                ) : (stats.topProducts || []).map((product, index) => (
                  <div key={index} className="flex items-center gap-3">
                    <span className="w-8 h-8 rounded-lg bg-secondary flex items-center justify-center font-bold text-sm">
                      {index + 1}
                    </span>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium truncate">{product.name}</p>
                      <p className="text-sm text-tertiary">{product.sales} {t('admin.sold')}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Low Stock Widget */}
            <LowStockWidget />
        </div>
      </div>

      {/* Recent Orders & Pending Quotes */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Recent Orders */}
        <div className="bg-primary rounded-xl p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-bold">{t('admin.recentOrders')}</h2>
            <a href="/admin/orders" className="text-sm text-primary flex items-center gap-1 hover:underline">
              {t('common.viewAll')} <ArrowUpRight size={14} />
            </a>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="text-left text-sm text-tertiary border-b">
                  <th className="pb-3">{t('common.fields.orderCode')}</th>
                  <th className="pb-3">{t('common.fields.customer')}</th>
                  <th className="pb-3">{t('common.fields.total')}</th>
                  <th className="pb-3">{t('common.fields.status')}</th>
                </tr>
              </thead>
              <tbody>
                {ordersLoading ? (
                  <tr><td colSpan={4} className="py-8 text-center"><Loader2 className="animate-spin mx-auto" /></td></tr>
                ) : recentOrders.length === 0 ? (
                  <tr><td colSpan={4} className="py-4 text-center text-secondary">{t('common.noData')}</td></tr>
                ) : (recentOrders.map((order) => (
                  <tr key={order.code} className="border-b last:border-0">
                    <td className="py-3 font-medium">{order.code}</td>
                    <td className="py-3">{order.shippingName || order.userCode}</td>
                    <td className="py-3 text-error font-medium">{formatCurrency(order.finalAmount)}</td>
                    <td className="py-3">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium bg-${getStatusColor(order.status)}/20 text-${getStatusColor(order.status)}`}>
                        {t(getStatusText(order.status))}
                      </span>
                    </td>
                  </tr>
                )))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Pending Quotes (Note: Currently we only show count, list is dummy or requires real fetch) */}
        <div className="bg-primary rounded-xl p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-bold flex items-center gap-2">
              {t('admin.quoteRequests')}
              <span className="px-2 py-0.5 bg-error/20 text-error text-xs rounded-full">
                {stats.pendingQuotes} {t('admin.pending')}
              </span>
            </h2>
            <a href="/admin/quotes" className="text-sm text-primary flex items-center gap-1 hover:underline">
              {t('common.viewAll')} <ArrowUpRight size={14} />
            </a>
          </div>
          <p className="text-sm text-secondary">
             {t('common.messages.checkQuotesPage')}
          </p>
        </div>
      </div>
    </div>
  );
};

export default DashboardPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { FileText, Trash2, Edit, Image as ImageIcon } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { AdminPageHeader } from '@/components/admin';
import { DataTable } from '@/components/common';
import { formatDate } from '@/utils/format';
import { newsService, type NewsDto } from '@/services/newsService';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { PaginationDefaults } from '@/constants';
import { useToast } from '@/store';

export const NewsPage = () => {
  const { t } = useTranslation();
  const { success, error: toastError } = useToast();
  const queryClient = useQueryClient();

  // State
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingNews, setEditingNews] = useState<NewsDto | null>(null);
  const [newsToDelete, setNewsToDelete] = useState<NewsDto | null>(null);
  const [activeTab, setActiveTab ] = useState<'content' | 'seo'>('content');

  // Form State
  const [formData, setFormData] = useState({
    title: '',
    summary: '',
    content: '',
    thumbnail: '',
    author: '',
    isActive: true,
    metaTitle: '',
    metaDescription: '',
    metaKeywords: '',
    slug: ''
  });

  // Queries
  const { data: newsData, isLoading, isFetching } = useQuery({
    queryKey: ['admin-news', currentPage, pageSize, searchQuery],
    queryFn: () => newsService.search({
      pageIndex: currentPage,
      pageSize: pageSize,
      search: searchQuery
    }),
  });

  const newsItems = newsData?.data?.items || [];
  const totalPages = newsData?.data?.totalPages || 1;

  // Mutations
  const createMutation = useMutation({
    mutationFn: (data: any) => newsService.create(data),
    onSuccess: () => {
      success(t('messages.createSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-news'] });
      setIsModalOpen(false);
      resetForm();
    },
    onError: (err: any) => toastError(err.message || t('messages.createError'))
  });

  const updateMutation = useMutation({
    mutationFn: ({ code, data }: { code: string, data: any }) => newsService.update(code, data),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-news'] });
      setIsModalOpen(false);
      resetForm();
    },
    onError: (err: any) => toastError(err.message || t('messages.updateError'))
  });

  const deleteMutation = useMutation({
    mutationFn: (code: string) => newsService.delete(code),
    onSuccess: () => {
      success(t('messages.deleteSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-news'] });
      setNewsToDelete(null);
    },
    onError: () => toastError(t('messages.deleteError'))
  });

  // Handlers
  const resetForm = () => {
    setFormData({
      title: '',
      summary: '',
      content: '',
      thumbnail: '',
      author: '',
      isActive: true,
      metaTitle: '',
      metaDescription: '',
      metaKeywords: '',
      slug: ''
    });
    setEditingNews(null);
    setActiveTab('content');
  };

  const handleEdit = (item: NewsDto) => {
    setEditingNews(item);
    setFormData({
      title: item.title,
      summary: item.summary || '',
      content: item.content || '',
      thumbnail: item.thumbnail || '',
      author: item.author || '',
      isActive: item.isActive,
      metaTitle: item.metaTitle || '',
      metaDescription: item.metaDescription || '',
      metaKeywords: item.metaKeywords || '',
      slug: item.slug || ''
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingNews) {
      updateMutation.mutate({ code: editingNews.code, data: formData });
    } else {
      createMutation.mutate(formData);
    }
  };

  // Columns
  const columns = [
    {
      id: 'thumbnail',
      header: '',
      accessor: (row: NewsDto) => (
        <div className="w-12 h-12 rounded bg-tertiary flex items-center justify-center overflow-hidden">
          {row.thumbnail ? (
            <img src={row.thumbnail} alt={row.title} className="w-full h-full object-cover" />
          ) : (
            <ImageIcon size={20} className="text-tertiary" />
          )}
        </div>
      ),
      className: 'w-16'
    },
    {
      id: 'title',
      header: t('common.fields.title'),
      accessor: (row: NewsDto) => (
        <div className="max-w-[300px]">
          <p className="font-medium truncate">{row.title}</p>
          <p className="text-xs text-tertiary truncate">{row.summary}</p>
        </div>
      )
    },
    {
       id: 'author',
       header: t('common.fields.author'),
       accessor: (row: NewsDto) => row.author || t('common.none')
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (row: NewsDto) => (
        <Badge color={row.isActive ? 'success' : 'error'} size="sm">
          {row.isActive ? t('admin.status.published') : t('admin.status.draft')}
        </Badge>
      ),
      className: 'text-center'
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (row: NewsDto) => <span className="text-secondary text-sm">{formatDate(row.publishedAt || row.createdAt)}</span>
    }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.news"
        subtitle="admin.subtitles.news"
      />

      <DataTable
        columns={columns}
        data={newsItems}
        isLoading={isLoading || isFetching}
        keyField="code"
        
        currentPage={currentPage}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setCurrentPage}
        onPageSizeChange={setPageSize}

        // Toolbar Actions
        onAdd={() => { resetForm(); setIsModalOpen(true); }}
        onRefresh={() => queryClient.invalidateQueries({ queryKey: ['admin-news'] })}
        searchPlaceholder={t('common.placeholders.search')}
        onSearch={setSearchQuery} // Wire up search to State

        renderRowActions={(row) => (
          <div className="flex items-center gap-1">
            <button
              className="p-1.5 hover:bg-primary/10 rounded text-primary"
              title={t('common.actions.edit')}
              onClick={() => handleEdit(row)}
            >
              <Edit size={18} />
            </button>
            <button
              className="p-1.5 hover:bg-error/10 rounded text-error"
              title={t('common.actions.delete')}
              onClick={() => setNewsToDelete(row)}
            >
              <Trash2 size={18} />
            </button>
          </div>
        )}
      />

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={editingNews ? t('admin.news.edit') : t('admin.news.add')}
        size="xl"
        footer={
          <div className="flex justify-end gap-2">
             <Button variant="outline" onClick={() => setIsModalOpen(false)}>{t('common.cancel')}</Button>
             <Button onClick={handleSubmit} isLoading={createMutation.isPending || updateMutation.isPending}>{t('common.save')}</Button>
          </div>
        }
      >
        <div className="space-y-4">
           {/* Tabs */}
           <div className="flex border-b border-tertiary">
              <button 
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${activeTab === 'content' ? 'border-primary text-primary' : 'border-transparent text-tertiary'}`}
                onClick={() => setActiveTab('content')}
              >
                {t('admin.news.contentTab')}
              </button>
              <button 
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${activeTab === 'seo' ? 'border-primary text-primary' : 'border-transparent text-tertiary'}`}
                onClick={() => setActiveTab('seo')}
              >
                {t('admin.news.seoTab')}
              </button>
           </div>

           <form onSubmit={handleSubmit} className="space-y-4">
             {activeTab === 'content' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">{t('common.fields.title')} <span className="text-error">*</span></label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.title}
                      onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                      required
                    />
                  </div>
                  
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('common.fields.author')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.author}
                      onChange={(e) => setFormData({ ...formData, author: e.target.value })}
                    />
                  </div>

                  <div>
                     <label className="block text-sm font-medium mb-1">{t('admin.news.thumbnailUrl')}</label>
                     <input
                        type="text"
                        className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                        value={formData.thumbnail}
                        onChange={(e) => setFormData({ ...formData, thumbnail: e.target.value })}
                        placeholder="https://..."
                     />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">{t('admin.news.summary')}</label>
                    <textarea
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 h-20"
                      value={formData.summary}
                      onChange={(e) => setFormData({ ...formData, summary: e.target.value })}
                    />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">{t('admin.news.content')} <span className="text-error">*</span></label>
                    <textarea
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 h-64 font-mono text-sm"
                      value={formData.content}
                      onChange={(e) => setFormData({ ...formData, content: e.target.value })}
                      required
                    />
                  </div>

                  <div className="flex items-center gap-2">
                    <input
                      type="checkbox"
                      id="isActive"
                      className="w-4 h-4 rounded border-tertiary"
                      checked={formData.isActive}
                      onChange={(e) => setFormData({ ...formData, isActive: e.target.checked })}
                    />
                    <label htmlFor="isActive" className="text-sm font-medium cursor-pointer">{t('admin.status.published')}</label>
                  </div>
                </div>
             ) : (
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.slug')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.slug}
                      onChange={(e) => setFormData({ ...formData, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })}
                      placeholder="post-title-slug"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.metaTitle')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.metaTitle}
                      onChange={(e) => setFormData({ ...formData, metaTitle: e.target.value })}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.metaDescription')}</label>
                    <textarea
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 h-24"
                      value={formData.metaDescription}
                      onChange={(e) => setFormData({ ...formData, metaDescription: e.target.value })}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.metaKeywords')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.metaKeywords}
                      onChange={(e) => setFormData({ ...formData, metaKeywords: e.target.value })}
                      placeholder="news, shop, organic"
                    />
                  </div>
                </div>
             )}
           </form>
        </div>
      </Modal>

      <ConfirmDialog
        isOpen={!!newsToDelete}
        onClose={() => setNewsToDelete(null)}
        onConfirm={() => newsToDelete && deleteMutation.mutate(newsToDelete.code)}
        title={t('common.actions.delete')}
        message={t('messages.confirmDelete')}
        variant="danger"
        isLoading={deleteMutation.isPending}
      />
    </div>
  );
};

export default NewsPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { ShoppingCart, FileText, Truck, Eye, Trash2, Package, ClipboardList, ChevronUp, ChevronDown, Loader2, Download, Check, X, Printer } from 'lucide-react';
