              onCancel={closeForm}
              isLoading={createMutation.isPending || updateMutation.isPending}
            />
          </Modal>

      {/* View Modal */}
      <Modal
        isOpen={!!viewingProduct}
        onClose={() => setViewingProduct(null)}
        title={t('common.actions.view') + ' ' + t('common.modules.products')}
        size="lg"
      >
        {viewingProduct && (
          <div className="space-y-6">
            <div className="flex items-start gap-6">
              <img
                src={getSafeImageUrl(viewingProduct.images?.[0] || viewingProduct.productImages?.[0]) || 'https://placehold.co/200'}
                alt={viewingProduct.name}
                className="w-32 h-32 rounded-lg object-cover border bg-white"
              />
              <div className="flex-1">
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">{viewingProduct.name}</h2>
                <div className="flex items-center gap-2 mt-2">
                  <Badge color="info">{viewingProduct.brand || t('common.fields.noBrand')}</Badge>
                  <Badge color="secondary">{viewingProduct.categoryName || '-'}</Badge>
                  <Badge color={viewingProduct.isActive !== false ? 'success' : 'error'}>
                    {viewingProduct.isActive !== false ? t('common.status.active') : t('common.status.inactive')}
                  </Badge>
                </div>
                <div className="mt-4 flex flex-col gap-1">
                  <div className="flex items-baseline gap-2">
                    <span className="text-sm text-slate-500 w-20">{t('common.fields.price')}:</span>
                    <span className="text-2xl font-bold text-rose-600">{formatCurrency(viewingProduct.price)}</span>
                  </div>
                  {(viewingProduct.wholesalePrice || 0) > 0 && (
                    <div className="flex items-baseline gap-2">
                      <span className="text-sm text-slate-500 w-20">{t('common.fields.wholesalePrice')}:</span>
                      <span className="text-lg font-semibold text-blue-600">{formatCurrency(viewingProduct.wholesalePrice || 0)}</span>
                    </div>
                  )}
                  {(viewingProduct.costPrice || 0) > 0 && (
                    <div className="flex items-baseline gap-2">
                      <span className="text-sm text-slate-500 w-20">{t('common.fields.costPrice')}:</span>
                      <span className="text-md font-medium text-slate-600">{formatCurrency(viewingProduct.costPrice || 0)}</span>
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <h3 className="font-semibold text-slate-800 dark:text-white border-b pb-2">{t('common.fields.info')}</h3>
                <div className="space-y-2 text-sm">
                  <div className="flex justify-between py-1 border-b border-dashed">
                    <span className="text-slate-500">{t('common.fields.stock')}</span>
                    <span className="font-medium">{viewingProduct.stockQuantity}</span>
                  </div>
                  {viewingProduct.material && (
                    <div className="flex justify-between py-1 border-b border-dashed">
                      <span className="text-slate-500">{t('common.fields.material')}</span>
                      <span className="font-medium">{viewingProduct.material}</span>
                    </div>
                  )}
                  {viewingProduct.size && (
                    <div className="flex justify-between py-1 border-b border-dashed">
                      <span className="text-slate-500">{t('common.fields.size')}</span>
                      <span className="font-medium">{viewingProduct.size}</span>
                    </div>
                  )}
                  {viewingProduct.color && (
                    <div className="flex justify-between py-1 border-b border-dashed">
                      <span className="text-slate-500">{t('common.fields.color')}</span>
                      <span className="font-medium">{viewingProduct.color}</span>
                    </div>
                  )}
                </div>
              </div>

              <div className="space-y-4">
                <h3 className="font-semibold text-slate-800 dark:text-white border-b pb-2">{t('common.fields.specs')}</h3>
                <div className="space-y-2 text-sm">
                  {viewingProduct.details?.map((detail, idx) => (
                    <div key={idx} className="flex justify-between py-1 border-b border-dashed">
                      <span className="text-slate-500">{detail.specName}</span>
                      <span className="font-medium">{detail.specValue}</span>
                    </div>
                  ))}
                  
                  {viewingProduct.voltage && (
                    <div className="flex justify-between py-1 border-b border-dashed">
                      <span className="text-slate-500">{t('common.fields.voltage')}</span>
                      <span className="font-medium">{viewingProduct.voltage}</span>
                    </div>
                  )}
                  {viewingProduct.power && (
                    <div className="flex justify-between py-1 border-b border-dashed">
                      <span className="text-slate-500">{t('common.fields.power')}</span>
                      <span className="font-medium">{viewingProduct.power}</span>
                    </div>
                  )}
                </div>
              </div>
            </div>

            {viewingProduct.description && (
              <div>
                <h3 className="font-semibold text-slate-800 dark:text-white border-b pb-2 mb-2">{t('common.fields.description')}</h3>
                <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed max-h-40 overflow-y-auto">
                  {viewingProduct.description}
                </p>
              </div>
            )}

            <div className="flex justify-end pt-4">
              <Button onClick={() => setViewingProduct(null)}>
                {t('common.actions.close')}
              </Button>
            </div>
          </div>
        )}
      </Modal>

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!productToDelete || showBulkConfirm}
        onClose={handleCancelDelete}
        onConfirm={handleDelete}
        title={t('common.actions.delete')}
        message={t('common.confirmDelete', { count: selectedToDelete.length > 0 ? selectedToDelete.length : 1 })}
        confirmText={t('common.actions.delete')}
        variant="danger"
        isLoading={isDeleting}
      />
    </div>
  );
};

export default ProductsPage;

import { useState, useRef, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Plus, Edit2, Trash2, Eye, Tag, Clock } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog, TableActions } from '@/components/ui';
import { formatCurrency, formatDate } from '@/utils/format';
import { PromotionForm } from './forms/PromotionForm';
import {
  useEntityManager,
} from '@/hooks'; // We will assume usePromotions hook logic is handled via useEntityManager or we need a hook? 
// useEntityManager requires a service. We have promotionService.
// We also need a fetch hook for data. `usePromotions` doesn't specific exist as a hook file yet? 
// Wait, I didn't create `usePromotions.ts`. I should use `useQuery` or `useEntityManager`'s integrated hook if it has one?
// `useEntityManager` typically handles mutations. Data fetching is usually `useQuery`.
// I will create a simple `usePromotions` hook in this file or use `useQuery` directly for "DRY" if I don't want a separate file.
// But following pattern, `useProducts` exists. I should probably have `usePromotions`.
// However, to keep it simple and within this file ("OOP encapsulate?"), I can use `useQuery`.
// Let's use `useQuery` from `@tanstack/react-query` directly here or import a standard hook.
// I'll assume I need to fetch data.

import { promotionService, Promotion, CreatePromotionRequest, UpdatePromotionRequest, PromotionFilter } from '@/services/promotionService';
import { useQuery } from '@tanstack/react-query';
import { DataTable, type DataTableColumn } from '@/components/common/DataTable';
import { ImportModal } from '@/components/common/ImportModal';
import { PageSize, PaginationDefaults, SortDirection } from '@/constants';
import { useToast } from '@/store';
import { AdminPageHeader } from '@/components/admin';

// We need a hook to fetch promotions compatible with DataTable
const usePromotions = (params: PromotionFilter) => {
  return useQuery({
    queryKey: ['promotions', params],
    queryFn: () => promotionService.getAll(params),
    placeholderData: (previousData) => previousData,
  });
};

export const PromotionsPage = () => {
  const { t } = useTranslation();
  const toast = useToast();

  // State
  const [currentPage, setCurrentPage] = useState<number>(PaginationDefaults.PAGE_INDEX);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [advancedFilters, setAdvancedFilters] = useState<Record<string, string>>({});
  const [pageSize, setPageSize] = useState<number>(PaginationDefaults.PAGE_SIZE);

  // Sorting
  const [sortField, setSortField] = useState<string>('createdAt');
  const [sortDir, setSortDir] = useState<SortDirection>(SortDirection.DESC);

  // Import
  const [isImportModalOpen, setIsImportModalOpen] = useState(false);
  const handleImportPromotion = async (file: File) => {
    try {
        await promotionService.import(file);
        toast.success(t('common.importSuccess') || 'Import successful');
        refetch();
    } catch (error) {
        toast.error(t('common.importError') || 'Import failed');
        throw error;
    }
  };

  // Fetch API
  const {
    data: promotionsData,
    isLoading,
    isFetching,
    isError,
    error,
    refetch,
  } = usePromotions({
    pageIndex: currentPage,
    pageSize,
    search: searchQuery || undefined,
    sortBy: sortField,
    sortDesc: sortDir === SortDirection.DESC,
    ...advancedFilters
  });

  const promotions: Promotion[] = promotionsData?.data?.items || [];
  const totalItems: number = promotionsData?.data?.totalItems || 0;
  const totalPages: number = Math.ceil(totalItems / pageSize);

  // Mutations and State via useEntityManager
  const {
    isFormOpen,
    editingItem: editingPromotion,
    itemToDelete: promotionToDelete,
    isLoading: isSubmitting,
    isDeleting,
    openCreate,
    openEdit,
    closeForm,
    confirmDelete,
    cancelDelete,
    createMutation,
    updateMutation,
    deleteMutation
  } = useEntityManager<Promotion, CreatePromotionRequest, UpdatePromotionRequest>({
    service: promotionService,
    queryKey: ['promotions'],
  });

  // Selection
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const selectedToDelete = promotions.filter(p => selectedIds.has(p.code));
  const [showBulkConfirm, setShowBulkConfirm] = useState(false);

  // View State
  const [viewingPromotion, setViewingPromotion] = useState<Promotion | null>(null);

  // Column Definitions
  const columns: DataTableColumn<Promotion>[] = [
    {
      id: 'code',
      header: t('common.fields.code'),
      accessor: (p) => (
        <div className="flex flex-col">
          <span className="font-bold text-primary">{p.code}</span>
          <span className="text-xs text-slate-500">{p.name}</span>
        </div>
      ),
      sortable: true
    },
    {
      id: 'type',
      header: t('common.fields.type'),
      accessor: (p) => (
        <Badge variant="outline" className="flex items-center gap-1 w-fit">
          {p.productCodes && p.productCodes.length > 0 ? (
            <><Clock size={12} /> Flash Sale</>
          ) : (
            <><Tag size={12} /> Voucher</>
          )}
        </Badge>
      )
    },
    {
      id: 'discount',
      header: t('common.fields.discount'),
      accessor: (p) => (
        <div className="font-semibold text-rose-600">
          {p.discountType === 'PERCENTAGE' ? `${p.discountValue}%` : formatCurrency(p.discountValue)}
        </div>
      ),
      sortable: true
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (p) => (
        <div className="text-xs flex flex-col">
          <span>{formatDate(p.startDate)}</span>
          <span className="text-slate-400">to</span>
          <span>{formatDate(p.endDate)}</span>
        </div>
      )
    },
    {
      id: 'usage',
      header: t('common.fields.usageLimit'),
      accessor: (p) => p.usageLimit ?? '∞',
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (p) => (
        <Badge
          color={p.isActive ? 'success' : 'error'}
          size="sm"
          variant="outline"
        >
          {p.isActive ? t('common.status.active') : t('common.status.inactive')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },

  ];

  // Handler Wrappers
  const handleCreate = async (data: any) => {
    // Sanitizing nulls to undefined to match CreatePromotionRequest
    const cleanData: CreatePromotionRequest = {
      ...data,
      minOrderAmount: data.minOrderAmount ?? undefined,
      maxDiscountAmount: data.maxDiscountAmount ?? undefined,
      usageLimit: data.usageLimit ?? undefined,
      productCodes: data.productCodes ?? undefined,
      startDate: data.startDate instanceof Date ? data.startDate.toISOString() : data.startDate,
      endDate: data.endDate instanceof Date ? data.endDate.toISOString() : data.endDate,
    };
    await createMutation.mutateAsync(cleanData);
  };

  const handleUpdate = async (data: any) => {
    if (!editingPromotion) return;
    const cleanData: UpdatePromotionRequest = {
      ...data,
      minOrderAmount: data.minOrderAmount ?? undefined,
      maxDiscountAmount: data.maxDiscountAmount ?? undefined,
      usageLimit: data.usageLimit ?? undefined,
      productCodes: data.productCodes ?? undefined,
      startDate: data.startDate instanceof Date ? data.startDate.toISOString() : data.startDate,
      endDate: data.endDate instanceof Date ? data.endDate.toISOString() : data.endDate,
    };
    await updateMutation.mutateAsync({
      id: editingPromotion.code,
      data: cleanData
    });
  };

  const handleDelete = async () => {
    if (promotionToDelete) {
      deleteMutation.mutate(promotionToDelete.code);
    } else if (selectedToDelete.length > 0) {
      try {
        await Promise.all(selectedToDelete.map(item => deleteMutation.mutateAsync(item.code)));
        setSelectedIds(new Set());
        setShowBulkConfirm(false);
        toast.success(t('common.deleteSuccess'));
      } catch (err) { }
    }
  };

  const handleReset = () => {
    setAdvancedFilters({});
    setCurrentPage(PaginationDefaults.PAGE_INDEX);
    setSearchQuery('');
    setSortField('createdAt');
    setSortDir(SortDirection.DESC);

  };

      const promotionInitialData = useMemo(() => editingPromotion ? {
        ...editingPromotion,
        startDate: new Date(editingPromotion.startDate),
        endDate: new Date(editingPromotion.endDate),
      } : undefined, [editingPromotion]);

      return (
        <div className="space-y-6">
          <AdminPageHeader
            title="promotions.title"
            subtitle="promotions.subtitle"
          />

          <DataTable
            columns={columns}
            data={promotions}
            keyField="code"
            isLoading={isLoading || isFetching}
            isFetching={isFetching}
            error={isError ? (error as Error) : null}
            onAdd={() => openCreate()}
            onRefresh={() => refetch()}
            onImport={handleImportPromotion}
            importTemplateUrl="/templates/promotions_template.xlsx" 


            currentPage={currentPage}
            totalPages={totalPages}
            totalItems={totalItems}
            pageSize={pageSize}
            onPageChange={setCurrentPage}
            onPageSizeChange={(size) => {
              setPageSize(size);
              setCurrentPage(PaginationDefaults.PAGE_INDEX);
            }}

            externalSortField={sortField}
            externalSortDir={sortDir}
            onExternalSort={(f, d) => { setSortField(f); setSortDir(d as any); }}
            
            onEdit={openEdit}
            onDelete={confirmDelete}
            onView={setViewingPromotion}

            selectedIds={selectedIds}
            onSelectionChange={setSelectedIds}
            onBulkDelete={() => setShowBulkConfirm(true)}

            // Search
            onReset={handleReset}
            onAdvancedSearch={(filters) => {
              setAdvancedFilters(filters);
              setCurrentPage(PaginationDefaults.PAGE_INDEX);
            }}
            advancedFilterDefs={[
              { id: 'search', label: t('common.search'), type: 'text', placeholder: t('common.placeholders.search') },
              { id: 'type', label: t('common.fields.type'), type: 'select', options: [{ value: 'voucher', label: t('admin.types.voucher') }, { value: 'flash_sale', label: t('shared.flashSale') }] },
              { id: 'isActive', label: t('common.fields.status'), type: 'select', options: [{ value: 'true', label: t('common.status.active') }, { value: 'false', label: t('common.status.inactive') }] }
            ]}
          />

          <Modal
            isOpen={isFormOpen}
            onClose={closeForm}
            title={editingPromotion ? t('admin.actions.edit') : t('admin.actions.create')}
            size="2xl"
          >
            <PromotionForm
              initialData={promotionInitialData}
              onSubmit={editingPromotion ? handleUpdate : handleCreate}
              onCancel={closeForm}
              isLoading={isSubmitting}
            />
          </Modal>

      <ConfirmDialog
        isOpen={!!promotionToDelete || showBulkConfirm}
        onClose={() => { cancelDelete(); setShowBulkConfirm(false); }}
        onConfirm={handleDelete}
        title={t('admin.actions.delete')}
        message={t('common.confirmDelete', { count: showBulkConfirm ? selectedToDelete.length : 1 })}
        confirmText={t('common.delete')}
        variant="danger"
        isLoading={isDeleting}
      />
    </div>
  );
};

export default PromotionsPage;

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Search, MessageSquare, DollarSign, Check, Eye, Trash2, ClipboardList, FileText, X, Printer } from 'lucide-react';
import { Button, Badge, Modal, Input } from '@/components/ui';
import { formatCurrency, formatDate } from '@/utils/format';
import { quoteService } from '@/services/quoteService';
import { orderService } from '@/services/orderService';
import type { QuoteRequest } from '@/types';
import { AdminPageHeader } from '@/components/admin';

import { useToast } from '@/store/toastStore';
import { StatsCards } from '@/components/admin/StatsCards';
import { useQuery } from '@tanstack/react-query';

export const QuotesPage = () => {
  const { t } = useTranslation();
  const { success, error } = useToast();

  const [quotes, setQuotes] = useState<QuoteRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [selectedQuote, setSelectedQuote] = useState<QuoteRequest | null>(null);
  const [showQuoteModal, setShowQuoteModal] = useState(false);
  const [quotePrice, setQuotePrice] = useState('');

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['quote-stats'],
      queryFn: () => quoteService.getStats(),
      staleTime: 60000,
  });

  // Fetch quotes
  useEffect(() => {
    fetchQuotes();
  }, []);

  const fetchQuotes = async () => {
    try {
      const res = await quoteService.getAll();
      if (res.success && res.data) {
        const mappedQuotes: QuoteRequest[] = (res.data.items || []).map((dto) => ({
          code: dto.code,
          customer: {
            name: dto.customerName || dto.userName || 'Unknown Customer',
            email: dto.customerEmail || '',
            phone: dto.customerPhone || ''
          },
          items: dto.items.map(i => ({
              code: i.code,
              productCode: i.productCode,
              productName: i.productName,
              productImage: i.productImage || 'https://placehold.co/100',
              quantity: i.quantity,
              unitName: i.unitName,
              approvedPrice: i.approvedPrice,
              requestPrice: i.requestPrice
          })),
          note: dto.note,
          status: dto.status as any,
          totalAmount: dto.totalAmount,
          createdAt: dto.createdAt,
        }));
        setQuotes(mappedQuotes);
      }
    } catch (error) {
      console.error('Failed to fetch quotes', error);
    } finally {
      setLoading(false);
    }
  };

  const filteredQuotes = quotes.filter((quote) => {
    // Search in customer name or ANY product name
    const matchesSearch =
      quote.customer.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      quote.items.some(i => i.productName.toLowerCase().includes(searchQuery.toLowerCase()));
      
    const matchesStatus = statusFilter === 'all' || quote.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const handleQuote = (quote: QuoteRequest) => {
    setSelectedQuote(quote);
    setShowQuoteModal(true);
    // For single item backwards compat or simple quote, prompt for Total Amount
    setQuotePrice(quote.totalAmount ? quote.totalAmount.toString() : '');
  };

  const handleSubmitQuote = async () => {
    if (!selectedQuote || !quotePrice) return;

    try {
      // Logic Update: Distribute price or set Total? 
      // Backend UpdateQuoteDto has TotalAmount.
      const res = await quoteService.update(selectedQuote.code, {
        status: 'quoted',
        totalAmount: parseFloat(quotePrice) // Using 'quotedPrice' field as TotalAmount shim if needed, or update service
      } as any);

      if (res.success) {
        success('Báo giá thành công');
        setShowQuoteModal(false);
        setQuotePrice('');
        fetchQuotes(); // Refresh
      }
    } catch (err) {
      error('Lỗi khi cập nhật báo giá');
    }

  };

  // Convert to Order Logic
  const [showConvertModal, setShowConvertModal] = useState(false);
  const [convertData, setConvertData] = useState<{
      fullName: string;
      email: string;
      phone: string;
      address: string;
      city: string;
      district: string;
      ward: string;
      note: string;
      paymentMethod: string;
  }>({
      fullName: '',
      email: '',
      phone: '',
      address: '',
      city: 'Chưa cập nhật', // Default or ask user
      district: 'Chưa cập nhật',
      ward: 'Chưa cập nhật',
      note: '',
      paymentMethod: 'COD'
  });

  const handleCloseDeal = (quote: QuoteRequest) => {
      setSelectedQuote(quote);
      setConvertData({
          fullName: quote.customer.name,
          email: quote.customer.email,
          phone: quote.customer.phone,
          address: '', // Quote doesn't have address usually
          city: 'Hồ Chí Minh',
          district: '',
          ward: '',
          note: `Đơn hàng từ báo giá #${quote.code}. Ghi chú báo giá: ${quote.note || 'Không có'}`,
          paymentMethod: 'COD'
      });
      setShowConvertModal(true);
  };

  const submitConversion = async () => {
      if (!selectedQuote) return;

      try {
          const res = await orderService.create({
              ...convertData,
              items: selectedQuote.items.map(item => ({
                  productCode: item.productCode,
                  quantity: item.quantity,
                  userPrice: item.approvedPrice || (selectedQuote.totalAmount ? selectedQuote.totalAmount / selectedQuote.items.length : 0) // Fallback logic
              }))
          });

          if (res.success) {
               // Update quote status to closed
               await quoteService.update(selectedQuote.code, { status: 'closed' });
               success(t('messages.orderCreatedFailure') ? t('messages.orderCreatedSuccess') : 'Tạo đơn hàng thành công');
               setShowConvertModal(false);
               fetchQuotes();
          } else {
              error(res.message || 'Tạo đơn hàng thất bại');
          }
      } catch (err) {
          error('Lỗi khi tạo đơn hàng');
          console.error(err);
      }
  };

  if (loading) return <div>Loading...</div>;

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.quotes"
        subtitle="admin.subtitles.quotes"
        rightSection={
          <div className="flex items-center gap-2">
            <Badge color="warning">{quotes.filter((q) => q.status === 'pending').length} {t('admin.status.pending')}</Badge>
          </div>
        }
      />

      <StatsCards stats={[
        {
            label: t('admin.stats.totalOrders'),
            value: statsData?.total || 0,
            icon: <ClipboardList size={24} />,
            color: 'blue',
            loading: isStatsLoading
        },
        {
            label: t('admin.stats.pending'),
            value: statsData?.pending || 0,
            icon: <FileText size={24} />,
            color: 'amber',
            loading: isStatsLoading
        },
        {
            label: t('admin.stats.processedQuotes'),
             value: statsData?.processed || 0,
            icon: <Check size={24} />,
            color: 'emerald',
            loading: isStatsLoading
        }
    ]} />

      {/* Filters */}
      <div className="bg-primary rounded-xl p-4">
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1 relative">
            <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
            <input
              type="text"
              placeholder={t('common.placeholders.search')}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border rounded-lg focus:outline-none focus:border-primary"
            />
          </div>
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="px-4 py-2 border rounded-lg focus:outline-none focus:border-primary"
          >
            <option value="all">{t('admin.filters.allStatus')}</option>
            <option value="pending">{t('admin.status.pending')}</option>
            <option value="quoted">{t('admin.status.quoted')}</option>
            <option value="closed">{t('admin.status.closed')}</option>
            <option value="cancelled">{t('admin.status.cancelled')}</option>
          </select>
        </div>
      </div>

      {/* Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredQuotes.map((quote) => {
            const firstItem = quote.items[0];
            const otherItemsCount = quote.items.length - 1;
            
            return (
          <div key={quote.code} className="bg-primary rounded-xl p-5">
            {/* Status */}
            <div className="flex items-center justify-between mb-4">
              <Badge
                color={
                  quote.status === 'pending'
                    ? 'warning'
                    : quote.status === 'quoted'
                      ? 'info'
                      : quote.status === 'closed'
                        ? 'success'
                        : 'error'
                }
              >
                {t(`admin.status.${quote.status}`) || quote.status}
              </Badge>
              <span className="text-xs text-tertiary">{formatDate(quote.createdAt)}</span>
            </div>

            {/* Product (First Item + Count) */}
            {firstItem ? (
                <div className="flex gap-3 mb-4">
                <img
                    src={firstItem.productImage}
                    alt={firstItem.productName}
                    className="w-16 h-16 object-cover rounded-lg"
                />
                <div>
                    <p className="font-semibold line-clamp-2">{firstItem.productName}</p>
                    <p className="text-sm text-tertiary">{t('common.fields.quantity')}: {firstItem.quantity}</p>
                    {otherItemsCount > 0 && (
                        <p className="text-xs text-blue-600 font-medium">+{otherItemsCount} {t('common.products').toLowerCase()}</p>
                    )}
                </div>
                </div>
            ) : (
                <div className="mb-4 text-gray-400 italic">No items</div>
            )}

            {/* Customer */}
            <div className="mb-4 p-3 bg-secondary rounded-lg">
              <p className="font-medium">{quote.customer.name}</p>
              <p className="text-sm text-tertiary">{quote.customer.phone}</p>
              <p className="text-sm text-tertiary">{quote.customer.email}</p>
            </div>

            {/* Note */}
            {quote.note && (
              <div className="mb-4">
                <p className="text-sm text-secondary">
                  <MessageSquare size={14} className="inline mr-1" />
                  {quote.note}
                </p>
              </div>
            )}

            {/* Quoted Price */}
            {quote.totalAmount !== undefined && quote.totalAmount > 0 && (
              <div className="mb-4 p-3 bg-success/10 rounded-lg text-center">
                <p className="text-sm text-secondary">{t('common.fields.quotedPrice')}</p>
                <p className="text-xl font-bold text-success">{formatCurrency(quote.totalAmount)}</p>
              </div>
            )}

            {/* Actions */}
            <div className="flex gap-2">
              {quote.status === 'pending' && (
                <>
                  <Button size="sm" fullWidth onClick={() => handleQuote(quote)} leftIcon={<DollarSign size={16} />}>
                    {t('admin.actions.quote')}
                  </Button>
                  <Button size="sm" variant="ghost" className="text-error">
                    <X size={16} />
                  </Button>
                </>
              )}
              {quote.status === 'quoted' && (
                <>
                  <Button size="sm" fullWidth variant="outline" onClick={() => handleQuote(quote)}>
                    {t('admin.actions.updatePrice')}
                  </Button>
                  <Button size="sm" leftIcon={<Check size={16} />} onClick={() => handleCloseDeal(quote)}>
                    {t('admin.actions.closeDeal')}
                  </Button>
                </>
              )}
              {(quote.status === 'closed' || quote.status === 'cancelled') && (
                <Button size="sm" fullWidth variant="outline" leftIcon={<Eye size={16} />}>
                  {t('admin.actions.view')}
                </Button>
              )}
            </div>
          </div>
        );
        })}
      </div>

      {/* Quote Modal */}
      <Modal
        isOpen={showQuoteModal}
        onClose={() => {
          setShowQuoteModal(false);
          setQuotePrice('');
        }}
        title={t('admin.actions.quote')}
        size="sm"
        footer={
          <div className="flex gap-3 justify-end">
            <Button variant="outline" onClick={() => setShowQuoteModal(false)}>
              {t('admin.actions.cancel')}
            </Button>
            <Button
              onClick={handleSubmitQuote}
            >
              {t('admin.actions.sendQuote')}
            </Button>
          </div>
        }
      >
        {selectedQuote && (
          <div className="space-y-4">
            {/* List all items in modal */}
            <div className="max-h-60 overflow-y-auto space-y-3 pr-2">
                {selectedQuote.items.map((item, idx) => (
                    <div key={idx} className="flex gap-3 border-b pb-2">
                    <img
                        src={item.productImage}
                        alt={item.productName}
                        className="w-12 h-12 object-cover rounded-lg"
                    />
                    <div>
                        <p className="font-semibold text-sm">{item.productName}</p>
                        <p className="text-sm text-tertiary">Qty: {item.quantity}</p>
                    </div>
                    </div>
                ))}
            </div>

            <Input
              label={t('common.fields.price') + ' (VNĐ) - Total'}
              type="number"
              placeholder={t('common.placeholders.enterPrice')}
              value={quotePrice}
              onChange={(e) => setQuotePrice(e.target.value)}
              leftIcon={<DollarSign size={18} />}
            />

            <div>
              <label className="block text-sm font-medium mb-2">{t('common.fields.note')}</label>
              <textarea
                placeholder={t('common.placeholders.enterNote')}
                rows={3}
                className="w-full px-4 py-2 border rounded-lg focus:outline-none focus:border-primary resize-none"
              />
            </div>
          </div>
        )}
      </Modal>

      {/* Convert to Order Modal */}
      <Modal
        isOpen={showConvertModal}
        onClose={() => setShowConvertModal(false)}
        title={t('admin.actions.createOrder') || "Tạo đơn hàng"}
        size="lg"
        footer={
            <div className="flex gap-3 justify-end">
                <Button variant="outline" onClick={() => setShowConvertModal(false)}>
                    {t('admin.actions.cancel')}
                </Button>
                <Button onClick={submitConversion} leftIcon={<Check size={18} />}>
                    {t('admin.actions.confirmOrder') || "Xác nhận tạo đơn"}
                </Button>
            </div>
        }
      >
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-4">
                <h3 className="font-bold text-lg border-b pb-2">Thông tin khách hàng</h3>
                <Input
                    label={t('common.fields.fullName')}
                    value={convertData.fullName}
                    onChange={(e) => setConvertData({ ...convertData, fullName: e.target.value })}
                />
                <Input
                    label={t('common.fields.phone')}
                    value={convertData.phone}
                    onChange={(e) => setConvertData({ ...convertData, phone: e.target.value })}
                />
                <Input
                    label={t('common.fields.email')}
                    value={convertData.email}
                    onChange={(e) => setConvertData({ ...convertData, email: e.target.value })}
                />
            </div>
            <div className="space-y-4">
                <h3 className="font-bold text-lg border-b pb-2">Địa chỉ giao hàng</h3>
                <Input
                    label={t('common.fields.address')}
                    placeholder="Số nhà, tên đường"
                    value={convertData.address}
                    onChange={(e) => setConvertData({ ...convertData, address: e.target.value })}
                />
                <div className="grid grid-cols-2 gap-2">
                    <Input
                        label={t('common.fields.city')}
                        value={convertData.city}
                        onChange={(e) => setConvertData({ ...convertData, city: e.target.value })}
                    />
                    <Input
                        label="Quận/Huyện"
                        value={convertData.district}
                        onChange={(e) => setConvertData({ ...convertData, district: e.target.value })}
                    />
                </div>
                 <Input
                        label="Phường/Xã"
                        value={convertData.ward}
                        onChange={(e) => setConvertData({ ...convertData, ward: e.target.value })}
                    />
            </div>
        </div>
        <div className="mt-6">
            <h3 className="font-bold text-lg border-b pb-2 mb-4">Chi tiết đơn hàng</h3>
            {selectedQuote && selectedQuote.items.map((item, idx) => (
                <div key={idx} className="flex justify-between items-center bg-secondary/20 p-4 rounded-lg mb-2">
                    <div className="flex items-center gap-3">
                        <img src={item.productImage} className="w-12 h-12 rounded object-cover" />
                        <div>
                             <p className="font-medium">{item.productName}</p>
                             <p className="text-sm">x{item.quantity}</p>
                        </div>
                    </div>
                    <div className="text-right">
                        <p className="text-sm text-tertiary">Đơn giá</p>
                        <p className="font-bold text-lg text-primary">{formatCurrency(item.approvedPrice || 0)}</p>
                    </div>
                </div>
            ))}
             <div className="mt-4">
                <label className="block text-sm font-medium mb-1">Ghi chú đơn hàng</label>
                <textarea 
                    className="w-full border rounded-lg p-2" 
                    rows={2}
                    value={convertData.note}
                    onChange={(e) => setConvertData({...convertData, note: e.target.value})}
                />
            </div>
        </div>
      </Modal>
    </div>
  );
};

export default QuotesPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Star, Check, X, MessageSquare, Trash2, Search, Filter } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { AdminPageHeader } from '@/components/admin';
import { DataTable } from '@/components/common';
import { formatDate } from '@/utils/format';
import { reviewService, type ReviewDto } from '@/services/reviewService';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { PaginationDefaults } from '@/constants';
import { useToast } from '@/store';

export const ReviewsPage = () => {
  const { t } = useTranslation();
  const { success, error: toastError } = useToast();
  const queryClient = useQueryClient();

  // State
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [selectedReview, setSelectedReview] = useState<ReviewDto | null>(null);
  const [reviewToDelete, setReviewToDelete] = useState<ReviewDto | null>(null);
  const [replyText, setReplyText] = useState('');

  // Queries
  const { data: reviewsData, isLoading, isFetching } = useQuery({
    queryKey: ['admin-reviews', currentPage, pageSize, searchQuery, statusFilter],
    queryFn: () => reviewService.search({
      pageIndex: currentPage,
      pageSize: pageSize,
      search: searchQuery,
      filters: statusFilter !== 'all' ? [
        { field: 'isApproved', value: statusFilter === 'approved' }
      ] : []
    }),
  });

  const reviews = reviewsData?.data?.items || [];
  const totalPages = reviewsData?.data?.totalPages || 1;

  // Mutations
  const approveMutation = useMutation({
    mutationFn: (code: string) => reviewService.approve(code),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-reviews'] });
    },
    onError: () => toastError(t('messages.updateError'))
  });

  const rejectMutation = useMutation({
    mutationFn: (code: string) => reviewService.reject(code),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-reviews'] });
    },
    onError: () => toastError(t('messages.updateError'))
  });

  const deleteMutation = useMutation({
    mutationFn: (code: string) => reviewService.delete(code),
    onSuccess: () => {
      success(t('messages.deleteSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-reviews'] });
      setReviewToDelete(null);
    },
    onError: () => toastError(t('messages.deleteError'))
  });

  const replyMutation = useMutation({
    mutationFn: (data: { code: string, reply: string }) => 
      reviewService.update(data.code, { adminReply: data.reply }),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-reviews'] });
      setSelectedReview(null);
      setReplyText('');
    },
    onError: () => toastError(t('messages.updateError'))
  });

  // Handlers
  const handleReply = () => {
    if (selectedReview && replyText.trim()) {
      replyMutation.mutate({ code: selectedReview.code, reply: replyText });
    }
  };

  const renderStars = (rating: number) => {
    return (
      <div className="flex gap-0.5">
        {Array.from({ length: 5 }).map((_, i) => (
          <Star
            key={i}
            size={14}
            className={i < rating ? 'fill-yellow-400 text-yellow-400' : 'text-gray-300'}
          />
        ))}
      </div>
    );
  };

  // Columns
  const columns = [
    {
      id: 'product',
      header: t('common.fields.product'),
      accessor: (row: ReviewDto) => (
        <div className="max-w-[200px]">
          <p className="font-medium truncate">{row.productName || row.productCode}</p>
          <p className="text-xs text-tertiary">{row.productCode}</p>
        </div>
      )
    },
    {
      id: 'user',
      header: t('common.fields.user'),
      accessor: (row: ReviewDto) => (
        <div>
          <p className="font-medium">{row.userName}</p>
          <p className="text-xs text-secondary">{row.userCode}</p>
        </div>
      )
    },
    {
      id: 'rating',
      header: t('common.fields.rating'),
      accessor: (row: ReviewDto) => renderStars(row.rating),
      className: 'text-center'
    },
    {
      id: 'comment',
      header: t('common.fields.comment'),
      accessor: (row: ReviewDto) => (
        <div className="max-w-[300px]">
          <p className="text-sm line-clamp-2">{row.comment}</p>
          {row.adminReply && (
            <p className="text-xs text-primary mt-1 flex items-center gap-1 italic">
              <MessageSquare size={10} /> {t('admin.reviews.replied')}
            </p>
          )}
        </div>
      )
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (row: ReviewDto) => (
        <Badge color={row.isApproved ? 'success' : 'warning'} size="sm">
          {row.isApproved ? t('admin.reviews.approved') : t('admin.reviews.pending')}
        </Badge>
      ),
      className: 'text-center'
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (row: ReviewDto) => <span className="text-secondary text-sm">{formatDate(row.createdAt)}</span>
    }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.reviews"
        subtitle="admin.subtitles.reviews"
      />

      {/* Toolbar */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between bg-primary p-4 rounded-xl border border-tertiary">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" size={18} />
          <input
            type="text"
            placeholder={t('common.placeholders.search')}
            className="w-full pl-10 pr-4 py-2 bg-secondary border border-tertiary rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
        <div className="flex gap-2">
           <select 
            className="bg-secondary border border-tertiary rounded-lg px-3 py-2 text-sm focus:outline-none"
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
           >
              <option value="all">{t('admin.reviews.all')}</option>
              <option value="approved">{t('admin.reviews.approved')}</option>
              <option value="pending">{t('admin.reviews.pending')}</option>
           </select>
           <Button variant="outline" onClick={() => queryClient.invalidateQueries({ queryKey: ['admin-reviews'] })}>
              {t('common.refresh')}
           </Button>
        </div>
      </div>

      <DataTable
        columns={columns}
        data={reviews}
        isLoading={isLoading || isFetching}
        keyField="code"
        
        currentPage={currentPage}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setCurrentPage}
        onPageSizeChange={setPageSize}

        renderRowActions={(row) => (
          <div className="flex items-center gap-1">
            {!row.isApproved && (
              <button
                className="p-1.5 hover:bg-success/10 rounded text-success"
                title={t('admin.actions.approve')}
                onClick={() => approveMutation.mutate(row.code)}
              >
                <Check size={18} />
              </button>
            )}
            {row.isApproved && (
               <button
                 className="p-1.5 hover:bg-warning/10 rounded text-warning"
                 title={t('admin.actions.unapprove')}
                 onClick={() => rejectMutation.mutate(row.code)}
               >
                 <X size={18} />
               </button>
            )}
            <button
              className="p-1.5 hover:bg-primary/10 rounded text-primary"
              title={t('admin.actions.reply')}
              onClick={() => {
                setSelectedReview(row);
                setReplyText(row.adminReply || '');
              }}
            >
              <MessageSquare size={18} />
            </button>
            <button
              className="p-1.5 hover:bg-error/10 rounded text-error"
              title={t('common.actions.delete')}
              onClick={() => setReviewToDelete(row)}
            >
              <Trash2 size={18} />
            </button>
          </div>
        )}
      />

      {/* Reply Modal */}
      <Modal
        isOpen={!!selectedReview}
        onClose={() => setSelectedReview(null)}
        title={t('admin.reviews.replyTitle')}
        footer={
          <div className="flex justify-end gap-2">
            <Button variant="outline" onClick={() => setSelectedReview(null)}>{t('common.cancel')}</Button>
            <Button onClick={handleReply} isLoading={replyMutation.isPending}>{t('common.save')}</Button>
          </div>
        }
      >
        {selectedReview && (
          <div className="space-y-4">
            <div className="bg-secondary p-4 rounded-lg">
              <div className="flex justify-between items-start mb-2">
                <span className="font-bold">{selectedReview.userName}</span>
                {renderStars(selectedReview.rating)}
              </div>
              <p className="text-sm text-secondary italic">"{selectedReview.comment}"</p>
            </div>
            <div>
              <label className="block text-sm font-medium mb-1">{t('admin.reviews.yourReply')}</label>
              <textarea
                className="w-full p-3 bg-primary border rounded-lg h-32 focus:ring-2 focus:ring-primary/20 outline-none"
                placeholder={t('admin.reviews.replyPlaceholder')}
                value={replyText}
                onChange={(e) => setReplyText(e.target.value)}
              />
            </div>
          </div>
        )}
      </Modal>

      <ConfirmDialog
        isOpen={!!reviewToDelete}
        onClose={() => setReviewToDelete(null)}
        onConfirm={() => reviewToDelete && deleteMutation.mutate(reviewToDelete.code)}
        title={t('common.actions.delete')}
        message={t('messages.confirmDelete')}
        variant="danger"
        isLoading={deleteMutation.isPending}
      />
    </div>
  );
};

export default ReviewsPage;

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Shield, Edit, Trash2, Plus, Info, CheckCircle2, XCircle } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { roleService, CreateRoleRequest, UpdateRoleRequest } from '@/services/roleService';
import { useEntityManager, useRoles } from '@/hooks';
import type { Role } from '@/types';
import { DataTable, type DataTableColumn } from '@/components/common/DataTable';
import { AdminPageHeader } from '@/components/admin';
import { PaginationDefaults, SortDirection } from '@/constants';
import { RoleForm, RoleFormData } from './forms/RoleForm';

export const RolesPage = () => {
    const { t, i18n } = useTranslation();

    // State
    const [currentPage, setCurrentPage] = useState<number>(PaginationDefaults.PAGE_INDEX);
    const [pageSize, setPageSize] = useState<number>(PaginationDefaults.PAGE_SIZE);
    const [searchQuery, setSearchQuery] = useState<string>('');

    // Sorting
    const [sortField, setSortField] = useState<string>('name');
    const [sortDir, setSortDir] = useState<SortDirection>(SortDirection.ASC);

    // Data Fetching
    const {
        data: result,
        isLoading,
        isFetching,
        isError,
        error,
        refetch
    } = useRoles({
        pageIndex: currentPage,
        pageSize,
        search: searchQuery || undefined,
        searchField: 'Name',
        sortBy: sortField,
        sortDesc: sortDir === SortDirection.DESC
    });
    
    const roles = result?.data?.items || [];
    const totalItems = result?.data?.totalItems || 0;
    const totalPages = Math.ceil(totalItems / pageSize) || 1;

    // Entity Manager (for CRUD state)
    const {
        isFormOpen,
        editingItem: editingRole,
        itemToDelete: roleToDelete,
        isDeleting,
        openCreate,
        openEdit,
        closeForm,
        confirmDelete,
        cancelDelete,
        createMutation,
        updateMutation,
        deleteMutation
    } = useEntityManager<Role, CreateRoleRequest, UpdateRoleRequest>({
        service: roleService,
        queryKey: ['roles']
    });

    // Handlers
    const handleSort = (field: string, dir: 'asc' | 'desc') => {
        setSortField(field);
        setSortDir(dir as SortDirection);
        setCurrentPage(PaginationDefaults.PAGE_INDEX);
    };

    const handleCreate = async (data: RoleFormData) => {
        try {
            await createMutation.mutateAsync({
                name: data.name,
                description: data.description,
                isActive: data.isActive,
                permissionCodes: data.permissionCodes
            });
        } catch (err) {
            // Error handled by hook
        }
    };

    const handleUpdate = async (data: RoleFormData) => {
        if (!editingRole) return;
        try {
            await updateMutation.mutateAsync({
                id: editingRole.code,
                data: {
                    name: data.name,
                    description: data.description,
                    isActive: data.isActive,
                    permissionCodes: data.permissionCodes
                }
            });
        } catch (err) {
            // Error handled by hook
        }
    };

    const handleDelete = async () => {
        if (roleToDelete) {
            deleteMutation.mutate(roleToDelete.code);
        }
    };

    // Column Definitions
    const columns: DataTableColumn<Role>[] = [
        {
            id: 'code',
            header: t('common.fields.code'),
            accessor: 'code',
            sortable: true
        },
        {
            id: 'name',
            header: t('common.fields.name'),
            accessor: (role) => (
                <div>
                    <p className="font-medium text-sm text-slate-700 dark:text-slate-200">{role.name}</p>
                    <p className="text-xs text-slate-500 line-clamp-1">{role.description}</p>
                </div>
            ),
            sortable: true
        },
        {
            id: 'permissions',
            header: t('rbac.permissions'),
            accessor: (role) => (
                <div className="flex flex-wrap gap-1 max-w-xs">
                    {role.permissions?.slice(0, 5).map(p => (
                        <Badge key={p.code} size="sm" variant="outline" color="primary">{p.name}</Badge>
                    ))}
                    {role.permissions?.length > 5 && (
                        <Badge size="sm" variant="outline">+{role.permissions.length - 5}</Badge>
                    )}
                </div>
            )
        },
        {
            id: 'status',
            header: t('common.fields.status'),
            accessor: (role) => (
                <Badge
                    color={role.isActive ? 'success' : 'error'}
                    size="sm"
                    variant="soft"
                >
                    {role.isActive ? t('common.status.active') : t('common.status.inactive')}
                </Badge>
            ),
            className: 'text-center',
            headerClassName: 'text-center'
        },
        {
            id: 'actions',
            header: '',
            accessor: (role) => (
                <div className="flex justify-end gap-2">
                    <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => openEdit(role)}
                        title={t('common.actions.edit')}
                    >
                        <Edit size={16} />
                    </Button>
                    <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => confirmDelete(role)}
                        disabled={role.code === 'ADMIN'} // Protected role
                        title={t('common.actions.delete')}
                        className="text-rose-500 hover:text-rose-600 hover:bg-rose-50"
                    >
                        <Trash2 size={16} />
                    </Button>
                </div>
            ),
            className: 'text-right'
        }
    ];

    const roleInitialData = useMemo(() => editingRole ? {
        name: editingRole.name,
        description: editingRole.description,
        isActive: editingRole.isActive,
        permissionCodes: editingRole.permissions?.map(p => p.code) || []
    } : undefined, [editingRole]);

    return (
        <div className="space-y-6">
            <AdminPageHeader
                title="rbac.roles.title"
                subtitle="rbac.roles.subtitle"
            />

            <DataTable
                columns={columns}
                data={roles}
                keyField="code"
                isLoading={isLoading}
                isFetching={isFetching}
                onAdd={() => openCreate()}
                onRefresh={() => refetch()}
                error={isError ? (error as Error) : null}

                // Sorting
                externalSortField={sortField}
                externalSortDir={sortDir}
                onExternalSort={handleSort}

                // Pagination
                currentPage={currentPage}
                totalPages={totalPages}
                totalItems={totalItems}
                pageSize={pageSize}
                onPageChange={setCurrentPage}
                onPageSizeChange={(size) => {
                    setPageSize(size);
                    setCurrentPage(PaginationDefaults.PAGE_INDEX);
                }}

                // Search
                onSearch={setSearchQuery}
            />

            {/* Form Modal */}
            <Modal
                isOpen={isFormOpen}
                onClose={closeForm}
                title={editingRole ? t('rbac.roles.edit') : t('rbac.roles.create')}
                size="4xl"
            >
                <RoleForm
                    initialData={roleInitialData}
                    onSubmit={editingRole ? handleUpdate : handleCreate}
                    onCancel={closeForm}
                    isLoading={createMutation.isPending || updateMutation.isPending}
                    isEdit={!!editingRole}
                />
            </Modal>

            {/* Delete Confirmation */}
            <ConfirmDialog
                isOpen={!!roleToDelete}
                onClose={cancelDelete}
                onConfirm={handleDelete}
                title={t('common.actions.delete')}
                message={t('rbac.roles.deleteConfirm', { name: roleToDelete?.name })}
                confirmText={t('common.actions.delete')}
                variant="danger"
                isLoading={isDeleting}
            />
        </div>
    );
};

export default RolesPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useForm } from 'react-hook-form';
import { Save, Store, CreditCard, Truck, Bell, Shield, Globe, Eye, EyeOff, Lock } from 'lucide-react';
import { Button, Input, Select, Switch } from '@/components/ui';
import { AdminPageHeader } from '@/components/admin';
import { useToast, useSettings } from '@/store';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { createSchemas } from '@/utils/schemas';

export const SettingsPage = () => {
    const { t } = useTranslation();
    const { 
        generalSettingsSchema, 
        paymentSettingsSchema, 
        shippingSettingsSchema, 
        notificationsSettingsSchema, 
        changePasswordSchema 
    } = createSchemas(t);
  const toast = useToast();
  const [activeTab, setActiveTab] = useState('general');
  const { settings, updateSettings } = useSettings();

  const handleSave = (section: keyof typeof settings, data: any) => {
    updateSettings(section, data);
    toast.success(t('messages.saveSuccess'));
  };

  const tabs = [
    { id: 'general', label: t('admin.settingsPage.tabs.general'), icon: Store },
    { id: 'payment', label: t('admin.settingsPage.tabs.payment'), icon: CreditCard },
    { id: 'shipping', label: t('admin.settingsPage.tabs.shipping'), icon: Truck },
    { id: 'notifications', label: t('admin.settingsPage.tabs.notifications'), icon: Bell },
    { id: 'security', label: t('admin.settingsPage.tabs.security'), icon: Shield },
  ];

  const GeneralSettings = () => {
    const { register, handleSubmit, formState: { errors } } = useForm({
      resolver: zodResolver(generalSettingsSchema),
      defaultValues: settings.general
    });

    return (
      <form onSubmit={handleSubmit((data) => handleSave('general', data))} className="space-y-6">
        <h2 className="text-lg font-bold flex items-center gap-2">
          <Store size={20} />
          {t('admin.settingsPage.tabs.general')}
        </h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <Input 
            label={t('admin.settingsPage.general.storeName')} 
            placeholder={t('common.placeholders.storeName')}
            {...register('storeName')} 
            error={errors.storeName?.message} 
          />
          <Input 
            label={t('admin.settingsPage.general.email')} 
            type="email" 
            placeholder={t('common.placeholders.email')}
            {...register('email')} 
            error={errors.email?.message} 
          />
          <Input 
            label={t('admin.settingsPage.general.phone')} 
            placeholder={t('common.placeholders.phone')}
            {...register('phone')} 
            error={errors.phone?.message} 
          />
          <Input 
            label={t('admin.settingsPage.general.website')} 
            placeholder={t('common.placeholders.website')}
            {...register('website')} 
            error={errors.website?.message} 
          />
          <div className="md:col-span-2">
            <Input 
                label={t('admin.settingsPage.general.address')} 
                placeholder={t('common.placeholders.address')}
                {...register('address')} 
                error={errors.address?.message} 
            />
          </div>
          <div className="md:col-span-2">
            <label className="block text-sm font-bold text-primary mb-2">{t('admin.settingsPage.general.description')}</label>
            <textarea
              rows={3}
              {...register('description')}
              placeholder={t('common.placeholders.description')}
              className="w-full px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:border-primary focus:ring-1 focus:ring-primary resize-none placeholder:text-tertiary text-sm"
            />
          </div>
        </div>

        <Button type="submit" leftIcon={<Save size={18} />}>{t('common.save')}</Button>
      </form>
    );
  };

  const PaymentSettings = () => {
    const { register, handleSubmit, setValue, watch } = useForm({
        resolver: zodResolver(paymentSettingsSchema),
        defaultValues: settings.payment
    });

    const formState = watch();

    return (
      <form onSubmit={handleSubmit((data) => handleSave('payment', data))} className="space-y-6">
        <h2 className="text-lg font-bold flex items-center gap-2">
          <CreditCard size={20} />
          {t('admin.settingsPage.payment.title')}
        </h2>

        <div className="space-y-4">
          {[
            { id: 'cod', name: t('admin.settingsPage.payment.cod'), desc: t('admin.settingsPage.payment.codDesc') },
            { id: 'zaloPay', name: t('shared.zaloPay'), desc: t('admin.settingsPage.payment.zaloPayDesc') },
            { id: 'momo', name: t('shared.momo'), desc: t('admin.settingsPage.payment.momoDesc') },
            { id: 'vnpay', name: t('shared.vnpay'), desc: t('admin.settingsPage.payment.vnpayDesc') },
            { id: 'bankTransfer', name: t('admin.settingsPage.payment.bankTransfer'), desc: t('admin.settingsPage.payment.bankTransferDesc') },
          ].map((method) => (
            <div key={method.id} className="p-1">
                <Switch
                    label={method.name}
                    description={method.desc}
                    checked={formState[method.id as keyof typeof formState] as boolean}
                    onChange={(val) => setValue(method.id as any, val)}
                    className="p-4 bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800 rounded-xl"
                />
            </div>
          ))}
        </div>

        <Button type="submit" leftIcon={<Save size={18} />}>{t('common.save')}</Button>
      </form>
    );
  };

  const ShippingSettings = () => {
      const { register, handleSubmit, formState: { errors } } = useForm({
          resolver: zodResolver(shippingSettingsSchema),
          defaultValues: settings.shipping
      });
      
      return (
        <form onSubmit={handleSubmit((data) => handleSave('shipping', data))} className="space-y-6">
          <h2 className="text-lg font-bold flex items-center gap-2">
            <Truck size={20} />
            {t('admin.settingsPage.shipping.title')}
          </h2>

          <div className="space-y-4">
            <Input
              label={t('admin.settingsPage.shipping.defaultFee')}
              type="number"
              placeholder={t('common.placeholders.shippingFee')}
              {...register('defaultFee', { valueAsNumber: true })}
              error={errors.defaultFee?.message}
            />
            <Input
              label={t('admin.settingsPage.shipping.freeShippingThreshold')}
              type="number"
              placeholder={t('common.placeholders.shippingThreshold')}
              {...register('freeShippingThreshold', { valueAsNumber: true })}
              error={errors.freeShippingThreshold?.message}
            />
            <Input
              label={t('admin.settingsPage.shipping.estimatedDelivery')}
              placeholder={t('common.placeholders.deliveryTime')}
              {...register('estimatedDelivery')}
              error={errors.estimatedDelivery?.message}
            />
          </div>

          <Button type="submit" leftIcon={<Save size={18} />}>{t('common.save')}</Button>
        </form>
      );
  };

  const NotificationSettings = () => {
    const { register, handleSubmit, setValue, watch } = useForm({
        resolver: zodResolver(notificationsSettingsSchema),
        defaultValues: settings.notifications
    });

    const formState = watch();

    return (
        <form onSubmit={handleSubmit((data) => handleSave('notifications', data))} className="space-y-6">
            <h2 className="text-lg font-bold flex items-center gap-2">
            <Bell size={20} />
            {t('admin.settingsPage.notifications.title')}
            </h2>

            <div className="space-y-4">
            {[
                { id: 'emailNewOrder', label: t('admin.settingsPage.notifications.emailNewOrder') },
                { id: 'emailQuoteRequest', label: t('admin.settingsPage.notifications.emailQuoteRequest') },
                { id: 'emailOrderStatus', label: t('admin.settingsPage.notifications.emailOrderStatus') },
                { id: 'lowStockAlert', label: t('admin.settingsPage.notifications.lowStockAlert') },
            ].map((setting) => (
                <div key={setting.id} className="p-1">
                    <Switch
                        label={setting.label}
                        checked={formState[setting.id as keyof typeof formState] as boolean}
                        onChange={(val) => setValue(setting.id as any, val)}
                        className="p-4 bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800 rounded-xl"
                    />
                </div>
            ))}
            </div>

            <Button type="submit" leftIcon={<Save size={18} />}>{t('common.save')}</Button>
        </form>
    );
  };

  // Helper for password fields with toggle
  interface PasswordInputProps extends React.ComponentProps<typeof Input> {
    label: string;
  }
  const PasswordInput = ({ label, ...props }: PasswordInputProps) => {
    const [show, setShow] = useState(false);
    return (
      <Input
        label={label}
        type={show ? 'text' : 'password'}
        rightIcon={
          <button
            type="button"
            onClick={() => setShow(!show)}
            className="flex items-center justify-center p-1 text-slate-400 opacity-50 hover:opacity-100 hover:text-primary focus:outline-none transition-all"
            tabIndex={-1}
          >
            {show ? <EyeOff size={18} /> : <Eye size={18} />}
          </button>
        }
        {...props}
      />
    );
  };

  // Security Mock - no persistence needed for password/modal logic yet
  const SecuritySettings = () => {
    const { register, handleSubmit, formState: { errors }, reset } = useForm({
        resolver: zodResolver(changePasswordSchema),
        defaultValues: {
            currentPassword: '',
            newPassword: '',
            confirmPassword: '',
        }
    });

    const onSubmit = (data: z.infer<typeof changePasswordSchema>) => {
        // Logic to call API or update store
        toast.success(t('messages.saveSuccess'));
        reset();
    };

    return (
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
            <h2 className="text-lg font-bold flex items-center gap-2">
            <Shield size={20} />
            {t('admin.settingsPage.security.title')}
            </h2>

            <div className="p-4 border border-gray-100 dark:border-slate-800 rounded-xl bg-slate-50/50 dark:bg-slate-900/20">
            <h3 className="font-bold text-md mb-4 flex items-center gap-2">
                <Lock size={18} className="text-tertiary" />
                {t('admin.settingsPage.security.changePassword')}
            </h3>
            <div className="space-y-4">
                <PasswordInput 
                    label={t('admin.settingsPage.security.currentPassword')} 
                    placeholder={t('common.placeholders.currentPassword')}
                    {...register('currentPassword')} 
                    error={errors.currentPassword?.message}
                />
                <PasswordInput 
                    label={t('admin.settingsPage.security.newPassword')} 
                    placeholder={t('common.placeholders.newPassword')}
                    {...register('newPassword')} 
                    error={errors.newPassword?.message}
                />
                <PasswordInput 
                    label={t('admin.settingsPage.security.confirmNewPassword')} 
                    placeholder={t('common.placeholders.confirmPassword')}
                    {...register('confirmPassword')} 
                    error={errors.confirmPassword?.message}
                />
            </div>
            </div>

            <div className="p-4 border rounded-lg">
            <div className="flex items-center justify-between">
                <div>
                <p className="font-medium">{t('admin.settingsPage.security.twoFactor')}</p>
                <p className="text-sm text-tertiary">{t('admin.settingsPage.security.twoFactorDesc')}</p>
                </div>
                <Button variant="outline" size="sm" type="button">{t('admin.settingsPage.security.enable')}</Button>
            </div>
            </div>

            <Button type="submit" leftIcon={<Save size={18} />}>{t('common.save')}</Button>
        </form>
    );
  };

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.settings"
        subtitle="admin.subtitles.settings"
      />

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        {/* Sidebar */}
        <div className="lg:col-span-1">
          <div className="bg-primary rounded-xl p-2 sticky top-20">
            {tabs.map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg text-left transition-colors ${activeTab === tab.id ? 'bg-primary/10 text-indigo-600 dark:text-indigo-400 font-medium' : 'hover:bg-secondary text-secondary'
                  }`}
              >
                <tab.icon size={18} />
                <span className="">{tab.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Content */}
        <div className="lg:col-span-3">
          <div className="bg-primary rounded-xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
            {activeTab === 'general' && <GeneralSettings />}
            {activeTab === 'payment' && <PaymentSettings />}
            {activeTab === 'shipping' && <ShippingSettings />}
            {activeTab === 'notifications' && <NotificationSettings />}
            {activeTab === 'security' && <SecuritySettings />}
          </div>
        </div>
      </div>
    </div>
  );
};

