import { useMemo } from 'react';
import { SupplierForm, type SupplierFormData } from './forms';
import { StatsCards, StatItem } from '@/components/admin/StatsCards';
import { useQuery } from '@tanstack/react-query';

export default function SuppliersPage() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();

  // Data Fetching
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [filters, setFilters] = useState<Record<string, string>>({});

  const searchParams = useMemo(() => {
     const filterParams = [];
     if (filters.Name) filterParams.push({ field: 'Name', value: filters.Name, operator: SearchCondition.Contains });
     if (filters.TaxCode) filterParams.push({ field: 'TaxCode', value: filters.TaxCode, operator: SearchCondition.Contains });
     if (filters.Phone) filterParams.push({ field: 'Phone', value: filters.Phone, operator: SearchCondition.Contains });
     if (filters.IsActive) filterParams.push({ field: 'IsActive', value: filters.IsActive === 'true', operator: SearchCondition.Equal });
     
     return {
        pageIndex: page,
        pageSize,
        filters: filterParams
     };
  }, [page, pageSize, filters]);

  const { 
    data: result, 
    isLoading, 
    isFetching,
    refetch 
  } = useSuppliersPaged(searchParams);

  const suppliers = result?.items || [];
  const totalItems = result?.totalItems || 0;
  const totalPages = Math.ceil(totalItems / pageSize);

  // Entity Manager (for CRUD state)
  const {
      isFormOpen,
      editingItem: editingSupplier,
      itemToDelete: supplierToDelete,
      isDeleting,
      openCreate,
      openEdit,
      closeForm,
      confirmDelete,
      cancelDelete,
      createMutation,
      updateMutation,
      deleteMutation
  } = useEntityManager<SupplierDto, CreateSupplierRequest, UpdateSupplierRequest>({
      service: supplierService,
      queryKey: ['suppliers']
  });

  const { mutate: createSupplier, isPending: isCreating } = createMutation;
  const { mutate: updateSupplier, isPending: isUpdating } = updateMutation;
  const { mutate: deleteSupplier } = deleteMutation;

  // View State
  const [viewingSupplier, setViewingSupplier] = useState<SupplierDto | null>(null);

  // Selection
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Bulk Delete State
  const [itemsToDelete, setItemsToDelete] = useState<SupplierDto[] | null>(null);

  const bulkDeleteMutation = useMutation({
    mutationFn: (codes: string[]) => supplierService.deleteMultiple(codes),
    onSuccess: () => {
      setItemsToDelete(null);
      queryClient.invalidateQueries({ queryKey: ['suppliers'] });
    }
  });

  const handleBulkDelete = (items: SupplierDto[]) => {
    setItemsToDelete(items);
  };

  const confirmBulkDelete = () => {
    if (itemsToDelete) {
      bulkDeleteMutation.mutate(itemsToDelete.map(i => i.code));
    }
  };

  const handleFormSubmit = async (formData: SupplierFormData) => {
    if (editingSupplier) {
      await updateSupplier({
          id: editingSupplier.code, 
          data: formData as UpdateSupplierRequest
      }, {
          onSuccess: () => closeForm()
      });
    } else {
      await createSupplier(formData as unknown as CreateSupplierRequest, {
          onSuccess: () => closeForm()
      });
    }
  };



  const handleImport = async (file: File) => {
      try {
          await supplierService.import(file);
          // Assuming toast is available globally or needs import. 
          // SuppliersPage uses useTranslation but not useToast explicitly in original snippet but let's check imports.
          // Original imports didn't show useToast. I will assume it's okay or add if needed.
          // Wait, ProductsPage used useToast. SuppliersPage might not have it setup.
          // Actually, handleApiResponse in baseService handles toast if we use it, but here we call service directly.
          // Let's just refetch.
          refetch();
      } catch (error) {
          console.error("Import error", error);
      }
  };

  const handleDelete = () => {
    if (supplierToDelete) {
      deleteSupplier(supplierToDelete.code);
    }
  };

  const isSubmitting = isCreating || isUpdating;

  const prepareInitialData = (): Partial<SupplierFormData> | undefined => {
      if (!editingSupplier) return undefined;
      return {
          name: editingSupplier.name,
          contactPerson: editingSupplier.contactPerson || undefined,
          email: editingSupplier.email || undefined,
          phone: editingSupplier.phone || undefined,
          address: editingSupplier.address || undefined,
          taxCode: editingSupplier.taxCode || undefined,
          bankAccount: editingSupplier.bankAccount || undefined,
          bankName: editingSupplier.bankName || undefined,
          notes: editingSupplier.notes || undefined,
          isActive: editingSupplier.isActive
      };
  };

  // Column definitions
  const columns: DataTableColumn<SupplierDto>[] = [
    {
      id: 'name',
      header: t('common.fields.name'),
      accessor: (supplier) => (
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
            <Building2 size={16} />
          </div>
          <div>
            <p className="font-medium text-slate-800 dark:text-slate-100">{supplier.name}</p>
            {supplier.taxCode && <p className="text-xs text-secondary">{t('common.fields.taxCode')}: {supplier.taxCode}</p>}
          </div>
        </div>
      ),
      sortable: true,
    },
    {
      id: 'contact',
      header: t('common.fields.contact'),
      accessor: (supplier) => (
        <div className="space-y-1">
          {supplier.contactPerson && (
            <p className="text-sm font-medium">{supplier.contactPerson}</p>
          )}
          {supplier.phone && (
            <div className="flex items-center gap-1.5 text-xs text-secondary">
              <Phone size={12} />
              <span>{supplier.phone}</span>
            </div>
          )}
          {supplier.email && (
            <div className="flex items-center gap-1.5 text-xs text-secondary">
              <Mail size={12} />
              <span className="truncate max-w-[150px]">{supplier.email}</span>
            </div>
          )}
        </div>
      ),
    },
    {
      id: 'address',
      header: t('common.fields.address'),
      accessor: 'address',
      className: 'hidden md:table-cell max-w-[200px] truncate'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (supplier) => (
        <Badge color={supplier.isActive !== false ? 'success' : 'secondary'}>
          {supplier.isActive !== false ? t('admin.status.active') : t('admin.status.inactive')}
        </Badge>
      ),
      className: 'text-center',
    },
    {
        id: 'actions',
        header: '',
        className: 'w-[100px]',
        accessor: (supplier) => (
          <TableActions
            onView={() => setViewingSupplier(supplier)}
            onEdit={() => openEdit(supplier)}
            onDelete={() => confirmDelete(supplier)}
          />
        )
      }
  ];

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['supplier-stats'],
      queryFn: () => supplierService.getStats(),
      staleTime: 60000,
  });

  const stats: StatItem[] = [
      {
          label: t('admin.stats.totalSuppliers'),
          value: statsData?.total || 0,
          icon: <Truck size={24} />,
          color: 'blue',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.active'),
          value: statsData?.active || 0,
          icon: <RefreshCw size={24} />,
          color: 'emerald',
          loading: isStatsLoading
      }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.suppliers"
        subtitle="admin.subtitles.suppliers"
      />

      <StatsCards stats={stats} />

      <DataTable
        data={suppliers as SupplierDto[]}
        columns={columns}
        isLoading={isLoading}
        searchPlaceholder={t('common.placeholders.search')}
        searchOptions={[
          { label: t('common.fields.name'), value: 'name' },
          { label: t('common.fields.phone'), value: 'phone' },
          { label: t('common.fields.email'), value: 'email' }
        ]}
        keyField="code"
        enableSelection
        // Selection
        selectedIds={selectedIds}
        onSelectionChange={setSelectedIds}

        // Pagination
        currentPage={page}
        pageSize={pageSize}
        totalItems={totalItems}
        totalPages={totalPages}
        onPageChange={setPage}
        onPageSizeChange={setPageSize}
        
        onBulkDelete={handleBulkDelete}
        onAdd={() => openCreate()}
        onRefresh={() => refetch()}

        // Advanced Filter
        advancedFilterDefs={[
             { id: 'Name', label: t('common.fields.name'), type: 'text', placeholder: t('common.placeholders.search') },
             { id: 'TaxCode', label: t('common.fields.taxCode'), type: 'text', placeholder: 'MST...' },
             { id: 'Phone', label: t('common.fields.phone'), type: 'text', placeholder: 'SDT...' },
             { id: 'IsActive', label: t('common.fields.status'), type: 'select', options: [{ value: 'true', label: t('admin.status.active') }, { value: 'false', label: t('admin.status.inactive') }] }
        ]}
        onAdvancedSearch={setFilters}

        // Export
         onExportAllData={async () => {
           return supplierService.exportData(); // Use new generic helper
        }}
        onImport={handleImport}
        importTemplateUrl="/suppliers/template"
        importTitle={t('common.importData')}

        onEdit={(item) => openEdit(item)}
        onDelete={(item) => confirmDelete(item)}
        onView={(item) => setViewingSupplier(item)}
      />

       {/* Form Modal */}
       {isFormOpen && (
        <SupplierForm
            initialData={prepareInitialData()}
            onSubmit={handleFormSubmit}
            onCancel={closeForm}
            isLoading={isSubmitting}
            modalOpen={isFormOpen}
            modalTitle={editingSupplier ? t('admin.actions.edit') : t('admin.actions.create')}
        />
       )}

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!supplierToDelete}
        onClose={cancelDelete}
        onConfirm={handleDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDelete', { name: supplierToDelete?.name })}
        confirmText={t('admin.actions.delete')}
        cancelText={t('common.cancel')}
        variant="danger"
        isLoading={isDeleting}
      />

      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!itemsToDelete}
        onClose={() => setItemsToDelete(null)}
        onConfirm={confirmBulkDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDeleteCount', { count: itemsToDelete?.length || 0 })}
        confirmText={t('admin.actions.delete')}
        cancelText={t('common.cancel')}
        variant="danger"
        isLoading={bulkDeleteMutation.isPending}
      />

      {/* View Details Modal */}
      {viewingSupplier && (
        <Modal
          isOpen={!!viewingSupplier}
          onClose={() => setViewingSupplier(null)}
          title={t('admin.actions.viewDetails')}
          size="lg"
        >
          <div className="space-y-6">
            <div className="flex items-center gap-4 border-b border-gray-100 dark:border-gray-800 pb-4">
              <div className="w-16 h-16 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
                <Building2 size={32} />
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">{viewingSupplier.name}</h2>
                <div className="mt-1">
                    <Badge color={viewingSupplier.isActive !== false ? 'success' : 'secondary'}>
                        {viewingSupplier.isActive !== false ? t('admin.status.active') : t('admin.status.inactive')}
                    </Badge>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-x-8 gap-y-6">
              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.taxCode')}</label>
                <p className="font-medium mt-1">{viewingSupplier.taxCode || t('common.none')}</p>
              </div>
              
              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.contactPerson')}</label>
                <p className="font-medium mt-1">{viewingSupplier.contactPerson || t('common.none')}</p>
              </div>

              <div className="col-span-2">
                 <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.address')}</label>
                 <p className="font-medium mt-1">{viewingSupplier.address || t('common.none')}</p>
              </div>

              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.phone')}</label>
                <div className="flex items-center gap-2 mt-1">
                    <Phone size={14} className="text-gray-400" />
                    <span className="font-medium">{viewingSupplier.phone || t('common.none')}</span>
                </div>
              </div>
              
              <div>
                 <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.email')}</label>
                 <div className="flex items-center gap-2 mt-1">
                    <Mail size={14} className="text-gray-400" />
                    <span className="font-medium">{viewingSupplier.email || t('common.none')}</span>
                </div>
              </div>

              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.bankName')}</label>
                <p className="font-medium mt-1">{viewingSupplier.bankName || t('common.none')}</p>
              </div>

              <div>
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.bankAccount')}</label>
                <p className="font-medium mt-1">{viewingSupplier.bankAccount || t('common.none')}</p>
              </div>

              <div className="col-span-2">
                <label className="text-xs text-secondary uppercase font-semibold">{t('common.fields.note')}</label>
                <p className="text-gray-600 dark:text-gray-300 mt-1 whitespace-pre-wrap text-sm">
                  {viewingSupplier.notes || t('common.none')}
                </p>
              </div>
            </div>
            
            <div className="flex justify-end pt-4 border-t border-gray-100 dark:border-gray-800">
              <Button onClick={() => setViewingSupplier(null)}>
                {t('common.close')}
              </Button>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}

import { z } from 'zod';
import { useTranslation } from 'react-i18next';
import { BaseForm, FieldDefinition } from '@/components/common';
import { createSchemas } from '@/utils/schemas';

// ============ Type ============
// Since bannerSchema is dynamic (localized), we can define a static interface 
// that matches it for prop typing.
export interface BannerFormData {
  title: string;
  content: string;
  linkUrl: string;
  linkText: string;
  imageURL: string;
  priority: number;
  isActive: boolean;
  [key: string]: any; // Required for FieldValues compatibility if we can't use 'any' then what?
}

// ============ Props ============
interface BannerFormProps {
  initialData?: Partial<BannerFormData>;
  onSubmit: (data: BannerFormData) => void | Promise<void>;
  onCancel: () => void;
  isLoading?: boolean;
}

// ============ Component ============
export const BannerForm = ({
  initialData,
  onSubmit,
  onCancel,
  isLoading = false,
}: BannerFormProps) => {
  const { t } = useTranslation();
  const { bannerSchema } = createSchemas(t);
  
  // Field definitions
  const fields: FieldDefinition[] = [
    {
      name: 'imageURL',
      type: 'image',
      label: t('common.fields.image'),
      colSpan: 12,
    },
    {
      name: 'title',
      type: 'text',
      label: t('common.fields.title'),
      placeholder: t('common.placeholders.enterTitle'),
      required: true,
      colSpan: 12,
    },
    {
      name: 'content',
      type: 'text',
      label: t('common.fields.content'),
      placeholder: t('common.placeholders.enterContent'),
      colSpan: 12,
    },
    {
      name: 'linkUrl',
      type: 'text',
      label: t('common.fields.linkUrl'),
      placeholder: t('common.placeholders.enterLinkUrl'),
      colSpan: 6,
    },
    {
      name: 'linkText',
      type: 'text',
      label: t('common.fields.linkText'),
      placeholder: t('common.placeholders.enterLinkText'),
      colSpan: 6,
    },
    {
      name: 'priority',
      type: 'number',
      label: t('common.fields.priority'),
      colSpan: 6,
    },
    {
      name: 'isActive',
      type: 'switch',
      label: t('common.status.active'),
      description: t('admin.statusHint'),
      colSpan: 6,
    },
  ];

  // Default values
  const defaultValues: BannerFormData = {
    title: initialData?.title || '',
    content: initialData?.content || '',
    linkUrl: initialData?.linkUrl || '',
    linkText: initialData?.linkText || t('common.placeholders.learnMore'),
    imageURL: initialData?.imageURL || '',
    priority: initialData?.priority || 0,
    isActive: initialData?.isActive ?? true,
  };

  return (
    <BaseForm<BannerFormData>
      schema={bannerSchema as any}
      defaultValues={defaultValues}
      fields={fields}
      onSubmit={onSubmit}
      onCancel={onCancel}
      isLoading={isLoading}
      submitLabel={initialData?.title ? t('common.save') : t('common.create')}
    />
  );
};

export default BannerForm;

import { useTranslation } from 'react-i18next';
import { z } from 'zod';
import { Upload, X, Edit, Trash2 } from 'lucide-react';
import { Button, Input, Badge, ConfirmDialog, Checkbox } from '@/components/ui';
import { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { getImageUrl } from '@/utils/format';
import { useToast } from '@/store';
import { BaseForm, FieldGroup } from '@/components/common';
import { useDropzone } from 'react-dropzone';
import { UseFormReturn, Controller } from 'react-hook-form';
import LazySelect from '@/components/ui/LazySelect';
import { categoryService, supplierService, unitService, brandService } from '@/services';
import { SearchCondition } from '@/services/baseService';
import { ProductUnitsManager, ProductUnitDto } from '@/components/common/ProductUnitsManager';
import { ProductVariantManager, ProductVariantData } from '@/components/common/ProductVariantManager';
import { ProductImage } from '@/types';

const productSchema = z.object({
  name: z.string().min(3, { message: 'validation.productNameMin' }),
  categoryCode: z.string().min(1, { message: 'validation.categoryRequired' }),
  price: z.number().min(0, { message: 'validation.priceMin' }),
  wholesalePrice: z.number().min(0, { message: 'validation.priceMin' }).optional(),
  costPrice: z.number().min(0, { message: 'validation.priceMin' }).optional(),
  stockQuantity: z.number().int({ message: 'validation.integer' }).min(0, { message: 'validation.stockMin' }),
  description: z.string().optional(),
  brandCode: z.string().optional(),
  baseUnit: z.string().optional(),
  minStockLevel: z.number().optional(),
  binLocation: z.string().optional(),
  vatRate: z.number().optional(),
  countryOfOrigin: z.string().optional(),
  supplierCode: z.string().optional(),
  weight: z.number().optional(),
  color: z.string().optional(),
  power: z.string().optional(),
  voltage: z.string().optional(),
  material: z.string().optional(),
  size: z.string().optional(),
  images: z.array(z.string()).optional(),
  isActive: z.boolean().optional(),
  details: z.array(z.object({
    detailType: z.enum(['SPEC', 'LOGISTICS', 'RELATION', 'IMAGE']),
    specName: z.string().min(1, { message: 'validation.required' }),
    specValue: z.string().min(1, { message: 'validation.required' })
  })).optional(),
  code: z.string().optional(),
  unitsSection: z.any().optional(),
  productUnits: z.array(z.any()).optional(),
  variants: z.array(z.any()).optional(),
});

export type ProductFormData = z.infer<typeof productSchema>;

interface ProductDetail {
  detailType: 'SPEC' | 'LOGISTICS' | 'RELATION' | 'IMAGE';
  specName: string;
  specValue: string;
}

interface ProductFormProps {
  initialData?: Partial<ProductFormData> & { 
      productImages?: ProductImage[]; 
      originalPrice?: number;
      categoryName?: string;
      supplierName?: string;
      brandName?: string;
      productUnits?: ProductUnitDto[];
      variants?: ProductVariantData[];
      imageURL?: string;
  };
  onSubmit: (data: ProductFormData) => void;
  onCancel: () => void;
  isLoading?: boolean;
}


export const ProductForm = ({ initialData, onSubmit, onCancel, isLoading }: ProductFormProps) => {
  const { t } = useTranslation();
  const { error: toastError } = useToast();

  const [localUnits, setLocalUnits] = useState<ProductUnitDto[]>(initialData?.productUnits || []);
  const [localVariants, setLocalVariants] = useState<ProductVariantData[]>(initialData?.variants || []);

  useEffect(() => {
    if (initialData?.productUnits) {
        setLocalUnits(initialData.productUnits);
    }
    if (initialData?.variants) {
        setLocalVariants(initialData.variants);
    }
  }, [initialData]);

  const handleSubmit = async (data: ProductFormData) => {
    try {
        // Strip API base URL from existing images to send relative paths (fixes update issue)
        const apiBase = import.meta.env.VITE_API_URL || 'http://localhost:5176/api/v1';
        const root = apiBase.replace(/\/api\/v1\/?$/, '');
        
        const processedImages = data.images?.map(img => {
            if (img.startsWith('data:')) return img; // Keep new base64 uploads
            if (root && img.startsWith(root)) {
                 return img.substring(root.length); // Remove http://domain to get /uploads/...
            }
            return img;
        });

        const baseRow: ProductUnitDto = {
            unitName: data.baseUnit || 'Cái',
            conversionRate: 1,
            price: data.price,
            isBaseUnit: true,
            isActive: true
        };
        const conversionUnits = localUnits.filter(u => !u.isBaseUnit && (u.unitName !== data.baseUnit || u.conversionRate !== 1));
        const payload = { 
            ...data, 
            images: processedImages,
            productUnits: [baseRow, ...conversionUnits].map(u => ({
                unitName: u.unitName,
                conversionRate: u.conversionRate,
                price: u.price,
                isBaseUnit: u.isBaseUnit,
                isActive: u.isActive
            })),
            variants: localVariants.map(v => ({
                sku: v.sku,
                attributes: typeof v.attributes === 'string' ? v.attributes : JSON.stringify(v.attributes),
                price: v.price,
                stockQuantity: v.stockQuantity
            }))
        };
        await onSubmit(payload as any);
    } catch (err) {
        console.error("Failed to save product", err);
    }
  };

  const defaultValues: ProductFormData = useMemo(() => ({
    name: initialData?.name || '',
    price: initialData?.price || 0,
    wholesalePrice: initialData?.wholesalePrice || 0,
    description: initialData?.description || '',
    brandCode: initialData?.brandCode || '',
    baseUnit: initialData?.baseUnit || 'Cái',
    isActive: initialData?.isActive ?? true,
    details: initialData?.details || [],
    categoryCode: initialData?.categoryCode || '',
    stockQuantity: initialData?.stockQuantity || 0,
    costPrice: initialData?.costPrice ?? initialData?.originalPrice ?? 0,
    images: (() => {
        const directImages = initialData?.images?.map(img => getImageUrl(img));
        if (directImages && directImages.length > 0) return directImages;
        
        const prodImages = initialData?.productImages?.map(img => getImageUrl(img.imageURL || (img as any).imageUrl));
        if (prodImages && prodImages.length > 0) return prodImages;
        
        if (initialData?.imageURL) return [getImageUrl(initialData.imageURL)];
        
        return [];
    })(),
    code: initialData?.code || '',
    vatRate: initialData?.vatRate || 0,
    minStockLevel: initialData?.minStockLevel || 0,
    binLocation: initialData?.binLocation || '',
    countryOfOrigin: initialData?.countryOfOrigin || '',
    supplierCode: initialData?.supplierCode || '',
    variants: initialData?.variants || [],
  }), [initialData]);

  const [isUploading, setIsUploading] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const specSuggestions = ["Công suất", "Điện áp", "Lưu lượng", "Phi (Ø)", "Đường kính", "Độ dày", "Chất liệu", "Màu sắc"];

  const fetchCategories = async (params: { pageIndex: number; pageSize: number; search?: string }) => {
      const res = await categoryService.search({
          pageIndex: params.pageIndex, pageSize: params.pageSize, search: params.search,
          searchField: 'Name', sortBy: 'Code',
          filters: [{ field: 'IsActive', value: true, operator: SearchCondition.Equal }],
          fields: ['Code', 'Name']
      });
      return { items: (res.data?.items || []).map(x => ({ value: x.code, label: x.name })), totalItems: res.data?.totalItems || 0 };
  };

  const fetchSuppliers = async (params: { pageIndex: number; pageSize: number; search?: string }) => {
      const res = await supplierService.search({
          pageIndex: params.pageIndex, pageSize: params.pageSize, search: params.search,
          searchField: 'Name', sortBy: 'Code',
          filters: [{ field: 'IsActive', value: true, operator: SearchCondition.Equal }],
          fields: ['Code', 'Name']
      });
      return { items: (res.data?.items || []).map(x => ({ value: x.code, label: x.name })), totalItems: res.data?.totalItems || 0 };
  };

  const fetchUnits = async (params: { pageIndex: number; pageSize: number; search?: string }) => {
    const res = await unitService.search({
        pageIndex: params.pageIndex, pageSize: params.pageSize, search: params.search,
        searchField: 'Name', sortBy: 'Code',
        filters: [{ field: 'IsActive', value: true, operator: SearchCondition.Equal }],
        fields: ['Code', 'Name']
    });
    return { items: (res.data?.items || []).map(x => ({ value: x.name, label: x.name })), totalItems: res.data?.totalItems || 0 };
  };

  const fetchBrands = async (params: { pageIndex: number; pageSize: number; search?: string }) => {
    const res = await brandService.search({
        pageIndex: params.pageIndex, pageSize: params.pageSize, search: params.search,
        searchField: 'Name', sortBy: 'Code',
        filters: [{ field: 'IsActive', value: true, operator: SearchCondition.Equal }],
        fields: ['Code', 'Name']
    });
    return { items: (res.data?.items || []).map(x => ({ value: x.code, label: x.name })), totalItems: res.data?.totalItems || 0 };
  };

  const fieldGroups: FieldGroup[] = [
    {
      title: t('admin.groups.general'),
      fields: [
        { name: 'name', type: 'text', label: t('common.fields.name'), required: true, colSpan: 12, placeholder: t('common.placeholders.productName') },
        { name: 'description', type: 'textarea', label: t('common.fields.description'), colSpan: 12, placeholder: t('common.placeholders.productDescription') }
      ]
    },
    {
        title: t('admin.groups.images'),
        fields: [
            { 
                name: 'images', type: 'custom', label: t('common.fields.image'), colSpan: 12,
                render: (form: UseFormReturn<ProductFormData>) => {
                    const images = form.watch('images') || [];
                    const onDrop = async (acceptedFiles: File[]) => {
                        if (acceptedFiles.length > 0) {
                            setIsUploading(true);
                            try {
                                const promises = acceptedFiles.map((file) => new Promise<string>((resolve, reject) => {
                                    const reader = new FileReader();
                                    reader.onload = () => resolve(reader.result as string);
                                    reader.onerror = reject;
                                    reader.readAsDataURL(file);
                                }));
                                const results = await Promise.all(promises);
                                const uniqueResults = results.filter(newImg => !images.includes(newImg));
                                form.setValue('images', [...images, ...uniqueResults], { shouldValidate: true });
                            } catch (err) { toastError(t('common.messages.errorOccurred')); } finally { setIsUploading(false); }
                        }
                    };
                    const { getRootProps, getInputProps, isDragActive } = useDropzone({ onDrop, accept: { 'image/*': [] } });
                    return (
                        <div className="space-y-4">
                            <div {...getRootProps()} className={`border-2 border-dashed rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer transition-all bg-slate-50 dark:bg-slate-900/50 ${isDragActive ? 'border-accent-primary bg-accent-primary/5' : 'border-border-color hover:border-accent-primary/50'}`}>
                                <input {...getInputProps()} />
                                <div className="w-12 h-12 bg-accent-primary/5 text-accent-primary rounded-full flex items-center justify-center mb-3"><Upload size={20} /></div>
                                <p className="text-sm font-medium text-primary">{isUploading ? t('common.loading') : t('common.dragOrClick')}</p>
                            </div>
                            {images.length > 0 && (
                                <div className="grid grid-cols-4 sm:grid-cols-6 gap-4">
                                    {images.map((img: string, idx: number) => (
                                        <div key={idx} className="relative aspect-square rounded-lg border border-border-color overflow-hidden group bg-white cursor-pointer" onClick={() => setPreviewImage(img)}>
                                            <img src={img} className="w-full h-full object-cover" />
                                            <button type="button" onClick={(e) => { e.stopPropagation(); form.setValue('images', images.filter((_, i) => i !== idx)); }} className="absolute inset-0 bg-black/40 text-white opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center backdrop-blur-sm"><X size={16} /></button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    );
                }
            }
        ]
    },
    {
        title: t('admin.groups.pricing'),
        fields: [
            {
                name: 'pricingSection', type: 'custom', label: '', colSpan: 12,
                render: (form: UseFormReturn<ProductFormData>) => {
                    const price = form.watch('price') || 0;
                    const wholesalePrice = form.watch('wholesalePrice') || 0;
                    const costPrice = form.watch('costPrice') || 0;
                    const vatRate = form.watch('vatRate') || 0;
                    
                    // Calculate profit
                    const profit = price - costPrice;
                    const profitMargin = price > 0 ? ((profit / price) * 100).toFixed(1) : '0';
                    
                    // Format number with thousand separators
                    const formatNumber = (num: number) => num.toLocaleString('vi-VN');
                    const parseNumber = (str: string) => {
                        const cleaned = str.replace(/[^\d]/g, '');
                        return cleaned ? parseInt(cleaned, 10) : 0;
                    };
                    
                    // Validation warnings
                    const warnings: string[] = [];
                    if (wholesalePrice > 0 && wholesalePrice >= price) {
                        warnings.push('⚠️ Giá bán sỉ phải nhỏ hơn Giá lẻ');
                    }
                    if (costPrice > 0 && costPrice >= price) {
                        warnings.push('⚠️ Giá vốn phải nhỏ hơn Giá bán');
                    }
                    
                    // Auto-calculate price from cost + VAT when cost or VAT changes
                    const handleCostChange = (newCost: number) => {
                        form.setValue('costPrice', newCost, { shouldValidate: true });
                        if (newCost > 0) {
                            const calculatedPrice = Math.round(newCost * (1 + vatRate / 100));
                            form.setValue('price', calculatedPrice, { shouldValidate: true });
                        }
                    };
                    
                    const handleVatChange = (newVat: number) => {
                        form.setValue('vatRate', newVat, { shouldValidate: true });
                        if (costPrice > 0) {
                            const calculatedPrice = Math.round(costPrice * (1 + newVat / 100));
                            form.setValue('price', calculatedPrice, { shouldValidate: true });
                        }
                    };
                    
                    return (
                        <div className="space-y-4">
                            <div className="grid grid-cols-12 gap-4">
                                {/* Giá vốn (INPUT - primary) */}
                                <div className="col-span-3">
                                    <label className="block text-sm font-medium text-primary mb-1.5">
                                        {t('common.fields.costPrice')} <span className="text-red-500">*</span>
                                    </label>
                                    <Input
                                        value={formatNumber(costPrice)}
                                        onChange={(e) => handleCostChange(parseNumber(e.target.value))}
                                        placeholder={t('common.placeholders.enterPrice')}
                                        className="text-right"
                                    />
                                </div>
                                
                                {/* Giá bán sỉ (INPUT) */}
                                <div className="col-span-3">
                                    <label className="block text-sm font-medium text-primary mb-1.5">
                                        {t('common.fields.wholesalePrice')} / Giá thầu
                                    </label>
                                    <Input
                                        value={formatNumber(wholesalePrice)}
                                        onChange={(e) => form.setValue('wholesalePrice', parseNumber(e.target.value), { shouldValidate: true })}
                                        placeholder={t('common.placeholders.enterPrice')}
                                        className={`text-right ${wholesalePrice >= price && wholesalePrice > 0 ? 'border-yellow-500' : ''}`}
                                    />
                                </div>
                                
                                {/* VAT (INPUT) */}
                                <div className="col-span-2">
                                    <label className="block text-sm font-medium text-primary mb-1.5">
                                        {t('common.fields.vatPercent', 'VAT (%)')}
                                    </label>
                                    <Input
                                        type="number"
                                        value={vatRate}
                                        onChange={(e) => handleVatChange(parseFloat(e.target.value) || 0)}
                                        placeholder="0"
                                        className="text-right"
                                    />
                                </div>
                                
                                {/* Giá bán lẻ (CALCULATED - can be overridden) */}
                                <div className="col-span-4">
                                    <label className="block text-sm font-medium text-primary mb-1.5">
                                        {t('common.fields.price')} <span className="text-xs text-secondary">(tự tính)</span>
                                    </label>
                                    <Input
                                        value={formatNumber(price)}
                                        onChange={(e) => form.setValue('price', parseNumber(e.target.value), { shouldValidate: true })}
                                        placeholder={t('common.placeholders.enterPrice')}
                                        className="text-right font-semibold bg-green-50 dark:bg-green-900/20 border-green-300"
                                    />
                                </div>
                            </div>
                            
                            {/* Profit display */}
                            <div className="flex items-center gap-4 p-3 rounded-lg bg-slate-50 dark:bg-slate-900/50 border border-border-color">
                                <div className="flex-1">
                                    <span className="text-sm text-secondary">Lợi nhuận gộp:</span>
                                    <span className={`ml-2 font-semibold ${profit >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                                        {formatNumber(profit)} đ
                                    </span>
                                    <span className="ml-2 text-sm text-tertiary">({profitMargin}%)</span>
                                </div>
                            </div>
                            
                            {/* Validation warnings */}
                            {warnings.length > 0 && (
                                <div className="text-sm text-yellow-600 dark:text-yellow-400 space-y-1">
                                    {warnings.map((w, i) => <div key={i}>{w}</div>)}
                                </div>
                            )}
                        </div>
                    );
                }
            }
        ]
    },
    {
        title: t('admin.groups.inventory'),
        fields: [
            { name: 'stockQuantity', type: 'number', label: t('common.fields.stock'), required: true, colSpan: 6, placeholder: t('common.placeholders.enterQuantity') },
            { name: 'code', type: 'text', label: t('common.fields.code'), disabled: true, colSpan: 6, placeholder: t('common.placeholders.enterCode') },
            { name: 'minStockLevel', type: 'number', label: t('common.fields.minStock'), colSpan: 4, placeholder: '0' },
            { 
                name: 'baseUnit', type: 'custom', label: t('common.fields.unit'), colSpan: 4,
                render: (form: UseFormReturn<ProductFormData>) => (
                    <Controller control={form.control} name="baseUnit" render={({ field, fieldState }) => (
                        <LazySelect {...field} value={field.value || ''} onChange={field.onChange} label={t('common.fields.unit')} error={fieldState.error?.message} queryKeyPrefix="units" fetchFn={fetchUnits} placeholder={t('common.placeholders.select')} initialLabel={field.value} />
                    )} />
                )
            },
            { name: 'binLocation', type: 'text', label: t('common.fields.location'), colSpan: 4, placeholder: t('common.placeholders.enterLocation', 'Kệ A...') }
        ]
    },
    {
        title: t('admin.groups.specs'),
        fields: [
            {
                name: 'details', type: 'custom', label: t('common.fields.specs'), colSpan: 12,
                render: (form: UseFormReturn<ProductFormData>) => {
                    const details = form.watch('details') || [];
                    const addDetail = (type: 'SPEC' | 'LOGISTICS' | 'RELATION' | 'IMAGE') => form.setValue('details', [...details, { detailType: type, specName: '', specValue: '' }]);
                    const updateDetail = (idx: number, f: keyof ProductDetail, val: string) => {
                        const newDetails = [...details];
                        newDetails[idx] = { ...newDetails[idx], [f]: val } as ProductDetail;
                        form.setValue('details', newDetails);
                    };
                    return (
                        <div className="space-y-4">
                            <div className="flex gap-2 mb-2">
                                <Button type="button" size="sm" variant="outline" onClick={() => addDetail('SPEC')}>+ {t('common.fields.specs')}</Button>
                                <Button type="button" size="sm" variant="outline" onClick={() => addDetail('LOGISTICS')}>+ Logistics</Button>
                            </div>
                            <div className="space-y-3 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-border-color">
                                {details.length === 0 ? <p className="text-center text-sm text-tertiary py-4">{t('common.noData')}</p> : details.map((detail, idx: number) => {
                                    const dType = detail.detailType || 'SPEC';
                                    const badgeColor = dType === 'SPEC' ? 'primary' : dType === 'LOGISTICS' ? 'success' : 'warning';
                                    const badgeLabel = dType === 'SPEC' ? t('common.types.spec', 'SPEC') : dType === 'LOGISTICS' ? t('common.types.logistics', 'LOGIS') : t('common.types.tag', 'TAG');
                                    return (
                                    <div key={idx} className="flex items-center gap-3">
                                        <Badge color={badgeColor} className="w-20 justify-center">{badgeLabel}</Badge>
                                        <Input className="flex-1 h-9 text-sm" placeholder={t('common.fields.name')} value={detail.specName} onChange={(e) => updateDetail(idx, 'specName', e.target.value)} list={`spec-suggestions-${idx}`} /><datalist id={`spec-suggestions-${idx}`}>{specSuggestions.map(s => <option key={s} value={s} />)}</datalist>
                                        <Input className="flex-1 h-9 text-sm" placeholder={t('common.fields.value')} value={detail.specValue} onChange={(e) => updateDetail(idx, 'specValue', e.target.value)} />
                                        <button type="button" onClick={() => form.setValue('details', details.filter((_, i) => i !== idx))} className="text-slate-400 hover:text-red-500"><X size={18} /></button>
                                    </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                }
            }
        ]
    },
    {
        title: t('admin.groups.units'),
        fields: [
            {
                name: 'unitsSection', type: 'custom', label: '', colSpan: 12,
                render: (form: UseFormReturn<ProductFormData>) => (
                    <ProductUnitsManager 
                        baseUnitName={form.watch('baseUnit')} 
                        baseUnitPrice={form.watch('price')} 
                        units={localUnits}
                        onChange={(newUnits) => setLocalUnits(newUnits)}
                        fetchUnitOptions={fetchUnits}
                    />
                )
            }
        ]
    },
    {
        title: t('product.variants'),
        fields: [
            {
                name: 'variants', type: 'custom', label: '', colSpan: 12,
                render: (form: UseFormReturn<ProductFormData>) => (
                    <ProductVariantManager 
                        basePrice={form.watch('price')}
                        productCode={form.watch('code')}
                        initialVariants={localVariants}
                        onChange={(newVariants) => setLocalVariants(newVariants)}
                    />
                )
            }
        ]
    }
  ];

  const fieldGroupsSidebar: FieldGroup[] = [
    {
        title: t('admin.groups.organization'),
        fields: [
            { name: 'isActive', type: 'switch', label: t('common.fields.status'), description: t('admin.statusHint'), colSpan: 12 },
            { 
                name: 'categoryCode', type: 'custom', label: t('common.fields.category'), required: true, colSpan: 12,
                render: (form: UseFormReturn<ProductFormData>) => (
                    <Controller control={form.control} name="categoryCode" render={({ field, fieldState }) => (
                        <LazySelect {...field} value={field.value || ''} onChange={field.onChange} label={t('common.fields.category')} error={fieldState.error?.message} required queryKeyPrefix="categories" fetchFn={fetchCategories} placeholder={t('common.placeholders.select')} initialLabel={initialData?.categoryName} />
                    )} />
                )
            },
            { 
                name: 'brandCode', type: 'custom', label: t('common.fields.brand'), colSpan: 12, 
                render: (form: UseFormReturn<ProductFormData>) => (
                    <Controller control={form.control} name="brandCode" render={({ field, fieldState }) => (
                        <LazySelect {...field} value={field.value || ''} onChange={field.onChange} label={t('common.fields.brand')} error={fieldState.error?.message} queryKeyPrefix="brands" fetchFn={fetchBrands} placeholder={t('common.placeholders.select')} initialLabel={initialData?.brandName} />
                    )} />
                )
            },
            { 
                name: 'supplierCode', type: 'custom', label: t('common.fields.supplier'), colSpan: 12, 
                render: (form: UseFormReturn<ProductFormData>) => (
                    <Controller control={form.control} name="supplierCode" render={({ field, fieldState }) => (
                        <LazySelect {...field} value={field.value || ''} onChange={field.onChange} label={t('common.fields.supplier')} error={fieldState.error?.message} queryKeyPrefix="suppliers" fetchFn={fetchSuppliers} placeholder={t('common.placeholders.select')} initialLabel={initialData?.supplierName} />
                    )} />
                )
            },
            { name: 'countryOfOrigin', type: 'text', label: t('common.fields.origin'), colSpan: 12, placeholder: t('common.placeholders.enterOrigin', 'VD: Vietnam') }
        ]
    }
  ];

  return (
    <div className="w-full">
        <BaseForm<ProductFormData> schema={productSchema} defaultValues={defaultValues} fieldGroups={[...fieldGroups, ...fieldGroupsSidebar]} onSubmit={handleSubmit} onCancel={onCancel} isLoading={isLoading} layout="tabs" submitLabel={t('common.save')} />
        
        {previewImage && createPortal(
            <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={() => setPreviewImage(null)}>
                <div className="relative max-w-full max-h-full flex flex-col items-center justify-center">
                    <img src={previewImage} alt="Full size preview" className="max-w-full max-h-[90vh] object-contain rounded-lg shadow-2xl" onClick={(e) => e.stopPropagation()} />
                    <button type="button" onClick={() => setPreviewImage(null)} className="absolute top-4 right-4 p-2 bg-white/10 text-white rounded-full hover:bg-white/20 transition-colors backdrop-blur-md"><X size={24} /></button>
                </div>
            </div>, document.body
        )}
    </div>
  );
};


export default ProductForm;

