import { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Mail, Lock, Eye, EyeOff, ArrowRight } from 'lucide-react';
import { Button, Input } from '@/components/ui';
import { useAuthStore, useToast } from '@/store';
import { UserRole, UserStatus } from '@/types';
import { authService } from '@/services/authService';
import { AuthLayout } from '@/layouts/AuthLayout';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { createSchemas } from '@/utils/schemas';
import { signInWithPopup, type AuthProvider } from 'firebase/auth';
import { auth, googleProvider, facebookProvider } from '@/config/firebase';

export const LoginPage = () => {
  const { t } = useTranslation();
  const { loginSchema } = createSchemas(t);
  
  interface LoginFormData {
    email: string;
    password: string;
    remember: boolean;
  }

  const navigate = useNavigate();
  const location = useLocation();
  const { login, isAuthenticated, user } = useAuthStore();
  const toast = useToast();
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const {
      register,
      handleSubmit,
      setValue,
      formState: { errors },
  } = useForm<LoginFormData>({
      resolver: zodResolver(loginSchema),
      defaultValues: {
          email: '',
          password: '',
          remember: false,
      }
  });

  // Redirect if already authenticated
  useEffect(() => {
    if (isAuthenticated && user) {
        if (String(user.role).toLowerCase() === 'admin') { 
            navigate('/admin', { replace: true });
        } else {
            navigate('/', { replace: true });
        }
    }
  }, [isAuthenticated, user, navigate]);

  /* Load saved email if 'Remember Me' was checked */
  useEffect(() => {
      const isRemembered = localStorage.getItem('vnvt-remember') === 'true';
      if (isRemembered) {
          const savedEmail = localStorage.getItem('vnvt-email');
          if (savedEmail) {
              setValue('email', savedEmail);
              setValue('remember', true);
          }
      }
  }, [setValue]);

  const from = (location.state as { from?: string })?.from || '/';

  const onSubmit = async (data: LoginFormData) => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await authService.login({
        username: data.email,
        password: data.password,
      });

      if (response.success && response.data) {
        const { token, refreshToken, user } = response.data;

        // Handle Remember Me preference
        if (data.remember) {
            localStorage.setItem('vnvt-remember', 'true');
            localStorage.setItem('vnvt-email', data.email);
        } else {
            localStorage.removeItem('vnvt-remember');
            localStorage.removeItem('vnvt-email');
        }

        login(
          {
            code: user.code,
            email: user.email,
            fullName: user.fullName || user.username,
            role: (user.role as UserRole) || UserRole.Customer,
            status: UserStatus.Active,
            createdAt: new Date().toISOString(),
          },
          token,
          refreshToken
        );

        toast.success(t('messages.loginSuccess'));
        
        // Redirect to admin if admin role, otherwise to original destination
        // backend returns PascalCase 'Admin', Enum is 'Admin'
        if (String(user.role).toLowerCase() === 'admin') { 
            navigate('/admin', { replace: true });
        } else {
            navigate(from, { replace: true });
        }
      } else {
        setError(response.message || 'Tên đăng nhập hoặc mật khẩu không đúng');
      }
    } catch (err) {
      toast.error(t('messages.error'));
      setError('Có lỗi xảy ra. Vui lòng thử lại.');
      console.error('Login error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSocialLogin = async (provider: string, authProvider: AuthProvider) => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await signInWithPopup(auth, authProvider);
      const token = await result.user.getIdToken();
      
      const response = await authService.externalLogin(provider, token);
      
      if (response.success && response.data) {
        const { token: accessToken, refreshToken, user: userData } = response.data;
        
        login(
          {
            code: userData.code,
            email: userData.email,
            fullName: userData.fullName || userData.username,
            role: (userData.role as UserRole) || UserRole.Customer,
            status: UserStatus.Active,
            createdAt: new Date().toISOString(),
            avatar: userData.avatar
          },
          accessToken,
          refreshToken
        );

        toast.success(t('messages.loginSuccess'));
        
        if (String(userData.role).toLowerCase() === 'admin') { 
            navigate('/admin', { replace: true });
        } else {
            navigate(from, { replace: true });
        }
      } else {
        setError(response.message || t('messages.error'));
      }
    } catch (err: unknown) {
      console.error(`${provider} login error:`, err);
      const isPopupClosed = err instanceof Error && (err as any).code === 'auth/popup-closed-by-user';
      if (!isPopupClosed) {
        toast.error(t('messages.error'));
        setError(t('messages.error'));
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthLayout title={t('login.title')} subtitle={t('login.subtitle')}>
      <div className="grid grid-cols-2 gap-4 mb-6">
        {/* Google Login */}
        <button 
          onClick={() => handleSocialLogin('google', googleProvider)}
          disabled={isLoading}
          className="flex items-center justify-center gap-2 py-3 px-4 border rounded-xl font-medium hover:bg-gray-50 transition-colors disabled:opacity-50"
        >
          <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" alt="Google" className="w-5 h-5" />
          <span>Google</span>
        </button>

        {/* Facebook Login */}
        <button 
          onClick={() => handleSocialLogin('facebook', facebookProvider)}
          disabled={isLoading}
          className="flex items-center justify-center gap-2 py-3 px-4 border rounded-xl font-medium hover:bg-gray-50 transition-colors disabled:opacity-50"
        >
          <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/facebook.svg" alt="Facebook" className="w-5 h-5" />
          <span>Facebook</span>
        </button>
      </div>

      <div className="flex items-center gap-4 mb-6">
        <hr className="flex-1" />
        <span className="text-tertiary text-sm">{t('login.or')}</span>
        <hr className="flex-1" />
      </div>

      {/* Form */}
      <form onSubmit={handleSubmit(onSubmit)} className="space-y-4" noValidate>
        {error && (
          <div className="p-3 border border-error bg-error/10 text-error text-sm rounded-lg">
            {error}
          </div>
        )}
        <Input
          label="Email"
          type="email"
          placeholder="email@example.com"
          {...register('email')}
          leftIcon={<Mail size={18} />}
          required
          error={errors.email?.message}
          data-testid="login-email"
        />

        <Input
          label={t('login.password')}
          type={showPassword ? 'text' : 'password'}
          placeholder="••••••••"
          {...register('password')}
          leftIcon={<Lock size={18} />}
          rightIcon={
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="flex items-center justify-center p-1 text-slate-400 opacity-50 hover:opacity-100 hover:text-primary focus:outline-none transition-all"
              tabIndex={-1}
            >
              {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          }
          required
          error={errors.password?.message}
          data-testid="login-password"
        />

        <div className="flex items-center justify-between">
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              {...register('remember')}
              className="w-4 h-4 rounded"
            />
            <span className="text-sm text-secondary">{t('login.remember')}</span>
          </label>
          <Link to="/forgot-password" className="text-sm text-primary hover:underline">
            {t('login.forgot')}
          </Link>
        </div>

        <Button
          type="submit"
          fullWidth
          size="lg"
          isLoading={isLoading}
          rightIcon={<ArrowRight size={20} />}
          data-testid="login-submit"
        >
          {t('login.submit')}
        </Button>
      </form>

      {/* Register Link */}
      <p className="text-center mt-6 text-secondary">
        {t('login.noAccount')}{' '}
        <Link to="/register" className="text-primary font-semibold hover:underline">
          {t('login.register')}
        </Link>
      </p>
    </AuthLayout>
  );
};

export default LoginPage;

import { useState, useEffect } from 'react';
import { useSearchParams, useNavigate, Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Lock, Eye, EyeOff, Loader2, CheckCircle, AlertCircle } from 'lucide-react';
import { Button, Input } from '@/components/ui';
import { authService } from '@/services/authService';
import { useToast } from '@/store';

export const ResetPasswordPage = () => {
    const { t } = useTranslation();
    const { success, error: toastError } = useToast();
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();

    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [isSuccess, setIsSuccess] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const email = searchParams.get('email');
    const token = searchParams.get('token');

    useEffect(() => {
        if (!email || !token) {
            setError(t('auth.resetPassword.invalidLink'));
        }
    }, [email, token, t]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        
        if (password !== confirmPassword) {
            toastError(t('validation.passwordMismatch'));
            return;
        }

        if (!email || !token) return;

        setIsLoading(true);
        setError(null);
        
        try {
            const response = await authService.resetPassword({
                email,
                token,
                newPassword: password
            });

            if (response.success) {
                setIsSuccess(true);
                success(t('auth.resetPassword.success'));
                setTimeout(() => navigate('/login'), 3000);
            } else {
                setError(response.message || t('messages.error'));
                toastError(response.message || t('messages.error'));
            }
        } catch (err: unknown) {
            const msg = err instanceof Error ? err.message : t('messages.error');
            setError(msg);
            toastError(msg);
        } finally {
            setIsLoading(false);
        }
    };

    if (isSuccess) {
        return (
            <div className="min-h-[60vh] flex items-center justify-center px-4">
                <div className="max-w-md w-full bg-primary p-8 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800 text-center space-y-6">
                    <CheckCircle className="w-16 h-16 text-emerald-500 mx-auto" />
                    <h2 className="text-2xl font-bold">{t('auth.resetPassword.success')}</h2>
                    <p className="text-secondary">
                        {t('auth.resetPassword.successDesc')}
                    </p>
                    <Link to="/login" className="block w-full py-2.5 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 transition-colors text-center">
                        {t('auth.resetPassword.backToLogin')}
                    </Link>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-[60vh] flex items-center justify-center px-4">
            <div className="max-w-md w-full bg-primary p-8 rounded-2xl shadow-xl border border-slate-100 dark:border-slate-800">
                <div className="text-center mb-8">
                    <h1 className="text-3xl font-bold mb-2">{t('auth.resetPassword.title')}</h1>
                    <p className="text-secondary">{t('auth.resetPassword.subtitle')}</p>
                </div>

                {error && (
                    <div className="mb-6 p-4 bg-rose-50 dark:bg-rose-900/20 border border-rose-100 dark:border-rose-900/30 rounded-lg flex items-start gap-3 text-rose-600 dark:text-rose-400 text-sm">
                        <AlertCircle size={18} className="shrink-0 mt-0.5" />
                        <p>{error}</p>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-5">
                    <Input
                        label={t('auth.resetPassword.newPassword')}
                        type={showPassword ? "text" : "password"}
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="••••••••"
                        leftIcon={<Lock size={18} />}
                        rightIcon={
                          <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="flex items-center justify-center p-1 text-slate-400 opacity-50 hover:opacity-100 hover:text-primary transition-all focus:outline-none"
                            tabIndex={-1}
                          >
                            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                          </button>
                        }
                        isRequired
                        disabled={!!error || isLoading}
                    />

                    <Input
                        label={t('auth.resetPassword.confirmPassword')}
                        type={showPassword ? "text" : "password"}
                        value={confirmPassword}
                        onChange={(e) => setConfirmPassword(e.target.value)}
                        placeholder="••••••••"
                        leftIcon={<Lock size={18} />}
                        rightIcon={
                          <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="flex items-center justify-center p-1 text-slate-400 opacity-50 hover:opacity-100 hover:text-primary transition-all focus:outline-none"
                            tabIndex={-1}
                          >
                            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                          </button>
                        }
                        isRequired
                        disabled={!!error || isLoading}
                    />

                    <Button 
                        type="submit" 
                        fullWidth 
                        isLoading={isLoading} 
                        disabled={!!error || !password || password !== confirmPassword}
                    >
                        {t('auth.resetPassword.submit')}
                    </Button>
                </form>

                <div className="mt-8 pt-6 border-t text-center">
                    <Link 
                        to="/login" 
                        className="text-sm text-secondary hover:text-primary transition-colors font-medium"
                    >
                        {t('auth.resetPassword.backToLogin')}
                    </Link>
                </div>
            </div>
        </div>
    );
};

export default ResetPasswordPage;

