  });
});

import { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui';
import { addressService, type AddressDto, type CreateAddressRequest } from '@/services/userService';
import { useToast } from '@/store';
import { MapPin, Star, Edit2, Trash2, CheckCircle, X, Plus } from 'lucide-react';
import { z } from 'zod';
import { createSchemas } from '@/utils/schemas';
import { ConfirmDialog } from '@/components/ui/ConfirmDialog';
import { BaseForm, type FieldGroup } from '@/components/common/BaseForm';

const AddressesContent = () => {
    const { t } = useTranslation();
    const { addressSchema } = createSchemas(t);
    type AddressFormData = z.infer<typeof addressSchema>;

    const emptyForm: AddressFormData = {
        fullName: '',
        phone: '',
        category: t('addresses.form.options.home'),
        street: '',
        ward: '',
        district: '',
        city: '',
        isDefault: false
    };

    const toast = useToast();
    const [addresses, setAddresses] = useState<AddressDto[]>([]);
    const [showModal, setShowModal] = useState(false);
    const [showConfirmModal, setShowConfirmModal] = useState(false);
    const [addressToDelete, setAddressToDelete] = useState<string | null>(null);
    const [editingCode, setEditingCode] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [tempFormData, setTempFormData] = useState<AddressFormData | null>(null);

    const fetchAddresses = async () => {
        const res = await addressService.search({});
        if (res.success && res.data) {
            setAddresses(res.data.items || []);
        }
    };

    useEffect(() => {
        fetchAddresses();
    }, []);

    const openAddModal = () => {
        setTempFormData(emptyForm);
        setEditingCode(null);
        setShowModal(true);
    };

    const openEditModal = (addr: AddressDto) => {
        const parts = (addr.addressLine || '').split(',').map((p: string) => p.trim());
        const street = parts[0] || '';
        const ward = parts.length > 2 ? parts[1] : '';
        const district = parts.length > 2 ? parts[2] : (parts[1] || '');

        setTempFormData({
            fullName: addr.fullName || '',
            phone: addr.phone || '',
            category: addr.category || t('addresses.form.options.home'),
            street: street,
            ward: ward,
            district: district,
            city: addr.city || '',
            isDefault: addr.isDefault || false
        });
        setEditingCode(addr.code);
        setShowModal(true);
    };

    const handleFormSubmit = (data: AddressFormData) => {
        setTempFormData(data);
        setShowConfirmModal(true);
    };

    const onConfirmSubmit = async () => {
        if (!tempFormData) return;
        
        const addressPayload: CreateAddressRequest = {
            fullName: tempFormData.fullName,
            phone: tempFormData.phone,
            category: tempFormData.category,
            addressLine: [tempFormData.street, tempFormData.ward, tempFormData.district].filter((p: string | undefined): p is string => !!p?.trim()).join(', '),
            city: tempFormData.city,
            state: '', 
            postalCode: '',
            country: 'Vietnam',
            isDefault: tempFormData.isDefault
        };

        setLoading(true);
        try {
            if (editingCode) {
                await addressService.update(editingCode, addressPayload);
                toast.success(t('addresses.messages.updateSuccess'));
            } else {
                await addressService.create(addressPayload);
                toast.success(t('addresses.messages.createSuccess'));
            }
            fetchAddresses();
            setShowModal(false);
            setShowConfirmModal(false);
        } catch (e) {
            console.error(e);
            toast.error(t('addresses.messages.saveError'));
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (code: string) => {
        setAddressToDelete(code);
    };

    const confirmDelete = async () => {
        if (!addressToDelete) return;
        
        setLoading(true);
        try {
            await addressService.delete(addressToDelete);
            toast.success(t('addresses.messages.deleteSuccess'));
            fetchAddresses();
            setAddressToDelete(null);
        } catch (e) {
            console.error(e);
            toast.error(t('addresses.messages.deleteError'));
        } finally {
            setLoading(false);
        }
    };

    const setAsDefault = async (addr: AddressDto) => {
        try {
            await addressService.update(addr.code, { 
                fullName: addr.fullName,
                phone: addr.phone,
                category: addr.category,
                addressLine: addr.addressLine,
                city: addr.city,
                isDefault: true 
            });
            toast.success(t('addresses.messages.setDefaultSuccess'));
            fetchAddresses();
        } catch (e) {
            console.error(e);
            toast.error(t('addresses.messages.saveError'));
        }
    };

    const fieldGroups: FieldGroup[] = useMemo(() => [
        {
            title: t('addresses.form.groups.contact'),
            fields: [
                { name: 'fullName', type: 'text', label: t('addresses.form.labels.fullName'), required: true, colSpan: 12, placeholder: t('addresses.form.placeholders.fullName'), size: 'lg' },
                { name: 'phone', type: 'phone', label: t('addresses.form.labels.phone'), required: true, colSpan: 12, placeholder: t('common.placeholders.phone'), size: 'lg' },
                { 
                    name: 'category', 
                    type: 'select', 
                    label: t('addresses.form.labels.category'), 
                    required: true, 
                    colSpan: 12,
                    size: 'lg',
                    options: [
                        { value: 'Nhà riêng', label: t('addresses.form.options.home', 'Nhà riêng') },
                        { value: 'Văn phòng', label: t('addresses.form.options.office', 'Văn phòng') },
                        { value: 'Khác', label: t('addresses.form.options.other', 'Khác') },
                    ]
                },
            ]
        },
        {
            title: t('addresses.form.groups.area'),
            fields: [
                { name: 'city', type: 'text', label: t('addresses.form.labels.city'), required: true, colSpan: 12, placeholder: t('addresses.form.placeholders.city'), size: 'lg' },
                { name: 'district', type: 'text', label: t('addresses.form.labels.district'), required: true, colSpan: 6, size: 'lg' },
                { name: 'ward', type: 'text', label: t('addresses.form.labels.ward'), colSpan: 6, size: 'lg' },
            ]
        },
        {
            title: t('addresses.form.groups.details'),
            fields: [
                { name: 'street', type: 'textarea', label: t('addresses.form.labels.street'), required: true, colSpan: 12, rows: 4, placeholder: t('addresses.form.placeholders.street'), size: 'lg' },
                { name: 'isDefault', type: 'switch', label: t('addresses.form.labels.isDefault'), description: t('addresses.form.labels.isDefaultDesc'), colSpan: 12 },
            ]
        }
    ], [t]);

    return (
        <div className="bg-white rounded-2xl shadow-sm p-8 border border-gray-100 dark:bg-slate-900 dark:border-slate-800">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900 dark:text-white uppercase tracking-tight">{t('addresses.title')}</h2>
                    <p className="text-gray-500 dark:text-gray-400 mt-1">{t('addresses.subtitle')}</p>
                </div>
                <Button 
                    variant="primary" 
                    leftIcon={<Plus size={18} />} 
                    onClick={() => {
                        setEditingCode(null);
                        setTempFormData(emptyForm);
                        setShowModal(true);
                    }}
                    className="shadow-md hover:shadow-lg transition-all"
                >
                    {t('addresses.addNew')}
                </Button>
            </div>
            
            {addresses.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-16 bg-gray-50/50 dark:bg-slate-800/50 rounded-2xl border-2 border-dashed border-gray-100 dark:border-slate-700">
                    <div className="w-16 h-16 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-sm mb-4">
                        <MapPin className="w-8 h-8 text-gray-300" />
                    </div>
                    <p className="text-gray-400 font-medium">{t('addresses.noAddresses')}</p>
                    <button onClick={openAddModal} className="mt-2 text-primary text-sm font-semibold hover:underline">
                        {t('addresses.addFirst')}
                    </button>
                </div>
            ) : (
                <div className="grid grid-cols-1 gap-5">
                    {addresses.map((addr) => (
                        <div 
                            key={addr.code} 
                            className={`group p-5 border-2 rounded-2xl relative transition-all duration-300 ${
                                addr.isDefault 
                                ? 'border-primary/20 bg-primary/[0.02] shadow-sm' 
                                : 'border-gray-100 dark:border-slate-800 hover:border-primary/20 hover:bg-white dark:hover:bg-slate-800/50 hover:shadow-md'
                            }`}
                        >
                            <div className="flex items-start gap-4">
                                <div className={`p-3 rounded-xl transition-colors ${
                                    addr.isDefault ? 'bg-primary text-white' : 'bg-gray-100 dark:bg-slate-800 text-gray-400 group-hover:bg-primary/10 group-hover:text-primary'
                                }`}>
                                    <MapPin className="w-6 h-6" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <div className="flex flex-wrap items-center gap-2 mb-1">
                                        <h3 className="font-bold text-gray-900 dark:text-white text-lg leading-tight truncate">
                                            {addr.fullName || t('common.fields.customer')}
                                        </h3>
                                        <span className="hidden md:inline text-gray-300 dark:text-slate-700">|</span>
                                        <span className="text-gray-600 dark:text-slate-400 font-medium">{addr.phone || 'N/A'}</span>
                                        {addr.isDefault && (
                                            <span className="bg-primary/10 text-primary text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider flex items-center gap-1">
                                                <Star className="w-2.5 h-2.5 fill-current" /> {t('addresses.defaultBadge')}
                                            </span>
                                        )}
                                        <span className="bg-gray-100 dark:bg-slate-800 text-gray-500 text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider">
                                            {addr.category}
                                        </span>
                                    </div>
                                    <p className="text-gray-600 dark:text-slate-400 text-sm leading-relaxed mb-4">
                                        {addr.addressLine}, {addr.city}
                                    </p>
                                    
                                    <div className="flex flex-wrap gap-4 pt-3 border-t border-gray-50 dark:border-slate-800">
                                        <button
                                            onClick={() => openEditModal(addr)}
                                            className="text-sm text-primary font-bold hover:opacity-80 flex items-center gap-1.5 transition-all"
                                        >
                                            <Edit2 className="w-4 h-4" /> {t('common.actions.edit')}
                                        </button>
                                        <button
                                            onClick={() => handleDelete(addr.code)}
                                            className="text-sm text-red-500 font-bold hover:opacity-80 flex items-center gap-1.5 transition-all"
                                        >
                                            <Trash2 className="w-4 h-4" /> {t('common.actions.delete')}
                                        </button>
                                        {!addr.isDefault && (
                                            <button
                                                onClick={() => setAsDefault(addr)}
                                                className="text-sm text-gray-400 font-bold hover:text-primary flex items-center gap-1.5 transition-all ml-auto"
                                            >
                                                <Star className="w-4 h-4" /> {t('addresses.setDefault')}
                                            </button>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {/* Address Form Modal using BaseForm */}
            <BaseForm<AddressFormData>
                isModal
                modalOpen={showModal}
                modalTitle={editingCode ? t('addresses.form.titleEdit') : t('addresses.form.titleAdd')}
                modalSize="6xl"
                onModalClose={() => setShowModal(false)}
                schema={addressSchema}
                defaultValues={tempFormData || emptyForm}
                fieldGroups={fieldGroups}
                groupLayoutClassName="grid grid-cols-1 lg:grid-cols-3 gap-8"
                onSubmit={handleFormSubmit}
                onCancel={() => setShowModal(false)}
                submitLabel={editingCode ? t('addresses.form.submitEdit') : t('addresses.form.submitAdd')}
                cancelLabel={t('common.actions.back')}
                isLoading={loading}
            />

            {/* Save Confirmation Dialog */}
            <ConfirmDialog
                isOpen={showConfirmModal}
                onClose={() => setShowConfirmModal(false)}
                onConfirm={onConfirmSubmit}
                title={t('addresses.confirm.saveTitle')}
                message={t('addresses.confirm.saveMessage')}
                variant="success"
                confirmText={t('addresses.confirm.saveButton')}
                isLoading={loading}
                icon={<CheckCircle className="size-6 text-green-600" />}
            />

            {/* Delete Confirmation Dialog */}
            <ConfirmDialog
                isOpen={!!addressToDelete}
                onClose={() => setAddressToDelete(null)}
                onConfirm={confirmDelete}
                title={t('addresses.confirm.deleteTitle')}
                message={t('addresses.confirm.deleteMessage')}
                variant="danger"
                confirmText={t('addresses.confirm.deleteButton')}
                isLoading={loading}
            />
        </div>
    );
};

export default AddressesContent;

import { memo, useMemo, useCallback } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
    ChevronLeft, Package, MapPin, Calendar, CreditCard, 
    Truck, AlertCircle, CheckCircle, Clock 
} from 'lucide-react';
import { Button, Badge } from '@/components/ui';
import SharedImage from '@/components/common/Image';
import { useOrder } from '@/hooks';
import { formatDate, formatCurrency, getStatusColor, getStatusText } from '@/utils/format';
import { OrderItemDto } from '@/services/orderService';

// ============ ORDER ITEM COMPONENT (MEMOIZED) ============
// Extracted to prevent re-renders of list items when parent state changes unrelated to items
const OrderItem = memo(({ item, onBuyAgain }: { item: OrderItemDto; onBuyAgain: (item: OrderItemDto) => void }) => {
    const { t } = useTranslation();
    
    // Callback wrapper to ensure stability if passed down further
    const handleBuyAgain = useCallback(() => {
        onBuyAgain(item);
    }, [item, onBuyAgain]);

    return (
        <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4 py-4 border-b last:border-0 border-secondary/10">
            <Link to={`/products/${item.productCode}`} className="flex-shrink-0">
                <SharedImage 
                    src={item.productImage} 
                    alt={item.productName} 
                    className="w-20 h-20 object-cover rounded-lg border border-secondary/20"
                />
            </Link>
            
            <div className="flex-1 min-w-0 pointer-events-none sm:pointer-events-auto">
                <Link to={`/products/${item.productCode}`} className="font-medium text-primary hover:text-indigo-600 truncate block">
                    {item.productName}
                </Link>
                <div className="text-sm text-tertiary mt-1 space-y-1">
                    <p>{t('cart.quantity')}: <span className="text-primary font-medium">{item.quantity}</span></p>
                    {item.size && <p>{t('product.size')}: {item.size}</p>}
                    {item.color && <p>{t('product.color')}: {item.color}</p>}
                </div>
            </div>

            <div className="flex flex-col items-end gap-2 flex-shrink-0">
                <span className="font-bold text-primary">{formatCurrency(item.priceAtOrder)}</span>
                <Button 
                    variant="outline" 
                    size="sm" 
                    onClick={handleBuyAgain}
                    className="text-xs"
                >
                    {t('order.buyAgain') || 'Buy Again'}
                </Button>
            </div>
        </div>
    );
});

OrderItem.displayName = 'OrderItem';

// ============ MAIN PAGE COMPONENT ============
const OrderDetailPage = () => {
    const { t } = useTranslation();
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    
    // Fetch Order Data
    const { data: order, isLoading, isError, error } = useOrder(id || '');

    // Handle Buy Again Action (Memoized Callback)
    const handleBuyAgain = useCallback((item: OrderItemDto) => {
        // Navigate to product page for now, could act as "Add to Cart" directly
        navigate(`/products/${item.productCode}`);
        // In a real scenario: addToCart(item.productCode, 1, ...)
    }, [navigate]);

    // Compute Status Icon (Memoized Value)
    const StatusIcon = useMemo(() => {
        if (!order) return Clock;
        switch (order.status) {
            case 'Delivered': return CheckCircle;
            case 'Cancelled': return AlertCircle;
            case 'Processing': return Package;
            case 'Shipping': return Truck;
            default: return Clock;
        }
    }, [order?.status]);

    if (isLoading) {
        return (
            <div className="flex items-center justify-center min-h-[60vh]">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            </div>
        );
    }

    if (isError || !order) {
        return (
            <div className="container mx-auto px-4 py-8 text-center">
                <AlertCircle className="mx-auto h-12 w-12 text-error mb-4" />
                <h2 className="text-xl font-bold mb-2">{t('common.error')}</h2>
                <p className="text-secondary mb-6">{error instanceof Error ? error.message : 'Order not found'}</p>
                <Button onClick={() => navigate('/account/orders')} leftIcon={<ChevronLeft size={16}/>}>
                    {t('order.backToOrders') || 'Back to Orders'}
                </Button>
            </div>
        );
    }

    return (
        <div className="container mx-auto px-4 py-8 max-w-5xl">
            {/* Header / Back Link */}
            <div className="mb-6">
                <Link to="/account?tab=orders" className="inline-flex items-center text-secondary hover:text-primary transition-colors mb-4">
                    <ChevronLeft size={16} className="mr-1" />
                    {t('order.backToOrders') || 'Back to Orders'}
                </Link>
                
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div>
                        <h1 className="text-2xl font-bold flex items-center gap-3">
                            {t('order.title')} #{order.code}
                            <Badge color={getStatusColor(order.status.toLowerCase()) as any} className="text-base px-3 py-1">
                                {t(getStatusText(order.status.toLowerCase()))}
                            </Badge>
                        </h1>
                        <p className="text-secondary mt-1 flex items-center gap-2">
                            <Calendar size={14} />
                            {formatDate(order.orderDate)}
                        </p>
                    </div>
                    {order.status === 'Delivered' && (
                        <div className="flex gap-2">
                             <Button variant="outline" className="border-error text-error hover:bg-error/5" onClick={() => navigate('/support')}>
                                {t('order.returnRefund') || 'Yêu cầu Trả hàng/Hoàn tiền'}
                            </Button>
                        </div>
                    )}
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Left Column: Order Items */}
                <div className="lg:col-span-2 space-y-6">
                    <div className="bg-primary rounded-xl shadow-sm border border-secondary/20 overflow-hidden">
                        <div className="p-4 border-b border-secondary/10 bg-secondary/5">
                            <h3 className="font-semibold flex items-center gap-2">
                                <Package size={18} />
                                {t('order.items')} ({order.orderItems.length})
                            </h3>
                        </div>
                        <div className="p-4">
                            {order.orderItems.map((item) => (
                                <OrderItem 
                                    key={item.id || item.code} // Fallback to code if id missing
                                    item={item} 
                                    onBuyAgain={handleBuyAgain} 
                                />
                            ))}
                        </div>
                    </div>

                    {/* Order Timeline / Status Steps (Simplified) */}
                    <div className="bg-primary rounded-xl shadow-sm border border-secondary/20 p-6">
                        <h3 className="font-semibold mb-4 flex items-center gap-2">
                            <Clock size={18} />
                            {t('order.timeline') || 'Order Status'}
                        </h3>
                        <div className="flex items-center gap-4 text-sm text-secondary">
                             <StatusIcon className={`text-${getStatusColor(order.status.toLowerCase())}`} size={24} />
                             <span className="font-medium text-primary">{t(getStatusText(order.status.toLowerCase()))}</span>
                             <span className="text-tertiary">- {formatDate(order.orderDate)}</span>
                        </div>
                    </div>
                </div>

                {/* Right Column: Summary & Info */}
                <div className="space-y-6">
                    {/* Shipping Address */}
                    <div className="bg-primary rounded-xl shadow-sm border border-secondary/20 p-6">
                        <h3 className="font-semibold mb-4 flex items-center gap-2">
                            <MapPin size={18} />
                            {t('checkout.shippingAddress')}
                        </h3>
                        <div className="text-sm space-y-2 text-secondary">
                            <p className="font-medium text-primary">{order.customerName}</p>
                            <p>{order.shippingAddress || 'N/A'}</p>
                            <p>{order.customerPhone}</p>
                        </div>
                    </div>

                    {/* Payment Info */}
                    <div className="bg-primary rounded-xl shadow-sm border border-secondary/20 p-6">
                        <h3 className="font-semibold mb-4 flex items-center gap-2">
                            <CreditCard size={18} />
                            {t('checkout.paymentMethod')}
                        </h3>
                        <p className="text-sm text-secondary">
                            {order.paymentMethod ? t(`payment.${order.paymentMethod}`) : 'N/A'}
                        </p>
                    </div>

                    {/* Order Summary */}
                    <div className="bg-primary rounded-xl shadow-sm border border-secondary/20 p-6">
                        <h3 className="font-semibold mb-4">{t('order.summary')}</h3>
                        <div className="space-y-3 text-sm pb-4 border-b border-secondary/10">
                            <div className="flex justify-between">
                                <span className="text-secondary">{t('cart.subtotal')}</span>
                                <span className="font-medium">{formatCurrency(order.totalAmount)}</span> 
                                {/* Note: Backend might need to send subtotal separately if tax/shipping logic complex */}
                            </div>
                            <div className="flex justify-between">
                                <span className="text-secondary">{t('cart.shipping')}</span>
                                <span className="font-medium">{formatCurrency(0)}</span>
                            </div>
                            {/* Tax, Discount placeholders */}
                        </div>
                        <div className="flex justify-between pt-4 font-bold text-lg">
                            <span>{t('cart.total')}</span>
                            <span className="text-error">{formatCurrency(order.totalAmount)}</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default memo(OrderDetailPage);

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Link } from 'react-router-dom';
import { Package, Calendar, ChevronRight, MapPin, Star } from 'lucide-react';
import SharedImage from '@/components/common/Image';
import { Button, Badge, Modal } from '@/components/ui';
import { formatDate, formatCurrency, getStatusColor, getStatusText } from '@/utils/format';
import { orderService, type OrderDto, type OrderItemDto } from '@/services/orderService';
import ReviewForm from '@/components/reviews/ReviewForm';
import { useAuthStore } from '@/store';

const OrdersContent = () => {
  const { t } = useTranslation();
  const [orders, setOrders] = useState<OrderDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState<OrderItemDto | null>(null);
  const { user } = useAuthStore();

  const fetchOrders = () => {
     orderService.getMyOrders({ pageIndex: 1, pageSize: 20 }).then(res => {
      if(res.success && res.data) {
          if (Array.isArray(res.data)) {
               setOrders(res.data as unknown as OrderDto[]);
          } else if (res.data.items) {
               setOrders(res.data.items);
          }
      }
      setLoading(false);
    });
  };

  useEffect(() => {
    fetchOrders();
  }, []);

  const handleReviewSuccess = () => {
    setSelectedItem(null);
    // Optionally refresh orders if needed (e.g. to hide review button if functionality added later) or show success toast
  };

  if (loading) return <div>{t('common.loading')}</div>;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold">{t('account.orders')}</h2>

      {orders.length === 0 && <p className="text-secondary">{t('review.no_orders')}</p>}

      {orders.map((order) => (
        <div key={order.code} className="bg-primary rounded-xl p-4 border border-secondary/20">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2 mb-4">
            <div>
              <Link to={`/account/orders/${order.code}`} className="font-bold text-primary hover:underline">
                #{order.code}
              </Link>
              <p className="text-sm text-tertiary">{formatDate(order.orderDate)}</p>
            </div>
            <span
              className={`px-3 py-1 rounded-full text-xs font-semibold bg-${getStatusColor(order.status)}/20 text-${getStatusColor(order.status)}`}
            >
              {t(getStatusText(order.status))}
            </span>
          </div>

          <div className="space-y-2 mb-4">
             {order.orderItems?.map((item, index) => (
              <div key={index} className="flex items-center gap-3 py-2 border-b border-secondary/10 last:border-0">
                <SharedImage
                  src={item.productImage}
                  alt={item.productName}
                  className="h-16 w-16 rounded-md object-cover flex-shrink-0"
                />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium truncate">{item.productName}</p>
                  <div className="flex justify-between items-center mt-1">
                      <p className="text-xs text-tertiary">x{item.quantity}</p>
                      
                      {order.status === 'Delivered' && (
                        <Button 
                            variant="outline" 
                            size="xs" 
                            leftIcon={<Star size={12}/>}
                            onClick={() => setSelectedItem(item)}
                        >
                            {t('review.write')}
                        </Button>
                      )}
                  </div>
                </div>
                <p className="text-sm font-medium flex-shrink-0">{formatCurrency(item.priceAtOrder * item.quantity)}</p>
              </div>
            ))}
          </div>

          <div className="flex justify-between items-center pt-4 border-t">
            <span className="text-sm text-secondary">{t('cart.total')}</span>
            <span className="font-bold text-error">{formatCurrency(order.totalAmount)}</span>
          </div>
        </div>
      ))}

      {/* Review Modal */}
      <Modal
        isOpen={!!selectedItem}
        onClose={() => setSelectedItem(null)}
        title={t('review.write_review')}
        size="lg"
      >
        {selectedItem && user && (
            <ReviewForm
                orderItemCode={selectedItem.code} 
                productName={selectedItem.productName}
                productImage={selectedItem.productImage}
                userCode={user.code}
                onSuccess={handleReviewSuccess}
                onCancel={() => setSelectedItem(null)}
            />
        )}
      </Modal>
    </div>
  );
};

export default OrdersContent;

